{
  "name": "AI Lesson Plan - Digital Math 6",
  "description": "Ứng dụng soạn giáo án Toán 6 (Kết nối tri thức) tích hợp năng lực số theo chuẩn Công văn 5512.",
  "requestFramePermissions": [
    "camera"
  ]
