import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface DigitalCompetency {
  code: string;
  name: string;
  description: string;
}

export interface Activity {
  id: string;
  title: string;
  content: string;
  digitalCompetency: string;
  mathFormulas?: string[];
  svgDiagram?: string;
}

export interface LessonPlan {
  topic: string;
  grade: string;
  bookSeries: string;
  objectives: string;
  activities: Activity[];
}

export enum GenerationMode {
  NEW = 'NEW',
  TRANSFORM = 'TRANSFORM',
  TEXTBOOK = 'TEXTBOOK'
}

import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING, description: 'Tên hoạt động: Mở đầu, Hình thành kiến thức, Luyện tập, Vận dụng' },
          content: { type: Type.STRING, description: 'Nội dung chi tiết hoạt động giảng dạy bằng Markdown và LaTeX' },
          digitalCompetency: { type: Type.STRING, description: 'Mã năng lực số tích hợp (ví dụ: NL1, NL3)' },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG hoàn chỉnh nếu hoạt động cần hình vẽ hình học (ví dụ: tam giác, hình vuông)' }
        },
        required: ['id', 'title', 'content', 'digitalCompetency']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: string
): Promise<LessonPlan> => {
  let prompt = "";

  if (mode === GenerationMode.NEW) {
    prompt = `Soạn giáo án môn Toán lớp 6 bộ sách Kết nối tri thức với cuộc sống. Chủ đề: ${input}.
    Yêu cầu:
    1. Chia làm 4 hoạt động chính theo công văn 5512.
    2. Mỗi hoạt động tích hợp ít nhất một Năng lực số (NL1-NL5).
    3. Nội dung toán học sử dụng LaTeX chuẩn: ví dụ $x^2 + y^2 = r^2$.
    4. Nếu có hình vẽ hình học, hãy tạo mã SVG đơn giản, tinh tế.`;
  } else if (mode === GenerationMode.TRANSFORM) {
    prompt = `Dưới đây là nội dung giáo án cũ. Hãy chuyển đổi sang định dạng 2 cột theo chuẩn 5512 và tích hợp Năng lực số cho từng hoạt động: ${input}`;
  } else {
    prompt = `Dựa trên nội dung sách giáo khoa (văn bản/hình ảnh được cung cấp), hãy soạn giáo án tích hợp năng lực số cho bài học này: ${input}`;
  }

  const parts: any[] = [{ text: prompt }];
  if (fileData) {
    parts.push({
      inlineData: {
        mimeType: 'image/jpeg',
        data: fileData
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.7,
    },
  });

  return JSON.parse(response.text || "{}") as LessonPlan;
};

import React, { useEffect, useRef } from 'react';
import katex from 'katex';

interface MathRendererProps {
  content: string;
}

const MathRenderer: React.FC<MathRendererProps> = ({ content }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (containerRef.current) {
      // Find all text between $...$ and render it as math
      const text = content;
      let rendered = text.replace(/\$([^\$]+)\$/g, (match, formula) => {
        try {
          return katex.renderToString(formula, { throwOnError: false, displayMode: false });
        } catch (e) {
          return match;
        }
      });

      // Also handle multi-line block math $$...$$
      rendered = rendered.replace(/\$\$([^\$]+)\$\$/g, (match, formula) => {
        try {
          return katex.renderToString(formula, { throwOnError: false, displayMode: true });
        } catch (e) {
          return match;
        }
      });

      containerRef.current.innerHTML = rendered.replace(/\n/g, '<br/>');
    }
  }, [content]);

  return <div ref={containerRef} className="prose max-w-none math-rendered" />;
};

export default MathRenderer;

import React, { useState, useCallback } from 'react';
