                    </button>
                    <button 
                      onClick={() => setMode(GenerationMode.TRANSFORM)}
                      className={`flex flex-col items-center p-3 rounded-lg border text-xs transition ${mode === GenerationMode.TRANSFORM ? 'bg-blue-50 border-blue-600 text-blue-700' : 'bg-gray-50 border-gray-200 text-gray-500 hover:bg-gray-100'}`}
                    >
