      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string }
): Promise<LessonPlan> => {
  let prompt = "";

  if (mode === GenerationMode.NEW) {
    prompt = `Bạn là chuyên gia soạn giáo án Toán lớp 6 bộ sách "Kết nối tri thức với cuộc sống". 
    Chủ đề: ${input}.
    Yêu cầu:
    1. Soạn giáo án theo chuẩn Công văn 5512 (4 hoạt động).
    2. Tích hợp năng lực số (NL1-NL5) một cách sáng tạo và thực tiễn vào từng hoạt động.
    3. Sử dụng LaTeX cho mọi công thức toán học (ví dụ: $a^2 + b^2 = c^2$).
    4. Nếu có hình vẽ, hãy cung cấp mã SVG sạch, chuyên nghiệp.`;
  } else if (mode === GenerationMode.TRANSFORM) {
    prompt = `Bạn nhận được một giáo án cũ (trong văn bản: "${input}" hoặc trong hình ảnh đính kèm). 
    Hãy thực hiện:
    1. Trích xuất nội dung từ giáo án cũ.
    2. Chuyển đổi sang cấu trúc 2 cột theo chuẩn 5512.
    3. Tích hợp mã năng lực số (NL1-NL5) phù hợp vào cột tương ứng.
    4. Đảm bảo các công thức toán học không bị lỗi bằng cách dùng LaTeX.`;
  } else {
    prompt = `Dựa trên trang sách giáo khoa được cung cấp (hình ảnh/văn bản: "${input}"), hãy soạn một giáo án hoàn chỉnh:
    1. Đúng nội dung kiến thức của bộ sách Kết nối tri thức.
    2. Tích hợp năng lực số cho học sinh.
    3. Vẽ hình minh họa bằng SVG nếu bài học yêu cầu hình học.`;
  }

  const parts: any[] = [{ text: prompt }];
  if (fileData) {
    parts.push({
      inlineData: {
        mimeType: fileData.mimeType,
        data: fileData.data
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.4, // Giảm temperature để output ổn định hơn cho giáo án
    },
  });

  const text = response.text;
  if (!text) throw new Error("Không nhận được phản hồi từ AI");

  return JSON.parse(text) as LessonPlan;
};

