import { DIGITAL_COMPETENCIES, KET_NOI_TRI_THUC_CHAPTERS } from './constants.tsx';
import { generateLessonPlan } from './services/geminiService';
import MathRenderer from './components/MathRenderer';

// --- MOCK DATABASE FOR QUICK SELECTION ---
const DATABASE = {
  6: [
    { id: 't6_c1_b1', name: 'Bài 1: Tập hợp', chapter: 'Chương I. Tập hợp các số tự nhiên' },
    { id: 't6_c1_b2', name: 'Bài 2: Cách ghi số tự nhiên', chapter: 'Chương I. Tập hợp các số tự nhiên' },
    { id: 't6_c1_b3', name: 'Bài 3: Thứ tự trong tập hợp các số tự nhiên', chapter: 'Chương I. Tập hợp các số tự nhiên' },
    { id: 't6_c1_b4', name: 'Bài 4: Phép cộng và phép trừ số tự nhiên', chapter: 'Chương I. Tập hợp các số tự nhiên' },
    { id: 't6_c4_b1', name: 'Bài 18: Hình tam giác đều. Hình vuông. Hình lục giác đều', chapter: 'Chương IV. Một số hình phẳng trong thực tế' },
    { id: 't6_c9_b42', name: 'Bài 42: Kết quả có thể và sự kiện trong trò chơi thí nghiệm', chapter: 'Chương IX. Dữ liệu và xác suất thực nghiệm' }
  ]
};

export default function LessonPlanApp() {
  const [activeTab, setActiveTab] = useState('create');
  const [selectedGrade, setSelectedGrade] = useState(6);
  const [selectedLessonId, setSelectedLessonId] = useState('');
  const [generatedPlan, setGeneratedPlan] = useState<LessonPlan | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showNotification, setShowNotification] = useState(false);

  // File Upload State
  const [fileData, setFileData] = useState<{ data: string, mimeType: string, name: string } | null>(null);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [uploadStage, setUploadStage] = useState(''); 
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleGenerateFromTopic = async () => {
    if (!selectedLessonId) return;

    const lesson = DATABASE[6].find(l => l.id === selectedLessonId);
    setIsProcessing(true);
    setError(null);

    try {
      const plan = await generateLessonPlan(GenerationMode.NEW, lesson?.name || "");
      setGeneratedPlan(plan);
      setShowNotification(true);
      setTimeout(() => setShowNotification(false), 3000);
    } catch (err) {
      setError("Không thể tạo giáo án. Vui lòng kiểm tra kết nối mạng.");
      console.error(err);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        setError("Vui lòng tải lên tệp hình ảnh (JPG, PNG) của giáo án hoặc trang sách.");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          data: base64String,
          mimeType: file.type,
          name: file.name
        });
        startAiProcessing(base64String, file.type, file.name);
      };
      reader.readAsDataURL(file);
    }
  };

  const startAiProcessing = async (base64: string, mimeType: string, fileName: string) => {
    setIsProcessing(true);
    setUploadProgress(10);
    setUploadStage('scanning');
    setError(null);

    const progressInterval = setInterval(() => {
      setUploadProgress(prev => {
        if (prev >= 90) {
          clearInterval(progressInterval);
          return 90;
        }
        if (prev < 40) setUploadStage('scanning');
        else if (prev < 70) setUploadStage('matching');
        else setUploadStage('integrating');
        return prev + 2;
      });
    }, 200);

    try {
      const plan = await generateLessonPlan(
        GenerationMode.TRANSFORM, 
        "Hãy nhận diện nội dung từ ảnh và soạn giáo án chuẩn 5512 tích hợp năng lực số.",
        { data: base64, mimeType }
      );

      clearInterval(progressInterval);
      setUploadProgress(100);
      setGeneratedPlan({ ...plan, topic: `${plan.topic} (Từ tệp: ${fileName})` });
      setShowNotification(true);
      setTimeout(() => setShowNotification(false), 3000);
    } catch (err) {
      clearInterval(progressInterval);
      setError("AI không thể đọc được nội dung ảnh. Vui lòng chụp rõ nét hơn.");
      setFileData(null);
    } finally {
      setIsProcessing(false);
      setUploadProgress(0);
      setUploadStage('');
    }
  };

  const getCompetencyInfo = (code: string) => {
    return DIGITAL_COMPETENCIES.find(c => c.code === code) || null;
  };

  return (
    <div className="flex h-screen bg-gray-50 font-sans text-slate-800 overflow-hidden">

      {/* SIDEBAR */}
      <aside className="w-64 bg-slate-900 text-slate-300 flex flex-col shadow-2xl no-print">
        <div className="p-6 border-b border-slate-700">
          <div className="flex items-center gap-3 text-white mb-1">
            <div className="bg-blue-600 p-2 rounded-lg">
              <Cpu size={24} className="text-white" />
            </div>
            <div>
              <h1 className="font-bold text-lg leading-tight tracking-tight">AI TEACHER</h1>
              <p className="text-[10px] text-blue-400 font-bold uppercase tracking-wider">Math 6 Edition</p>
            </div>
          </div>
        </div>

        <nav className="flex-1 p-4 space-y-2">
          <button 
            onClick={() => { setActiveTab('create'); setGeneratedPlan(null); setFileData(null); setError(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'create' ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-slate-800'}`}
          >
            <PenTool size={18} />
            <span className="font-semibold text-sm">Soạn bài mới</span>
          </button>

          <button 
            onClick={() => { setActiveTab('upload'); setGeneratedPlan(null); setFileData(null); setError(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'upload' ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-slate-800'}`}
          >
            <Upload size={18} />
            <div className="text-left">
              <span className="font-semibold text-sm block">Tải ảnh giáo án</span>
              <span className="text-[10px] text-slate-400 font-normal">Nhận diện AI thông minh</span>
            </div>
          </button>

          <button 
            onClick={() => { setActiveTab('competence'); setGeneratedPlan(null); }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${activeTab === 'competence' ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-slate-800'}`}
          >
            <List size={18} />
