import React, { useEffect, useRef } from 'react';

interface MathRendererProps {
  content: string;
}

const MathRenderer: React.FC<MathRendererProps> = ({ content }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (containerRef.current && (window as any).MathJax) {
      // Clear current content and set new one
      containerRef.current.innerHTML = content.replace(/\n/g, '<br/>');

      // Request MathJax to typeset the container
      try {
        (window as any).MathJax.typesetPromise([containerRef.current]);
      } catch (e) {
        console.error("MathJax error:", e);
      }
    }
  }, [content]);

  return <div ref={containerRef} className="prose max-w-none math-rendered text-slate-700 text-sm" />;
};

export default MathRenderer;

import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          content: { type: Type.STRING, description: 'Nội dung chi tiết hoạt động giảng dạy. Dùng công thức toán học dạng $...$ hoặc $$...$$' },
          digitalCompetency: { type: Type.STRING, description: 'Mã năng lực số: NL1, NL2, NL3, NL4, NL5' },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG nếu cần minh họa hình học' }
        },
        required: ['id', 'title', 'content', 'digitalCompetency']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string }
): Promise<LessonPlan> => {
  let prompt = `Bạn là một chuyên gia giáo dục hàng đầu, am hiểu sâu sắc bộ sách "Kết nối tri thức với cuộc sống" môn Toán lớp 6 và Công văn 5512.`;

  if (mode === GenerationMode.TRANSFORM) {
    prompt += `
    NHIỆM VỤ: Phân tích tệp đính kèm (có thể là giáo án cũ, bài giảng PDF/Word/PPT hoặc ảnh chụp trang sách).
    1. Trích xuất chủ đề chính, mục tiêu kiến thức, kỹ năng từ tài liệu đó.
    2. Thiết kế lại giáo án hoàn chỉnh theo 4 hoạt động của CV 5512.
    3. Quan trọng nhất: Đề xuất và tích hợp các Năng lực số (Digital Competency) thực tiễn nhất vào từng hoạt động dạy học.
    4. Sử dụng công thức toán học LaTeX chuẩn.
    Tài liệu đính kèm: ${input}`;
  } else if (mode === GenerationMode.NEW) {
    prompt += `
    NHIỆM VỤ: Soạn giáo án mới cho chủ đề: ${input}.
    1. Tuân thủ cấu trúc 5512.
    2. Tích hợp năng lực số (NL1-NL5).
    3. Vẽ hình minh họa bằng SVG nếu liên quan đến hình phẳng.`;
  }

  const parts: any[] = [{ text: prompt }];
  if (fileData) {
    parts.push({
      inlineData: {
        mimeType: fileData.mimeType,
        data: fileData.data
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.2,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi");

  return JSON.parse(text) as LessonPlan;
};

