import React, { useState, useRef } from 'react';
import { 
  BookOpen, 
  FileText, 
  Cpu, 
  Download, 
  RefreshCw, 
  CheckCircle, 
  Layout, 
  Upload, 
  FileCode,
  Calculator,
  PenTool,
  ChevronDown,
  List,
  X,
  FileCheck,
  AlertCircle,
  FileWarning,
  FileSearch,
  Monitor
} from 'lucide-react';
import { GenerationMode, LessonPlan } from './types';
import { DIGITAL_COMPETENCIES } from './constants.tsx';
import { generateLessonPlan } from './services/geminiService';
import MathRenderer from './components/MathRenderer';

const DATABASE = {
  6: [
    { id: 't6_c1_b1', name: 'Bài 1: Tập hợp', chapter: 'Chương I' },
    { id: 't6_c4_b1', name: 'Bài 18: Hình tam giác đều. Hình vuông', chapter: 'Chương IV' },
    { id: 't6_c6_b1', name: 'Bài 23: Mở rộng phân số', chapter: 'Chương VI' }
  ]
};

export default function LessonPlanApp() {
  const [activeTab, setActiveTab] = useState('upload');
  const [selectedLessonId, setSelectedLessonId] = useState('');
  const [generatedPlan, setGeneratedPlan] = useState<LessonPlan | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [fileData, setFileData] = useState<{ data: string, mimeType: string, name: string, type: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const getFileIcon = (mimeType: string) => {
    if (mimeType.includes('pdf')) return <FileText size={48} className="text-red-500" />;
    if (mimeType.includes('word') || mimeType.includes('msword')) return <FileCode size={48} className="text-blue-500" />;
    if (mimeType.includes('powerpoint') || mimeType.includes('presentation')) return <Monitor size={48} className="text-orange-500" />;
    return <Upload size={48} className="text-blue-600" />;
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const allowedTypes = [
        'image/jpeg', 'image/png', 'application/pdf', 
        'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'application/vnd.ms-powerpoint', 'application/vnd.openxmlformats-officedocument.presentationml.presentation'
      ];

      if (!allowedTypes.includes(file.type)) {
        setError("Định dạng tệp không được hỗ trợ. Vui lòng dùng PDF, Word, PPT hoặc Ảnh.");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          data: base64String,
          mimeType: file.type,
          name: file.name,
          type: file.type.split('/')[1]
        });
        startAiProcessing(base64String, file.type, file.name);
      };
      reader.readAsDataURL(file);
    }
  };

  const startAiProcessing = async (base64: string, mimeType: string, fileName: string) => {
    setIsProcessing(true);
    setError(null);
    try {
      const plan = await generateLessonPlan(
        GenerationMode.TRANSFORM, 
        `Phân tích tệp giáo án: ${fileName}`,
        { data: base64, mimeType }
      );
      setGeneratedPlan(plan);
    } catch (err) {
      setError("AI không thể đọc tệp này. Thử chuyển tệp sang PDF hoặc chụp ảnh rõ nét hơn.");
    } finally {
      setIsProcessing(false);
    }
  };

  const getCompetencyInfo = (code: string) => {
    return DIGITAL_COMPETENCIES.find(c => c.code === code) || null;
  };

  return (
    <div className="flex h-screen bg-slate-50 font-sans text-slate-800 overflow-hidden">

      {/* SIDEBAR */}
      <aside className="w-72 bg-slate-900 text-slate-300 flex flex-col shadow-2xl no-print">
        <div className="p-8 border-b border-slate-800">
          <div className="flex items-center gap-3 text-white mb-1">
            <div className="bg-blue-600 p-2.5 rounded-xl shadow-lg shadow-blue-900/20">
              <Cpu size={24} className="text-white" />
            </div>
            <div>
              <h1 className="font-black text-lg leading-tight tracking-tighter">MATH AI 6</h1>
              <p className="text-[10px] text-blue-400 font-black uppercase tracking-widest">Digital Reform</p>
            </div>
          </div>
        </div>

        <nav className="flex-1 p-5 space-y-3">
          <button 
            onClick={() => { setActiveTab('upload'); setGeneratedPlan(null); setFileData(null); }}
            className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all ${activeTab === 'upload' ? 'bg-blue-600 text-white shadow-xl shadow-blue-900/40 translate-x-1' : 'hover:bg-slate-800 hover:translate-x-1'}`}
          >
            <Upload size={20} />
            <div className="text-left">
              <span className="font-bold text-sm block">Tải giáo án lên</span>
              <span className="text-[10px] opacity-60 font-medium">Word, PDF, PPT, Ảnh</span>
            </div>
          </button>

