];

export default function LessonPlanApp() {
  const [activeTab, setActiveTab] = useState('upload');
  const [selectedLessonId, setSelectedLessonId] = useState('');
  const [generatedPlan, setGeneratedPlan] = useState<LessonPlan | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [fileData, setFileData] = useState<{ data: string, mimeType: string, name: string, type: string } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleDownloadWord = () => {
    if (!generatedPlan) return;

    // Tạo nội dung HTML tương thích với Word
    const header = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset='utf-8'>
        <title>${generatedPlan.topic}</title>
        <style>
          body { font-family: 'Times New Roman', serif; line-height: 1.5; }
          .center { text-align: center; }
          .bold { font-weight: bold; }
          .uppercase { text-transform: uppercase; }
          .section-title { font-size: 14pt; font-weight: bold; color: #003399; margin-top: 20px; }
          table { width: 100%; border-collapse: collapse; margin-top: 10px; }
          th, td { border: 1px solid black; padding: 8px; font-size: 11pt; vertical-align: top; }
          th { background-color: #f2f2f2; font-weight: bold; text-align: center; }
          .competency { font-style: italic; color: #555; font-size: 10pt; }
        </style>
      </head>
      <body>
        <div class="center">
          <p class="bold uppercase">GIÁO ÁN MÔN TOÁN LỚP 6</p>
          <p class="bold uppercase" style="font-size: 16pt;">${generatedPlan.topic}</p>
          <p>Bộ sách: ${generatedPlan.bookSeries} • Năm học: 2024 - 2025</p>
        </div>
        <br/>
        <div class="section-title">I. MỤC TIÊU BÀI DẠY</div>
        <p>${generatedPlan.objectives.replace(/\n/g, '<br/>')}</p>

        <div class="section-title">II. TIẾN TRÌNH DẠY HỌC</div>
        <table>
          <thead>
            <tr>
              <th style="width: 70%;">Nội dung & Phương pháp dạy học (CV 5512)</th>
              <th style="width: 30%;">Năng lực số tích hợp</th>
            </tr>
          </thead>
          <tbody>
            ${generatedPlan.activities.map(act => `
              <tr>
                <td>
                  <p class="bold">${act.title}</p>
                  <p>${act.content.replace(/\$/g, '').replace(/\n/g, '<br/>')}</p>
                </td>
                <td>
                  <p class="bold">${act.digitalCompetency}</p>
                  <p class="competency">${getCompetencyInfo(act.digitalCompetency)?.name || ''}</p>
                </td>
              </tr>
            `).join('')}
          </tbody>
        </table>
        <br/>
        <table style="border: none;">
          <tr style="border: none;">
            <td style="border: none; text-align: center; width: 50%;">
              <p class="bold">XÁC NHẬN CỦA CHUYÊN MÔN</p>
              <br/><br/><br/>
            </td>
            <td style="border: none; text-align: center; width: 50%;">
              <p class="bold">GIÁO VIÊN THỰC HIỆN</p>
              <br/><br/><br/>
            </td>
          </tr>
        </table>
      </body>
      </html>
    `;

    const blob = new Blob(['\ufeff', header], {
      type: 'application/msword'
    });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `GiaoAn_${generatedPlan.topic.replace(/\s+/g, '_')}.doc`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const allowedTypes = [
        'image/jpeg', 'image/png', 'application/pdf', 
        'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
        'application/vnd.ms-powerpoint', 'application/vnd.openxmlformats-officedocument.presentationml.presentation'
      ];

      if (!allowedTypes.includes(file.type)) {
        setError("Định dạng tệp không được hỗ trợ. Vui lòng dùng PDF, Word, PPT hoặc Ảnh.");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          data: base64String,
          mimeType: file.type,
          name: file.name,
          type: file.type.split('/')[1]
        });
        startAiProcessing(base64String, file.type, file.name);
      };
      reader.readAsDataURL(file);
    }
  };

  const startAiProcessing = async (base64: string, mimeType: string, fileName: string) => {
    setIsProcessing(true);
    setError(null);
    try {
      const plan = await generateLessonPlan(
        GenerationMode.TRANSFORM, 
        `Phân tích tệp giáo án: ${fileName}`,
        { data: base64, mimeType }
      );
      setGeneratedPlan(plan);
    } catch (err) {
      setError("AI không thể đọc tệp này. Thử chuyển tệp sang PDF hoặc chụp ảnh rõ nét hơn.");
    } finally {
      setIsProcessing(false);
    }
  };

  const getCompetencyInfo = (code: string) => {
    return DIGITAL_COMPETENCIES.find(c => c.code === code) || null;
