          >
            <Upload size={20} />
            <div className="text-left">
              <span className="font-bold text-sm block">Tải giáo án lên</span>
              <span className="text-[10px] opacity-60 font-medium">Word, PDF, PPT, Ảnh</span>
            </div>
          </button>

          <button 
            onClick={() => { setActiveTab('create'); setGeneratedPlan(null); setFileData(null); }}
            className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all ${activeTab === 'create' ? 'bg-blue-600 text-white shadow-xl shadow-blue-900/40 translate-x-1' : 'hover:bg-slate-800 hover:translate-x-1'}`}
          >
            <PenTool size={20} />
            <span className="font-bold text-sm">Soạn bài mới</span>
          </button>

          <button 
            onClick={() => setActiveTab('competence')}
            className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all ${activeTab === 'competence' ? 'bg-blue-600 text-white shadow-xl shadow-blue-900/40 translate-x-1' : 'hover:bg-slate-800 hover:translate-x-1'}`}
          >
            <List size={20} />
            <span className="font-bold text-sm">Khung năng lực số</span>
          </button>
        </nav>

        <div className="p-6 bg-slate-950/50 text-[11px] text-slate-500 border-t border-slate-800 m-4 rounded-2xl">
          <p className="font-bold text-slate-400">GIÁO ÁN ĐIỆN TỬ 5512</p>
          <p className="mt-1 leading-relaxed">Tự động hóa tích hợp năng lực số cho Giáo viên Toán lớp 6.</p>
        </div>
      </aside>

      {/* MAIN CONTENT */}
      <main className="flex-1 flex flex-col h-full relative overflow-hidden bg-[#f0f4f8]">

        <header className="h-20 bg-white border-b border-slate-200 flex items-center justify-between px-10 shadow-sm z-10 no-print">
          <div>
            <h2 className="text-xl font-black text-slate-900 flex items-center gap-3">
              {activeTab === 'upload' ? <FileSearch className="text-blue-600" /> : <Layout className="text-blue-600" />}
              {activeTab === 'upload' && 'Số hóa giáo án cũ'}
              {activeTab === 'create' && 'Soạn giáo án theo chủ đề'}
              {activeTab === 'competence' && 'Tra cứu phụ lục 3'}
            </h2>
          </div>

          <div className="flex items-center gap-4">
            {generatedPlan && (
              <div className="flex gap-2">
                <button 
                  onClick={handleDownloadWord}
                  className="flex items-center gap-2 px-6 py-2.5 text-sm font-black text-white bg-blue-600 rounded-xl hover:bg-blue-700 shadow-lg transition-all active:scale-95"
                >
                  <FileCode size={18} /> TẢI FILE WORD
                </button>
                <button 
                  onClick={() => window.print()}
                  className="flex items-center gap-2 px-6 py-2.5 text-sm font-black text-white bg-slate-900 rounded-xl hover:bg-black shadow-lg transition-all active:scale-95"
                >
                  <Printer size={18} /> IN GIÁO ÁN
                </button>
              </div>
            )}
            <div className="w-12 h-12 rounded-2xl bg-gradient-to-br from-blue-500 to-indigo-600 flex items-center justify-center text-white font-black shadow-lg shadow-blue-200">
              GV
            </div>
          </div>
        </header>

        <div className="flex-1 overflow-auto p-10">

          {error && (
            <div className="max-w-4xl mx-auto mb-8 p-5 bg-red-50 border border-red-100 text-red-700 rounded-2xl flex items-center gap-4 animate-in fade-in slide-in-from-top-4">
