              <p className="text-sm font-bold">{error}</p>
              <button onClick={() => setError(null)} className="ml-auto p-2 hover:bg-red-200 rounded-full transition-colors"><X size={18}/></button>
            </div>
          )}

          {/* UPLOAD WORKSPACE */}
          {activeTab === 'upload' && !generatedPlan && (
            <div className="max-w-3xl mx-auto mt-10">
               <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept=".pdf,.doc,.docx,.ppt,.pptx,image/*" />

               {!fileData && !isProcessing ? (
                 <div 
                   onClick={() => fileInputRef.current?.click()}
                   className="group border-2 border-dashed border-slate-300 bg-white rounded-[2.5rem] p-20 text-center hover:border-blue-500 hover:bg-blue-50/50 transition-all cursor-pointer shadow-sm hover:shadow-2xl"
                 >
                    <div className="w-28 h-28 bg-blue-50 text-blue-600 rounded-3xl flex items-center justify-center mx-auto mb-10 group-hover:scale-110 group-hover:rotate-3 transition-all shadow-inner">
                      <Upload size={56} />
                    </div>
                    <h3 className="text-3xl font-black text-slate-900 mb-4">Tải giáo án mẫu lên</h3>
                    <p className="text-slate-500 mb-10 max-w-md mx-auto leading-relaxed font-medium">
                      Hệ thống hỗ trợ <b>Word, PDF, PowerPoint và Ảnh chụp</b>. AI sẽ tự động phân tích và đề xuất phương án tích hợp năng lực số.
                    </p>
                    <div className="flex justify-center gap-3">
