                      <span className="px-5 py-2.5 bg-slate-100 text-slate-600 rounded-xl text-xs font-black">POWERPOINT</span>
                      <span className="px-5 py-2.5 bg-slate-100 text-slate-600 rounded-xl text-xs font-black">ẢNH CHỤP</span>
                    </div>
                 </div>
               ) : (
                 <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 p-20 text-center relative overflow-hidden">
                    {isProcessing && (
                      <div className="absolute top-0 left-0 w-full h-1.5 bg-blue-100">
                        <div className="h-full bg-blue-600 animate-[loading-bar_1.5s_infinite_linear]"></div>
                      </div>
                    )}
                    <div className="w-32 h-32 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-10 shadow-inner">
                      {isProcessing ? (
                        <div className="relative">
                           <RefreshCw className="animate-spin text-blue-600" size={56} />
                           <div className="absolute inset-0 flex items-center justify-center"><Cpu size={24} className="text-blue-400" /></div>
                        </div>
                      ) : <FileCheck size={56} className="text-green-500"/>}
                    </div>
                    <h3 className="text-2xl font-black text-slate-900 mb-2 truncate px-10 uppercase tracking-tighter">
                      {fileData?.name || 'Đang chuẩn bị...'}
                    </h3>
                    <div className="mt-8 space-y-3">
                      <p className="text-blue-600 font-black animate-pulse text-sm uppercase tracking-widest">
                        AI đang phân tích tài liệu cũ...
                      </p>
                      <p className="text-slate-400 text-xs font-bold italic">Vui lòng không đóng trình duyệt</p>
                    </div>
                 </div>
               )}
            </div>
          )}

          {/* CREATE WORKSPACE */}
          {activeTab === 'create' && !generatedPlan && (
            <div className="max-w-4xl mx-auto">
              <div className="bg-white rounded-3xl shadow-xl border border-slate-100 p-12">
                 <div className="space-y-8">
                    <div>
                      <h3 className="text-2xl font-black text-slate-900 mb-3">Soạn giáo án mới</h3>
                      <p className="text-sm text-slate-500 font-medium">Chọn bài học từ chương trình Kết nối tri thức và AI sẽ thiết kế giáo án tích hợp năng lực số.</p>
                    </div>

                    <div className="space-y-4">
                      <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Chọn bài học lớp 6</label>
                      <div className="relative">
                        <select 
                           value={selectedLessonId}
                           onChange={(e) => setSelectedLessonId(e.target.value)}
                           className="w-full bg-slate-50 border border-slate-200 text-slate-800 text-sm font-bold rounded-2xl p-4 outline-none focus:ring-4 focus:ring-blue-100 transition-all cursor-pointer appearance-none pr-10"
                        >
                          <option value="">-- Chọn bài học từ danh sách đầy đủ --</option>
                          {DATABASE.map(chapter => (
                            <optgroup key={chapter.chapter} label={chapter.chapter}>
                              {chapter.lessons.map(lesson => (
                                <option key={lesson.id} value={lesson.id}>{lesson.name}</option>
                              ))}
                            </optgroup>
                          ))}
                        </select>
                        <ChevronDown className="absolute right-4 top-4 text-slate-400 pointer-events-none" size={20} />
                      </div>
                    </div>

                    <button 
                      onClick={async () => {
                        const lesson = DATABASE.flatMap(c => c.lessons).find(l => l.id === selectedLessonId);
                        if (!lesson) return;
                        setIsProcessing(true);
                        try {
                          const plan = await generateLessonPlan(GenerationMode.NEW, lesson.name);
                          setGeneratedPlan(plan);
                        } catch (e) { setError("Lỗi tạo bài giảng."); }
                        finally { setIsProcessing(false); }
                      }}
                      disabled={!selectedLessonId || isProcessing}
                      className="w-full py-5 bg-gradient-to-r from-blue-600 to-indigo-700 text-white font-black rounded-2xl shadow-xl shadow-blue-200 flex items-center justify-center gap-3 active:scale-[0.98] transition-all disabled:opacity-50"
                    >
                      {isProcessing ? <RefreshCw className="animate-spin" size={24}/> : <Cpu size={24}/>}
                      {isProcessing ? 'ĐANG TẠO BÀI DẠY...' : 'BẮT ĐẦU SOẠN THẢO'}
