            <div className="max-w-5xl mx-auto mb-20 animate-in fade-in slide-in-from-bottom-12 duration-1000">
               <div className="bg-white rounded-[3rem] shadow-2xl border border-slate-100 overflow-hidden" id="printable-lesson-plan">

                  <div className="bg-slate-900 text-white p-14 relative overflow-hidden no-print">
