                        <span className="flex items-center gap-3"><Layout size={18} className="text-blue-500"/> CHUẨN 5512</span>
                      </div>
                    </div>
                  </div>

                  <div className="p-14 md:p-20">
                    <div className="hidden print:block text-center mb-10 border-b pb-6">
