                    </div>

                    <section className="mb-16">
                      <h3 className="text-2xl font-black text-slate-900 mb-8 flex items-center gap-5">
                        <span className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center text-lg font-black shadow-inner border border-blue-100">I</span>
                        MỤC TIÊU BÀI DẠY
                      </h3>
                      <div className="bg-slate-50 p-10 rounded-[2.5rem] border border-slate-100 text-slate-700 leading-relaxed text-sm pl-16 whitespace-pre-wrap relative overflow-hidden shadow-inner">
                        <div className="absolute left-0 top-0 w-2 h-full bg-blue-500"></div>
                        {generatedPlan.objectives}
                      </div>
                    </section>

                    <section>
                      <h3 className="text-2xl font-black text-slate-900 mb-10 flex items-center gap-5">
                        <span className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center text-lg font-black shadow-inner border border-blue-100">II</span>
                        TIẾN TRÌNH DẠY HỌC
                      </h3>

                      <div className="space-y-8">
                        {generatedPlan.activities.map((act, idx) => (
                          <div key={idx} className="group border border-slate-200 rounded-[2.5rem] overflow-hidden hover:border-blue-300 transition-all shadow-sm hover:shadow-xl bg-white">
                             <div className="grid grid-cols-1 lg:grid-cols-12">
                                <div className="lg:col-span-8 p-10">
                                   <div className="flex items-center gap-4 mb-6">
                                      <span className="text-xs font-black text-blue-600 bg-blue-50 w-8 h-8 rounded-xl flex items-center justify-center border border-blue-100 shadow-sm">{idx + 1}</span>
                                      <h4 className="font-black text-slate-900 text-base uppercase tracking-tight">{act.title}</h4>
                                   </div>
                                   <div className="pl-12">
