    const link = document.createElement('a');
    link.href = url;
    link.download = `GiaoAn_Toan6_${generatedPlan.topic.replace(/\s+/g, '_')}.doc`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    setError(null);

    try {
      if (file.type.includes('wordprocessingml') || file.name.endsWith('.docx')) {
        // Trích xuất văn bản từ Docx vì Gemini inlineData không hỗ trợ Docx trực tiếp
        const arrayBuffer = await file.arrayBuffer();
        const result = await mammoth.extractRawText({ arrayBuffer });
        const textContent = result.value;

        setFileData({
          data: textContent,
          mimeType: 'text/plain',
          name: file.name,
          type: 'docx-text'
        });

        startAiProcessing(textContent, 'text/plain', file.name, true);
      } else {
        // PDF hoặc Ảnh - gửi trực tiếp cho Gemini Multimodal
        const reader = new FileReader();
        reader.onloadend = () => {
          const base64String = (reader.result as string).split(',')[1];
          setFileData({
            data: base64String,
            mimeType: file.type,
            name: file.name,
            type: file.type.split('/')[1]
          });
          startAiProcessing(base64String, file.type, file.name);
        };
        reader.readAsDataURL(file);
      }
    } catch (err) {
      setError("Lỗi khi xử lý tệp. Vui lòng thử lại.");
      setIsProcessing(false);
    }
  };

