              {activeTab === 'create' && 'Soạn giáo án điện tử'}
              {activeTab === 'competence' && 'Phụ lục 3 - Năng lực số'}
            </h2>
          </div>

          <div className="flex items-center gap-4">
            {generatedPlan && (
              <div className="flex gap-2">
