import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          content: { type: Type.STRING, description: 'Nội dung chi tiết hoạt động giảng dạy. Dùng công thức toán học dạng $...$ hoặc $$...$$' },
          digitalCompetency: { type: Type.STRING, description: 'Mã năng lực số: NL1, NL2, NL3, NL4, NL5' },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG nếu cần minh họa hình học' }
        },
        required: ['id', 'title', 'content', 'digitalCompetency']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let prompt = `Bạn là một chuyên gia giáo dục hàng đầu tại Việt Nam, am hiểu sâu sắc bộ sách "Kết nối tri thức với cuộc sống" môn Toán lớp 6 và Công văn 5512.`;

  if (mode === GenerationMode.TRANSFORM) {
    prompt += `
    NHIỆM VỤ: Phân tích tài liệu thầy cô cung cấp (có thể là giáo án cũ, bài giảng PDF/Word/Ảnh).
    1. Trích xuất chủ đề chính, mục tiêu bài học (kiến thức, kỹ năng).
    2. Chuyển đổi toàn bộ nội dung sang cấu trúc 4 hoạt động của CV 5512.
    3. Quan trọng: Tích hợp Năng lực số (NL1-NL5) một cách sáng tạo và thực tiễn vào từng hoạt động.
    4. Sử dụng công thức toán học LaTeX ($...$ hoặc $$...$$).

    TÀI LIỆU CỦA GIÁO VIÊN: ${extractedText || input}`;
  } else if (mode === GenerationMode.NEW) {
    prompt += `
    NHIỆM VỤ: Thiết kế giáo án điện tử hoàn toàn mới cho chủ đề: ${input}.
    1. Tuân thủ 4 hoạt động của CV 5512.
    2. Tích hợp năng lực số NL1-NL5.
    3. Minh họa hình học bằng mã SVG đẹp mắt trong các bài hình học.`;
  }

  const parts: any[] = [{ text: prompt }];

  // Nếu có fileData (PDF hoặc Ảnh) thì gửi multimodal
  if (fileData && !extractedText) {
    parts.push({
      inlineData: {
        mimeType: fileData.mimeType,
        data: fileData.data
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.1, // Giảm temperature để output ổn định hơn cho toán học
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi");

  return JSON.parse(text) as LessonPlan;
};

