import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          content: { type: Type.STRING, description: 'Nội dung chi tiết hoạt động giảng dạy. Bắt buộc dùng LaTeX chuẩn: $...$ cho công thức nội dòng và $$...$$ cho công thức riêng biệt. Không sử dụng các ký tự toán học Unicode lạ.' },
          digitalCompetency: { type: Type.STRING, description: 'Mã năng lực số: NL1, NL2, NL3, NL4, NL5' },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG nếu cần minh họa hình học (vuông, tròn, tam giác...)' }
        },
        required: ['id', 'title', 'content', 'digitalCompetency']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let prompt = `Bạn là chuyên gia giáo dục môn Toán, am hiểu sách "Kết nối tri thức với cuộc sống" lớp 6 và Công văn 5512.`;

  if (mode === GenerationMode.TRANSFORM) {
    prompt += `
    NHIỆM VỤ: Chuyển đổi tài liệu thầy cô tải lên thành giáo án điện tử chuẩn 5512.
    1. Trích xuất mục tiêu, kiến thức.
    2. Thiết kế 4 hoạt động: Mở đầu, Hình thành kiến thức, Luyện tập, Vận dụng.
    3. Tích hợp Năng lực số (NL1-NL5) vào từng hoạt động.
    4. CÔNG THỨC TOÁN: Phải dùng LaTeX chuẩn $...$ hoặc $$...$$. Tuyệt đối không dùng ký tự Unicode đặc biệt (như ², ³, √ trực tiếp) mà phải dùng LaTeX (như ^2, ^3, \\sqrt{}).

    TÀI LIỆU CỦA GIÁO VIÊN: ${extractedText || input}`;
  } else if (mode === GenerationMode.NEW) {
    prompt += `
    NHIỆM VỤ: Soạn giáo án mới cho bài: ${input}.
    1. Cấu trúc 4 hoạt động chuẩn 5512.
    2. Tích hợp năng lực số thực tiễn.
    3. Công thức toán dùng LaTeX $...$ hoặc $$...$$. 
    4. Nếu là bài hình học, hãy cung cấp mã SVG minh họa rõ ràng.`;
  }

  const parts: any[] = [{ text: prompt }];

  if (fileData && !extractedText) {
    parts.push({
      inlineData: {
        mimeType: fileData.mimeType,
        data: fileData.data
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.05, // Giảm temperature để tối ưu hóa tính chính xác của công thức
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi");

  return JSON.parse(text) as LessonPlan;
};

