            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { type: Type.STRING, description: 'Mã năng lực số: NL1-NL5' },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG minh họa (nếu là bài hình học)' }
        },
        required: ['id', 'title', 'objectives', 'content', 'product', 'execution', 'digitalCompetency']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let prompt = `Bạn là chuyên gia giáo dục môn Toán, am hiểu sâu sắc sách giáo khoa "Kết nối tri thức với cuộc sống" lớp 6 và các phụ lục của Công văn 5512/BGDĐT.

YÊU CẦU QUAN TRỌNG:
1. NỘI DUNG: Phải bám sát các đơn vị kiến thức và ví dụ trong SGK Kết nối tri thức Toán 6.
2. CẤU TRÚC 5512: Mỗi hoạt động phải có đủ: Mục tiêu, Nội dung, Sản phẩm và Tổ chức thực hiện (4 bước: Chuyển giao -> Thực hiện -> Báo cáo -> Kết luận).
3. CÔNG THỨC TOÁN: Sử dụng LaTeX chuẩn đặt trong cặp dấu $...$ cho công thức nội dòng và $$...$$ cho công thức khối. Đảm bảo cú pháp LaTeX tinh gọn để tính năng "Toggle TeX" của MathType trong Word có thể nhận diện chính xác.
4. TỔ CHỨC THỰC HIỆN: Phải viết cụ thể hành động của Giáo viên và Học sinh.
5. NĂNG LỰC SỐ: Lồng ghép NL1-NL5 một cách tự nhiên vào quy trình dạy học.`;

  if (mode === GenerationMode.TRANSFORM) {
    prompt += `\n\nNHIỆM VỤ: Chuyển đổi tài liệu sau thành giáo án 5512 chuẩn SGK Kết nối tri thức:\n${extractedText || input}`;
  } else if (mode === GenerationMode.NEW) {
    prompt += `\n\nNHIỆM VỤ: Soạn giáo án mới cho bài học: "${input}". Hãy liệt kê đầy đủ các hoạt động từ Mở đầu đến Vận dụng.`;
  }

  const parts: any[] = [{ text: prompt }];

  if (fileData && !extractedText) {
    parts.push({
      inlineData: {
        mimeType: fileData.mimeType,
        data: fileData.data
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.1,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi");

  return JSON.parse(text) as LessonPlan;
};

