export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let prompt = `Bạn là một giáo viên cốt cán môn Toán lớp 6, chuyên gia soạn bài theo bộ sách "Kết nối tri thức với cuộc sống" và nắm vững Công văn 5512/BGDĐT.

YÊU CẦU NGHIÊM NGẶT:
1. NỘI DUNG SGK: Nội dung phải bám sát chính xác các bài học, ví dụ, và thuật ngữ trong SGK Kết nối tri thức Toán 6.
2. MẪU GIÁO ÁN 5512:
   - Phần I: Mục tiêu (Kiến thức, Năng lực, Phẩm chất).
   - Phần II: Thiết bị dạy học và học liệu.
   - Phần III: Tiến trình dạy học (Chia thành các hoạt động: Mở đầu, Hình thành kiến thức, Luyện tập, Vận dụng).
3. QUY TRÌNH 4 BƯỚC: Mỗi hoạt động phải có đủ 4 bước tổ chức: Chuyển giao nhiệm vụ -> Thực hiện nhiệm vụ -> Báo cáo, thảo luận -> Kết luận, nhận định.
4. CÔNG THỨC TOÁN (MATH TYPE COMPATIBLE): 
   - Sử dụng định dạng LaTeX chuẩn để tương thích với tính năng "Toggle TeX" của MathType trong Word.
   - Dùng cặp dấu $...$ cho công thức nội dòng.
   - Dùng cặp dấu $$...$$ cho công thức khối.
   - Tránh các ký tự Unicode toán học lạ, chỉ dùng lệnh LaTeX thuần (vd: \\frac{a}{b}, ^2, \\sqrt{x}).
5. NĂNG LỰC SỐ: Tích hợp các mã NL1-NL5 vào các bước thực hiện một cách thực tế.`;

  if (mode === GenerationMode.TRANSFORM) {
    prompt += `\n\nNHIỆM VỤ: Chuyển đổi nội dung giáo án sau đây sang chuẩn 5512 và SGK Kết nối tri thức:\n${extractedText || input}`;
  } else {
    prompt += `\n\nNHIỆM VỤ: Soạn giáo án hoàn chỉnh cho bài: "${input}".`;
  }

  const parts: any[] = [{ text: prompt }];
  if (fileData && !extractedText) {
    parts.push({ inlineData: { mimeType: fileData.mimeType, data: fileData.data } });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.1,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi");

  return JSON.parse(text) as LessonPlan;
};

