import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING, description: 'Mục tiêu: 1. Kiến thức; 2. Năng lực (Chung, đặc thù Toán); 3. Phẩm chất' },
    preparations: { type: Type.STRING, description: 'Thiết bị dạy học và học liệu (GV và HS)' },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING, description: 'Tên hoạt động (vd: Hoạt động 1: Mở đầu)' },
          objectives: { type: Type.STRING, description: 'Mục tiêu cụ thể hoạt động' },
          content: { type: Type.STRING, description: 'Nội dung và nhiệm vụ học tập (Bắt buộc dùng LaTeX $...$)' },
          product: { type: Type.STRING, description: 'Sản phẩm của học sinh (Bắt buộc dùng LaTeX $...$)' },
          execution: {
            type: Type.OBJECT,
            properties: {
              assignTask: { type: Type.STRING, description: 'Bước 1: Chuyển giao nhiệm vụ' },
              executeTask: { type: Type.STRING, description: 'Bước 2: Thực hiện nhiệm vụ' },
              reportDiscuss: { type: Type.STRING, description: 'Bước 3: Báo cáo, thảo luận' },
              concludeAssess: { type: Type.STRING, description: 'Bước 4: Kết luận, nhận định' }
            },
            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { type: Type.STRING, description: 'Mã NL số (NL1, NL2, NL3, NL4 hoặc NL5)' },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG minh họa (nếu cần)' }
        },
        required: ['id', 'title', 'objectives', 'content', 'product', 'execution', 'digitalCompetency']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let prompt = `Bạn là một chuyên gia giáo dục dạy Toán 6 (Bộ sách Kết nối tri thức).
NHIỆM VỤ: Soạn giáo án chuẩn Công văn 5512 bám sát SGK Kết nối tri thức.

YÊU CẦU CHI TIẾT:
1. NỘI DUNG: Phải đúng kiến thức, ví dụ và bài tập trong SGK Toán 6 Kết nối tri thức.
2. CẤU TRÚC 5512:
   - Mỗi hoạt động phải có 2 phần chính tương ứng 2 cột:
     + Cột 1: Hoạt động học (Nội dung và Sản phẩm).
     + Cột 2: Tổ chức thực hiện (Đủ 4 bước: Chuyển giao -> Thực hiện -> Báo cáo -> Kết luận).
3. CÔNG THỨC TOÁN (MATH TYPE): 
   - Tuyệt đối chỉ dùng LaTeX đặt trong $...$ hoặc $$...$$. 
   - Không dùng ký tự Unicode đặc biệt (như ², ³, √, ∈). Thay bằng $^2$, $^3$, $\\sqrt{}$, $\\in$.
   - Điều này giúp giáo viên nhấn "Toggle TeX" trong Word để MathType nhận diện.
4. NĂNG LỰC SỐ: Phải chọn chính xác 1 trong các mã (NL1, NL2, NL3, NL4, NL5) cho mỗi hoạt động và mô tả cách lồng ghép công nghệ vào bước thực hiện.
`;

  if (mode === GenerationMode.TRANSFORM) {
    prompt += `\n\nPHÂN TÍCH TÀI LIỆU SAU ĐỂ CHUYỂN ĐỔI SANG 5512:\n${extractedText || 'Dữ liệu từ tệp tin đính kèm.'}`;
  } else {
    prompt += `\n\nSOẠN MỚI GIÁO ÁN CHO BÀI: "${input}".`;
  }

  const parts: any[] = [{ text: prompt }];
  if (fileData) {
    parts.push({
      inlineData: {
        mimeType: fileData.mimeType,
        data: fileData.data
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [{ parts }],
    config: {
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.1,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi dữ liệu");
  return JSON.parse(text) as LessonPlan;
};

