import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING, description: 'Mục tiêu: 1. Kiến thức; 2. Năng lực (Chung và Đặc thù Toán); 3. Phẩm chất' },
    preparations: { type: Type.STRING, description: 'Thiết bị dạy học và học liệu (GV và HS)' },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING, description: 'Tên hoạt động (vd: Hoạt động 1: Mở đầu)' },
          objectives: { type: Type.STRING, description: 'Mục tiêu cụ thể hoạt động' },
          content: { type: Type.STRING, description: 'Nội dung và nhiệm vụ học tập (Dùng LaTeX $...$)' },
          product: { type: Type.STRING, description: 'Sản phẩm của học sinh (Dùng LaTeX $...$)' },
          execution: {
            type: Type.OBJECT,
            properties: {
              assignTask: { type: Type.STRING, description: 'Bước 1: Chuyển giao nhiệm vụ' },
              executeTask: { type: Type.STRING, description: 'Bước 2: Thực hiện nhiệm vụ' },
              reportDiscuss: { type: Type.STRING, description: 'Bước 3: Báo cáo, thảo luận' },
              concludeAssess: { type: Type.STRING, description: 'Bước 4: Kết luận, nhận định' }
            },
            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { type: Type.STRING, description: 'BẮT BUỘC: Ghi mã NL1, NL2, NL3, NL4 hoặc NL5' },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG minh họa đơn giản (nếu cần)' }
        },
        required: ['id', 'title', 'objectives', 'content', 'product', 'execution', 'digitalCompetency']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Sử dụng flash-preview để tăng tốc độ xử lý khi tải file, nhưng vẫn giữ độ chính xác cao cho 5512
  const modelName = 'gemini-3-flash-preview'; 

  let prompt = `Bạn là một chuyên gia giáo dục dạy Toán 6 (Bộ sách Kết nối tri thức).
NHIỆM VỤ: Soạn giáo án chuẩn Công văn 5512 bám sát SGK Kết nối tri thức.

YÊU CẦU CỰC KỲ QUAN TRỌNG:
1. CẤU TRÚC 5512: Phải chia rõ 2 phần cho mỗi hoạt động:
   - Phần 1: Nội dung và Sản phẩm.
   - Phần 2: Tổ chức thực hiện (4 bước: Chuyển giao, Thực hiện, Báo cáo, Kết luận).
2. NĂNG LỰC SỐ: Mỗi hoạt động PHẢI có 1 mã năng lực số (NL1-NL5).
3. TOÁN HỌC (MATHTYPE): 
   - Dùng LaTeX chuẩn: $x^2$, $\\frac{a}{b}$, $\\sqrt{x}$, $\\in$, $\\mathbb{N}$. 
   - Tuyệt đối không dùng ký tự đặc biệt Unicode để tránh lỗi khi dùng MathType Toggle TeX.
4. NỘI DUNG: Phải đúng kiến thức bài "${input}" của sách Kết nối tri thức Toán 6.`;

  if (mode === GenerationMode.TRANSFORM) {
    prompt += `\n\nCHUYỂN ĐỔI TÀI LIỆU SAU SANG CHUẨN 5512 (Hãy giữ lại các ví dụ hay nếu có):\n${extractedText || 'Dữ liệu trong tệp đính kèm.'}`;
  }

  const parts: any[] = [{ text: prompt }];
  if (fileData) {
    parts.push({
      inlineData: {
        mimeType: fileData.mimeType,
        data: fileData.data
      }
    });
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts }],
    config: {
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.1, // Thấp để đảm bảo tính chính xác và cấu trúc JSON
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi dữ liệu. Thầy vui lòng thử lại.");
  return JSON.parse(text) as LessonPlan;
};

