  "Đang hoàn thiện các bước tổ chức thực hiện..."
];

export default function LessonPlanApp() {
  const [activeTab, setActiveTab] = useState('upload');
  const [selectedLessonId, setSelectedLessonId] = useState('');
  const [generatedPlan, setGeneratedPlan] = useState<LessonPlan | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadingMsgIdx, setLoadingMsgIdx] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [fileData, setFileData] = useState<{ name: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Hiệu ứng thay đổi thông điệp loading
  useEffect(() => {
    let interval: any;
    if (isProcessing) {
      interval = setInterval(() => {
        setLoadingMsgIdx(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 3000);
    } else {
      setLoadingMsgIdx(0);
    }
    return () => clearInterval(interval);
  }, [isProcessing]);

  const convertSvgToPng = async (svgString: string): Promise<string> => {
    return new Promise((resolve) => {
      const img = new Image();
      const svgBlob = new Blob([svgString], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 800; canvas.height = 600;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.fillStyle = 'white'; ctx.fillRect(0, 0, canvas.width, canvas.height);
          const scale = Math.min(canvas.width / img.width, canvas.height / img.height) * 0.9;
          ctx.drawImage(img, (canvas.width - img.width * scale) / 2, (canvas.height - img.height * scale) / 2, img.width * scale, img.height * scale);
          resolve(canvas.toDataURL('image/png'));
        } else resolve('');
      };
      img.src = url;
    });
  };

  const handleDownloadWord = async () => {
    if (!generatedPlan) return;
    setIsProcessing(true);

    try {
      const images = await Promise.all(generatedPlan.activities.map(a => a.svgDiagram ? convertSvgToPng(a.svgDiagram) : ''));

      const htmlContent = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
          <meta charset='utf-8'>
          <style>
            @page { size: A4; margin: 1.5cm 1.5cm 1.5cm 2cm; }
            body { font-family: 'Times New Roman', serif; font-size: 11pt; line-height: 1.3; color: #000; }
            .center { text-align: center; }
            .bold { font-weight: bold; }
            .uppercase { text-transform: uppercase; }
            table { width: 100%; border-collapse: collapse; margin-top: 10pt; }
            th, td { border: 0.5pt solid black; padding: 6pt; vertical-align: top; }
            .section-title { font-size: 12pt; font-weight: bold; margin-top: 15pt; text-transform: uppercase; }
            .step-label { font-weight: bold; font-style: italic; }
            .digital-footer { font-size: 9pt; font-weight: bold; color: #333; margin-top: 8pt; border-top: 0.5pt dashed #999; padding-top: 2pt; }
          </style>
        </head>
        <body>
          <div class="center">
            <p class="bold uppercase">GIÁO ÁN (KẾ HOẠCH BÀI DẠY) MÔN TOÁN 6</p>
            <p class="bold uppercase" style="font-size: 14pt;">BÀI: ${generatedPlan.topic}</p>
            <p>Bộ sách: Kết nối tri thức với cuộc sống • Chuẩn Công văn 5512</p>
          </div>

          <div class="section-title">I. MỤC TIÊU</div>
          <div>${generatedPlan.objectives.replace(/\n/g, '<br/>')}</div>

          <div class="section-title">II. THIẾT BỊ DẠY HỌC VÀ HỌC LIỆU</div>
          <div>${generatedPlan.preparations.replace(/\n/g, '<br/>')}</div>

          <div class="section-title">III. TIẾN TRÌNH DẠY HỌC</div>
          <table>
            <tr style="background-color: #f3f4f6;">
              <th style="width: 45%;">Hoạt động học (Nội dung, Sản phẩm)</th>
              <th style="width: 55%;">Tổ chức thực hiện & Năng lực số</th>
            </tr>
            ${generatedPlan.activities.map((act, i) => `
              <tr>
                <td>
                  <p class="bold">${act.title}</p>
                  <p><span class="bold">1. Nội dung học tập:</span></p>
                  <p>${act.content.replace(/\n/g, '<br/>')}</p>
                  <p><span class="bold">2. Sản phẩm học tập:</span></p>
                  <p>${act.product.replace(/\n/g, '<br/>')}</p>
                  ${images[i] ? `<div class="center" style="margin-top:10pt;"><img src="${images[i]}" width="280"/></div>` : ''}
                </td>
                <td>
                  <p><span class="step-label">Bước 1: Chuyển giao nhiệm vụ:</span> ${act.execution.assignTask}</p>
                  <p><span class="step-label">Bước 2: Thực hiện nhiệm vụ:</span> ${act.execution.executeTask}</p>
                  <p><span class="step-label">Bước 3: Báo cáo, thảo luận:</span> ${act.execution.reportDiscuss}</p>
                  <p><span class="step-label">Bước 4: Kết luận, nhận định:</span> ${act.execution.concludeAssess}</p>
                  <div class="digital-footer">Tích hợp Năng lực số: ${act.digitalCompetency}</div>
                </td>
              </tr>
            `).join('')}
          </table>

          <table style="border: none; margin-top: 40pt;">
            <tr style="border: none;">
              <td style="border: none; text-align: center; width: 50%;"><b>XÁC NHẬN CỦA TỔ CHUYÊN MÔN</b></td>
              <td style="border: none; text-align: center; width: 50%;"><b>GIÁO VIÊN SOẠN BÀI</b></td>
            </tr>
          </table>
        </body>
        </html>
      `;

      const blob = new Blob(['\ufeff', htmlContent], { type: 'application/msword' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `GiaoAn_Toan6_5512_${generatedPlan.topic.replace(/\s+/g, '_')}.doc`;
      link.click();
    } catch (e) {
      setError("Có lỗi khi xuất file Word. Thầy vui lòng thử lại.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    setError(null);
    setFileData({ name: file.name });

    try {
      let extractedText = "";
      let base64Data = "";

      const reader = new FileReader();

      if (file.name.endsWith('.docx')) {
        const arrayBuffer = await file.arrayBuffer();
        const result = await mammoth.extractRawText({ arrayBuffer });
        extractedText = result.value;
        reader.onloadend = async () => {
          base64Data = (reader.result as string).split(',')[1];
          const plan = await generateLessonPlan(GenerationMode.TRANSFORM, file.name, { data: base64Data, mimeType: file.type }, extractedText);
          setGeneratedPlan(plan);
          setIsProcessing(false);
        };
      } else {
        reader.onloadend = async () => {
          base64Data = (reader.result as string).split(',')[1];
          const plan = await generateLessonPlan(GenerationMode.TRANSFORM, file.name, { data: base64Data, mimeType: file.type });
          setGeneratedPlan(plan);
          setIsProcessing(false);
        };
      }
      reader.readAsDataURL(file);

