import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING, description: 'Mục tiêu: Kiến thức, Năng lực, Phẩm chất' },
    preparations: { type: Type.STRING, description: 'Thiết bị dạy học và học liệu' },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING, description: 'Tên hoạt động' },
          objectives: { type: Type.STRING },
          content: { type: Type.STRING, description: 'Nhiệm vụ học tập (Sử dụng LaTeX $...$)' },
          product: { type: Type.STRING, description: 'Sản phẩm học tập (Sử dụng LaTeX $...$)' },
          execution: {
            type: Type.OBJECT,
            properties: {
              assignTask: { type: Type.STRING },
              executeTask: { type: Type.STRING },
              reportDiscuss: { type: Type.STRING },
              concludeAssess: { type: Type.STRING }
            },
            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { type: Type.STRING, description: 'Bắt buộc chọn mã: NL1, NL2, NL3, NL4 hoặc NL5' }
        },
        required: ['id', 'title', 'objectives', 'content', 'product', 'execution', 'digitalCompetency']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Model Flash cho tốc độ xử lý nhanh nhất
  const modelName = 'gemini-3-flash-preview'; 

  const systemInstruction = `Bạn là chuyên gia soạn giáo án Toán 6 Kết nối tri thức. 
Nhiệm vụ: Soạn hoặc chuyển đổi giáo án sang chuẩn Công văn 5512 với 2 cột và tích hợp năng lực số (NL1-NL5).

QUY TẮC CỨNG:
1. CẤU TRÚC 5512: Mỗi hoạt động phải có 2 cột nội dung (Cột 1: Nội dung/Sản phẩm; Cột 2: Tổ chức thực hiện đủ 4 bước).
2. NĂNG LỰC SỐ: Bắt buộc gán ít nhất một mã (NL1, NL2, NL3, NL4, NL5) cho mỗi hoạt động.
3. MATHTYPE COMPATIBLE: Chỉ dùng LaTeX trong $...$ hoặc $$...$$. Không dùng ký tự unicode như ², √, ∈. Ví dụ: dùng $x^2$, $\\sqrt{x}$, $\\in$.
4. TỐC ĐỘ: Trả về kết quả JSON chính xác, ngắn gọn, súc tích nhưng đầy đủ chuyên môn.`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `Dựa trên nội dung giáo án cũ sau đây, hãy cấu trúc lại hoàn toàn sang mẫu 5512 (2 cột) và tích hợp năng lực số cho từng bước: \n\n${extractedText || 'Sử dụng dữ liệu từ tệp đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án bài "${input}" (Toán 6 Kết nối tri thức) theo chuẩn 5512, tích hợp năng lực số và LaTeX MathType.`;
  }

  const parts: any[] = [{ text: prompt }];
  if (fileData) {
    parts.push({
      inlineData: {
        mimeType: fileData.mimeType,
        data: fileData.data
      }
    });
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.1,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi dữ liệu.");
  return JSON.parse(text) as LessonPlan;
};

