import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING, description: 'Mục tiêu: 1. Kiến thức; 2. Năng lực (Chung và Đặc thù Toán học); 3. Phẩm chất' },
    preparations: { type: Type.STRING, description: 'Thiết bị dạy học và học liệu (GV và HS chuẩn bị)' },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING, description: 'Tên hoạt động (vd: Hoạt động 1: Xác định tập hợp)' },
          objectives: { type: Type.STRING, description: 'Mục tiêu riêng' },
          content: { type: Type.STRING, description: 'Nội dung và nhiệm vụ học tập (Sử dụng LaTeX sạch $...$)' },
          product: { type: Type.STRING, description: 'Sản phẩm học tập (Sử dụng LaTeX sạch $...$)' },
          execution: {
            type: Type.OBJECT,
            properties: {
              assignTask: { type: Type.STRING, description: 'Bước 1: Chuyển giao nhiệm vụ' },
              executeTask: { type: Type.STRING, description: 'Bước 2: Thực hiện nhiệm vụ' },
              reportDiscuss: { type: Type.STRING, description: 'Bước 3: Báo cáo, thảo luận' },
              concludeAssess: { type: Type.STRING, description: 'Bước 4: Kết luận, nhận định' }
            },
            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { type: Type.STRING, description: 'Mã NL số (NL1-NL5) và giải thích ngắn cách tích hợp (ví dụ: NL3 - Sử dụng phần mềm Geogebra vẽ hình)' },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG hoàn chỉnh nếu bài học có hình vẽ hình học (hình vuông, tam giác, thoi...). Vẽ trên nền trắng, kích thước 400x300.' }
        },
        required: ['id', 'title', 'objectives', 'content', 'product', 'execution', 'digitalCompetency']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-flash-preview'; 

  const systemInstruction = `Bạn là một chuyên gia giáo dục dạy Toán 6 (Bộ sách Kết nối tri thức).
NHIỆM VỤ: Soạn giáo án chuẩn Công văn 5512 với cấu trúc 2 cột.

QUY TẮC CÔNG THỨC TOÁN (MATHTYPE):
- Tuyệt đối KHÔNG dùng ký tự Unicode đặc biệt (không dùng ², ³, √, ∈, ⊂, ∩, ∅, π, ...).
- BẮT BUỘC dùng LaTeX tiêu chuẩn đặt trong cặp dấu $...$ (inline) hoặc $$...$$ (block).
- Ví dụ: Dùng $x^2$ thay vì x², dùng $\\sqrt{x}$ thay vì √x, dùng $\\in$ thay vì ∈.
- Mục đích: Để giáo viên khi copy vào Word, chỉ cần chọn đoạn text và bấm "Toggle TeX" của MathType là chuyển đổi được ngay.

QUY TẮC 5512 & NĂNG LỰC SỐ:
- Cột 1: Hoạt động học (Nhiệm vụ & Sản phẩm).
- Cột 2: Tổ chức thực hiện (4 bước).
- Năng lực số (NL1-NL5): Phải gợi ý mã phù hợp dựa trên nhiệm vụ. Ví dụ: Nếu dùng máy tính bỏ túi là NL3, nếu tra cứu internet là NL5, nếu dùng tivi trình chiếu là NL1.

HÌNH VẼ HÌNH HỌC:
- Nếu bài học có nội dung hình học (Chương 4, 5, 8), hãy tạo mã SVG minh họa sắc nét, đầy đủ ký hiệu điểm, cạnh.`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `Phân tích giáo án cũ sau đây và chuyển đổi sang chuẩn 5512 hai cột. Cập nhật các ví dụ theo đúng bộ sách Kết nối tri thức Toán 6: \n\n${extractedText || 'Dữ liệu trong tệp đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án mới cho bài: "${input}" (Toán 6 Kết nối tri thức) theo chuẩn 5512. Tích hợp năng lực số và LaTeX MathType.`;
  }

  const parts: any[] = [{ text: prompt }];
  if (fileData) {
    parts.push({
      inlineData: {
        mimeType: fileData.mimeType,
        data: fileData.data
      }
    });
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.1,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

