    chapter: "Chương 4: Một số hình phẳng trong thực tế",
    lessons: [
      { id: "t6_c4_b18", name: "Bài 18: Hình tam giác đều. Hình vuông. Hình lục giác đều" },
      { id: "t6_c4_b19", name: "Bài 19: Hình chữ nhật. Hình thoi. Hình bình hành. Hình thang cân" }
    ]
  }
];

const LOADING_MESSAGES = [
  "Đang đọc dữ liệu...",
  "AI đang phân tích 2 cột 5512...",
  "Chuẩn hóa LaTeX cho MathType...",
  "Tích hợp mã Năng lực số...",
  "Đang phác thảo hình vẽ SVG...",
  "Gần xong rồi, thầy đợi chút nhé..."
];

export default function LessonPlanApp() {
  const [activeTab, setActiveTab] = useState('upload');
  const [selectedLessonId, setSelectedLessonId] = useState('');
  const [generatedPlan, setGeneratedPlan] = useState<LessonPlan | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadingMsgIdx, setLoadingMsgIdx] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    let interval: any;
    if (isProcessing) {
      interval = setInterval(() => {
        setLoadingMsgIdx(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 1500);
    }
    return () => clearInterval(interval);
  }, [isProcessing]);

  const handleDownloadWord = async () => {
    if (!generatedPlan) return;
    setIsProcessing(true);

    const htmlContent = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset='utf-8'>
        <style>
          @page { size: A4; margin: 1.5cm 1.5cm 1.5cm 2cm; }
          body { font-family: 'Times New Roman', serif; font-size: 11pt; line-height: 1.5; color: #000; }
          .center { text-align: center; }
          .bold { font-weight: bold; }
          .uppercase { text-transform: uppercase; }
          table { width: 100%; border-collapse: collapse; margin-top: 10pt; table-layout: fixed; }
          th, td { border: 0.5pt solid black; padding: 7pt; vertical-align: top; word-wrap: break-word; }
          .step-label { font-weight: bold; font-style: italic; display: block; margin-top: 4pt; }
          .activity-header { background-color: #f3f4f6; font-weight: bold; }
          .nl-box { font-size: 9pt; color: #444; border-top: 0.5pt dashed #ccc; padding-top: 5pt; margin-top: 10pt; }
        </style>
      </head>
      <body>
        <div class="center">
          <p class="bold uppercase" style="font-size: 12pt;">GIÁO ÁN MÔN TOÁN 6 - BỘ KẾT NỐI TRI THỨC</p>
          <p class="bold uppercase" style="font-size: 14pt;">BÀI: ${generatedPlan.topic}</p>
          <p><i>(Dành cho MathType: Sử dụng tính năng Toggle TeX để chuyển đổi công thức $)</i></p>
        </div>
        <p><b>I. MỤC TIÊU</b></p>
        <div>${generatedPlan.objectives.replace(/\n/g, '<br/>')}</div>
        <p><b>II. THIẾT BỊ DẠY HỌC VÀ HỌC LIỆU</b></p>
        <div>${generatedPlan.preparations.replace(/\n/g, '<br/>')}</div>
        <p><b>III. TIẾN TRÌNH DẠY HỌC</b></p>
        <table>
          <tr style="background-color: #e5e7eb;">
            <th style="width: 45%;">1. Hoạt động học (Nội dung, Sản phẩm)</th>
