          </button>
        </nav>

        <div className="p-6 bg-black/20 text-center">
          <p className="text-[9px] font-bold text-slate-500 uppercase tracking-widest">Toán 6 - Kết nối tri thức</p>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-full overflow-hidden bg-slate-50 relative">
        <header className="h-20 bg-white border-b flex items-center justify-between px-12 z-20 no-print">
          <div className="flex items-center gap-3">
            <Sparkles size={18} className="text-blue-600" />
            <h2 className="font-black text-slate-800 text-[10px] uppercase tracking-[0.2em]">Trợ lý soạn giáo án thông minh</h2>
          </div>
          {generatedPlan && (
            <button onClick={handleDownloadWord} disabled={isProcessing} className="bg-slate-900 text-white px-10 py-3.5 rounded-2xl font-black text-xs flex items-center gap-3 hover:bg-black transition-all shadow-xl shadow-slate-900/10">
              {isProcessing ? <RefreshCw className="animate-spin" size={18}/> : <FileCode size={18}/>}
