        <div className="flex-1 overflow-auto p-12">
          {error && <div className="max-w-4xl mx-auto bg-red-50 text-red-600 p-8 rounded-[2rem] mb-10 border border-red-100 font-bold text-sm flex gap-5 animate-in slide-in-from-top-4 shadow-xl shadow-red-100/50"><FileWarning size={24}/> {error}</div>}

          {/* Upload Area */}
          {activeTab === 'upload' && !generatedPlan && (
            <div className="max-w-4xl mx-auto mt-20 text-center">
              <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept=".pdf,.docx,image/*" />
              {!isProcessing ? (
                <div onClick={() => fileInputRef.current?.click()} className="bg-white border-4 border-dashed border-slate-200 p-32 rounded-[4rem] cursor-pointer hover:border-blue-500 hover:bg-blue-50/30 transition-all group shadow-2xl shadow-slate-200/20 relative">
                  <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-blue-600 text-white px-6 py-2 rounded-full font-black text-[10px] tracking-widest uppercase">Phân tích siêu tốc</div>
                  <Upload size={80} className="mx-auto text-slate-300 group-hover:text-blue-500 mb-10 transition-transform group-hover:-translate-y-3" />
                  <h3 className="text-4xl font-black text-slate-900 mb-6 tracking-tighter">Tải lên giáo án hoặc tài liệu</h3>
                  <p className="text-slate-500 font-bold max-w-lg mx-auto leading-relaxed text-sm uppercase tracking-widest opacity-60">AI sẽ tự động nhận diện bài học, cấu trúc lại theo chuẩn 5512 (2 cột) và tích hợp năng lực số cho thầy trong vài giây.</p>
                </div>
              ) : (
                <div className="p-32 bg-white rounded-[4rem] shadow-2xl text-center max-w-2xl mx-auto border border-blue-50">
                  <RefreshCw className="animate-spin mx-auto text-blue-600 mb-10" size={80} />
                  <h3 className="text-3xl font-black mb-4 tracking-tight">AI đang làm việc...</h3>
                  <div className="h-1.5 w-48 bg-slate-100 rounded-full mx-auto mb-8 overflow-hidden">
                    <div className="h-full bg-blue-600 animate-[loading_1.5s_infinite]"></div>
                  </div>
                  <p className="text-blue-600 font-black uppercase tracking-[0.25em] text-[11px] animate-pulse">
                    {LOADING_MESSAGES[loadingMsgIdx]}
