            </div>
          )}

          {/* Create New Area */}
          {activeTab === 'create' && !generatedPlan && (
            <div className="max-w-3xl mx-auto mt-20 bg-white p-20 rounded-[4rem] shadow-2xl border border-white">
              <h3 className="text-3xl font-black text-slate-900 mb-12 flex items-center gap-5 tracking-tighter">
