                  try { const plan = await generateLessonPlan(GenerationMode.NEW, lesson.name); setGeneratedPlan(plan); } catch (e) { setError("Gặp lỗi khi soạn thảo. Thầy vui lòng thử lại."); } finally { setIsProcessing(false); }
                }} className="w-full py-8 bg-blue-600 text-white rounded-[2.5rem] font-black text-xl hover:bg-blue-700 transition-all shadow-2xl shadow-blue-500/30 active:scale-95">
                  {isProcessing ? 'ĐANG SOẠN THẢO...' : 'BẮT ĐẦU SOẠN GIÁO ÁN'}
