            </div>
          )}

          {/* View Generated Plan */}
          {generatedPlan && (
            <div className="max-w-6xl mx-auto bg-white rounded-[3.5rem] shadow-2xl border border-white overflow-hidden mb-32 animate-in zoom-in-95 duration-500">
