                <div className="absolute top-0 right-0 p-12 opacity-5 scale-150"><Calculator size={120} /></div>
                <div className="flex gap-4 mb-6">
                   <span className="bg-blue-600 px-5 py-2 rounded-full text-[10px] font-black tracking-widest uppercase">Toán 6 - Kết nối tri thức</span>
