                              <div className="pl-6 border-l-4 border-blue-600 py-1 transition-all group-hover:pl-8">
                                <p><b className="text-slate-900 font-black">Bước 1: Chuyển giao:</b> {act.execution.assignTask}</p>
                              </div>
                              <div className="pl-6 border-l-4 border-blue-400 py-1 transition-all group-hover:pl-8">
                                <p><b className="text-slate-900 font-black">Bước 2: Thực hiện:</b> {act.execution.executeTask}</p>
                              </div>
                              <div className="pl-6 border-l-4 border-indigo-400 py-1 transition-all group-hover:pl-8">
                                <p><b className="text-slate-900 font-black">Bước 3: Báo cáo:</b> {act.execution.reportDiscuss}</p>
                              </div>
                              <div className="pl-6 border-l-4 border-emerald-400 py-1 transition-all group-hover:pl-8">
                                <p><b className="text-slate-900 font-black">Bước 4: Kết luận:</b> {act.execution.concludeAssess}</p>
                              </div>

                              <div className="mt-12 p-8 bg-white rounded-[2.5rem] border-2 border-blue-50 flex gap-6 items-center shadow-lg shadow-blue-500/5">
                                <div className="w-16 h-16 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl flex items-center justify-center text-white shadow-xl shadow-blue-500/20 group-hover:rotate-6 transition-transform"><Cpu size={32}/></div>
                                <div>
                                  <p className="font-black uppercase tracking-[0.2em] text-[10px] text-slate-400 mb-1">Năng lực số tích hợp</p>
                                  <p className="font-bold text-slate-900 text-lg">{act.digitalCompetency}</p>
                                </div>
                              </div>
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
