                </section>
              </div>
            </div>
          )}

          {/* Competence Map */}
          {activeTab === 'competence' && (
            <div className="max-w-5xl mx-auto space-y-8 pb-32">
              <div className="text-center mb-16">
                <h3 className="text-5xl font-black mb-4 tracking-tighter text-slate-900 uppercase">Khung năng lực số 5512</h3>
                <p className="text-slate-500 font-bold uppercase text-[11px] tracking-[0.4em] opacity-60">Theo quy định hiện hành của Bộ Giáo dục</p>
              </div>
              {DIGITAL_COMPETENCIES.map((c, idx) => (
                <div key={c.code} className="bg-white p-12 rounded-[3.5rem] border-2 border-white shadow-2xl flex gap-10 items-start hover:border-blue-400 transition-all hover:translate-x-3 group animate-in slide-in-from-left-6" style={{animationDelay: `${idx * 150}ms`}}>
