                  <div>
                    <h4 className="font-black text-2xl text-slate-900 mb-4 group-hover:text-blue-600 transition-colors">{c.name}</h4>
                    <p className="text-slate-500 text-lg font-medium leading-relaxed opacity-80">{c.description}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>
      <style>{`
        @keyframes loading {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(400%); }
        }
      `}</style>
    </div>
  );
}

import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING, description: 'Mục tiêu: 1. Kiến thức; 2. Năng lực (Chung và Đặc thù Toán học); 3. Phẩm chất' },
    preparations: { type: Type.STRING, description: 'Thiết bị dạy học và học liệu (GV và HS chuẩn bị)' },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING, description: 'Tên hoạt động (vd: Hoạt động 1: Khởi động - Tiếp cận khái niệm)' },
          objectives: { type: Type.STRING, description: 'Mục tiêu riêng' },
          content: { type: Type.STRING, description: 'Nội dung và nhiệm vụ học tập chi tiết. BẮT BUỘC dùng LaTeX trong $...$' },
          product: { type: Type.STRING, description: 'Sản phẩm học tập cụ thể của HS. BẮT BUỘC dùng LaTeX trong $...$' },
          execution: {
            type: Type.OBJECT,
            properties: {
