              concludeAssess: { type: Type.STRING, description: 'Bước 4: Kết luận, nhận định (GV chốt kiến thức, nhận xét)' }
            },
            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { type: Type.STRING, description: 'Mã NL số (NL1-NL5) + Mô tả cách thực hiện số hóa (ví dụ: NL3 - Sử dụng phần mềm Geogebra để mô phỏng hình vẽ)' },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG vẽ hình hình học (nếu có). Sử dụng stroke-width="2", font-family="Arial", background white.' }
        },
        required: ['id', 'title', 'objectives', 'content', 'product', 'execution', 'digitalCompetency']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-flash-preview'; 

  const systemInstruction = `Bạn là chuyên gia giáo dục dạy Toán 6 (Bộ sách Kết nối tri thức).
NHIỆM VỤ: Soạn giáo án chuẩn Công văn 5512 với cấu trúc 2 cột.

QUY TẮC TOÁN HỌC (MATHTYPE TOGGLE TEX):
- Tuyệt đối KHÔNG dùng ký tự Unicode đặc biệt (², ³, √, ∈, ⊂, ∩, ∅, π, độ °).
- BẮT BUỘC dùng LaTeX tiêu chuẩn:
  + Dùng $x^2$ thay vì x²
  + Dùng $\\sqrt{x}$ thay vì √x
  + Dùng $\\frac{a}{b}$ cho phân số
  + Dùng $\\in, \\notin$ cho tập hợp
  + Dùng ^\\circ cho độ (ví dụ: $60^\\circ$)
- Mọi công thức phải nằm trong cặp dấu $...$.

QUY TẮC NĂNG LỰC SỐ (NL1-NL5):
- Hãy chọn mã NL phù hợp nhất với nhiệm vụ học tập:
  + NL1 (Thiết bị/Phần mềm): Sử dụng tivi, máy chiếu, bảng tương tác, phần mềm cơ bản.
  + NL2 (Giao tiếp): Thảo luận qua Padlet, Zalo, gửi file bài tập trực tuyến.
  + NL3 (Giải quyết vấn đề): Sử dụng Geogebra, máy tính bỏ túi Casio, Scratch.
  + NL4 (Ứng xử): Giáo dục về bản quyền, bảo mật thông tin khi làm việc nhóm mạng.
  + NL5 (Tự học): HS tự tra cứu thông tin trên Internet, xem video bài giảng.

HÌNH VẼ SVG:
- Nếu bài học có hình vẽ (Hình vuông, tam giác, đường thẳng...), hãy tạo mã SVG 400x300.
- Các điểm phải có nhãn chữ (A, B, C...).`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `Phân tích và chuyển đổi tài liệu cũ sau sang giáo án 5512 hai cột. Tích hợp năng lực số và chuẩn hóa LaTeX MathType: \n\n${extractedText || 'Sử dụng dữ liệu tệp đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án chi tiết bài: "${input}" (Toán 6 Kết nối tri thức). Cần hoạt động phong phú, sinh động, chuẩn 5512 và tích hợp năng lực số.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.2,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

