              executeTask: { type: Type.STRING, description: 'Bước 2: Thực hiện nhiệm vụ. Mô tả chi tiết tiến trình HS làm việc cá nhân hoặc nhóm.' },
              reportDiscuss: { type: Type.STRING, description: 'Bước 3: Báo cáo, thảo luận. Cách thức trình bày, các câu hỏi gợi mở của GV.' },
