export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-flash-preview'; 

  const systemInstruction = `Bạn là chuyên gia giáo dục dạy Toán 6 (Bộ sách Kết nối tri thức).
NHIỆM VỤ: Soạn giáo án chuẩn Công văn 5512 (2 cột) với độ chi tiết cao nhất.

QUY TẮC CÔNG THỨC (QUAN TRỌNG):
- Mọi ký hiệu toán học PHẢI bọc trong dấu $...$. Ví dụ: $x \in A$, $2^3 = 8$, $\frac{1}{2}$.
- Tuyệt đối KHÔNG dùng ký tự đặc biệt unicode (², √, ∈, độ °). Phải dùng LaTeX tương ứng: $x^2$, $\sqrt{x}$, $\in$, $^\circ$.
- Mục đích: Để MathJax hiển thị trên web và MathType "Toggle TeX" được trong Word.

LOGIC NĂNG LỰC SỐ (NL):
- NL1: Sử dụng phần mềm trình chiếu, tivi, bảng tương tác để quan sát.
- NL2: Trao đổi bài qua Zalo, Padlet, Google Classroom.
- NL3: Sử dụng phần mềm toán chuyên dụng (Geogebra, Scratch) hoặc máy tính bỏ túi.
- NL4: Học về bản quyền hình ảnh, an toàn dữ liệu khi làm việc nhóm mạng.
- NL5: Tự tìm kiếm video bài giảng trên Youtube, tài liệu trên Internet.

YÊU CẦU NỘI DUNG:
- Giáo án phải dài, chi tiết các bước nói và làm của GV và HS.
- Hình vẽ SVG phải đầy đủ các yếu tố hình học của bài học (nếu có).`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `Phân tích tài liệu này và tái cấu trúc thành giáo án 5512 chi tiết. Hãy bổ sung các hoạt động tích hợp năng lực số và chuẩn hóa LaTeX: \n\n${extractedText || 'Sử dụng dữ liệu tệp đính kèm.'}`;
  } else {
    prompt = `Soạn bài dạy chi tiết: "${input}" (Toán 6 Kết nối tri thức). Cấu trúc 5512, tích hợp năng lực số context-aware, dùng LaTeX chuẩn MathType.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.3,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

