export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-flash-preview'; 

  const systemInstruction = `Bạn là chuyên gia soạn giáo án Toán 6 Kết nối tri thức. 
NHIỆM VỤ: Soạn giáo án chuẩn 5512 chi tiết, lồng ghép Năng lực số (NL) một cách tự nhiên và chính xác.

QUY TẮC CÔNG THỨC & MATHTYPE:
1. BẮT BUỘC bọc mọi ký hiệu toán học trong dấu $...$. Ví dụ: $x \in A$, $a^2 + b^2 = c^2$, $\frac{1}{2}$.
2. KHÔNG sử dụng ký tự đặc biệt unicode (², √, ∈, độ °). Phải dùng LaTeX: $x^2$, $\sqrt{x}$, $\in$, $^\circ$.
3. Đây là yêu cầu bắt buộc để MathJax hiển thị trên web và giáo viên có thể dùng "Toggle TeX" của MathType trong Word.

QUY TẮC NĂNG LỰC SỐ (NL):
- NL1: Khi GV/HS dùng thiết bị (Tivi, máy chiếu) hoặc phần mềm trình chiếu đơn thuần.
- NL2: Khi có sự tương tác, chia sẻ dữ liệu qua mạng (Zalo, Classroom, Padlet).
- NL3: Khi HS dùng công cụ số để tính toán/vẽ hình chuyên sâu (Casio, Geogebra, Scratch).
- NL4: Khi nhắc nhở về an toàn thông tin, bản quyền học liệu số.
- NL5: Khi yêu cầu HS tự tìm kiếm, khai thác học liệu trên Internet.

YÊU CẦU HÌNH HỌC:
- Mọi bài học về hình học (Chương 4, 8) phải có mã SVG vẽ hình minh họa rõ ràng, có ghi chú tên các đỉnh (A, B, C...).`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `Phân tích giáo án/tài liệu này và soạn lại thành giáo án 5512 chi tiết. Hãy chú trọng lồng ghép Năng lực số vào các bước thực hiện và chuẩn hóa LaTeX: \n\n${extractedText || 'Sử dụng dữ liệu tệp đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án chi tiết bài: "${input}" (Toán 6 Kết nối tri thức). Cần các hoạt động lôi cuốn, đúng chuẩn 5512 (2 cột), tích hợp NL số và LaTeX chuẩn MathType.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.3,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi dữ liệu.");
  return JSON.parse(text) as LessonPlan;
};

