export interface DigitalCompetency {
  code: string;
  name: string;
  description: string;
}

export interface ActivityExecution {
  assignTask: string; // Chuyển giao nhiệm vụ
  executeTask: string; // Thực hiện nhiệm vụ
  reportDiscuss: string; // Báo cáo, thảo luận
  concludeAssess: string; // Kết luận, nhận định
}

export interface Activity {
  id: string;
  title: string;
  objectives: string; // Mục tiêu riêng của hoạt động
  content: string; // Nội dung/Nhiệm vụ học tập
  product: string; // Sản phẩm học tập
  execution: ActivityExecution; // Tổ chức thực hiện
  digitalCompetency: string;
  svgDiagram?: string;
}

export interface LessonPlan {
  topic: string;
  grade: string;
  bookSeries: string;
  objectives: string; // Mục tiêu chung của bài (Kiến thức, Năng lực, Phẩm chất)
  preparations: string; // Thiết bị dạy học và học liệu
  activities: Activity[];
}

export interface LayoutConfig {
  col1Width: number; // Phần trăm chiều rộng cột 1 (30-70)
  competencyPlacement: 'col1-bottom' | 'col2-bottom' | 'separate-row';
}

