  const [layoutConfig, setLayoutConfig] = useState<LayoutConfig>({
    col1Width: 45,
    competencyPlacement: 'col2-bottom'
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    let interval: any;
    if (isProcessing) {
      interval = setInterval(() => {
        setLoadingMsgIdx(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 2500);
    }
    return () => clearInterval(interval);
  }, [isProcessing]);

  const handleDownloadWord = async () => {
    if (!generatedPlan) return;
    setIsProcessing(true);

    const col1W = layoutConfig.col1Width;
    const col2W = 100 - col1W;

    const renderDigitalCompetency = (comp: string) => `
      <div class="nl-box"><b>Tích hợp Năng lực số:</b> ${comp}</div>
    `;

    const htmlContent = `
      <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
      <head>
        <meta charset='utf-8'>
        <style>
          @page { size: A4; margin: 1.5cm 1.5cm 1.5cm 2cm; }
          body { font-family: 'Times New Roman', serif; font-size: 11pt; line-height: 1.4; color: #000; }
          .center { text-align: center; }
          .bold { font-weight: bold; }
          .uppercase { text-transform: uppercase; }
          table { width: 100%; border-collapse: collapse; margin-top: 12pt; table-layout: fixed; }
          th, td { border: 0.5pt solid black; padding: 8pt; vertical-align: top; text-align: justify; word-wrap: break-word; }
          .step-title { font-weight: bold; font-style: italic; color: #000; margin-top: 6pt; display: block; }
