          .svg-container { text-align: center; margin: 10pt 0; }
        </style>
      </head>
      <body>
        <div class="center">
          <p class="bold uppercase" style="font-size: 13pt;">KẾ HOẠCH BÀI DẠY (GIÁO ÁN)</p>
          <p class="bold uppercase" style="font-size: 15pt;">BÀI: ${generatedPlan.topic}</p>
          <p>Môn: Toán 6 • Bộ sách: Kết nối tri thức • Mẫu 5512</p>
          <p style="font-size: 9pt; color: #555;">(Lưu ý: Để hiện công thức, bôi đen văn bản và nhấn <b>Toggle TeX</b> của MathType)</p>
        </div>

        <p class="bold uppercase">I. MỤC TIÊU</p>
        <div style="margin-left: 10pt;">${generatedPlan.objectives.replace(/\n/g, '<br/>')}</div>

        <p class="bold uppercase">II. THIẾT BỊ DẠY HỌC VÀ HỌC LIỆU</p>
        <div style="margin-left: 10pt;">${generatedPlan.preparations.replace(/\n/g, '<br/>')}</div>

        <p class="bold uppercase">III. TIẾN TRÌNH DẠY HỌC</p>
        <table>
          <tr style="background-color: #f2f2f2;">
            <th style="width: ${col1W}%;">1. Hoạt động học (Nhiệm vụ & Sản phẩm)</th>
            <th style="width: ${col2W}%;">2. Tổ chức thực hiện & Năng lực số</th>
          </tr>
          ${generatedPlan.activities.map(act => `
            <tr>
              <td>
                <p class="activity-title">${act.title}</p>
                <p><b>- Mục tiêu:</b> ${act.objectives}</p>
                <p><b>- Nội dung/Nhiệm vụ:</b><br/>${act.content.replace(/\n/g, '<br/>')}</p>
                <p><b>- Sản phẩm học tập:</b><br/>${act.product.replace(/\n/g, '<br/>')}</p>
                ${act.svgDiagram ? `<div class="svg-container"><i>(Hình vẽ minh họa điện tử)</i><br/>${act.svgDiagram}</div>` : ''}
                ${layoutConfig.competencyPlacement === 'col1-bottom' ? renderDigitalCompetency(act.digitalCompetency) : ''}
              </td>
              <td>
                <span class="step-title">* Bước 1: Chuyển giao nhiệm vụ:</span>
                <p>${act.execution.assignTask}</p>
                <span class="step-title">* Bước 2: Thực hiện nhiệm vụ:</span>
                <p>${act.execution.executeTask}</p>
                <span class="step-title">* Bước 3: Báo cáo, thảo luận:</span>
                <p>${act.execution.reportDiscuss}</p>
                <span class="step-title">* Bước 4: Kết luận, nhận định:</span>
                <p>${act.execution.concludeAssess}</p>
                ${layoutConfig.competencyPlacement === 'col2-bottom' ? renderDigitalCompetency(act.digitalCompetency) : ''}
              </td>
            </tr>
            ${layoutConfig.competencyPlacement === 'separate-row' ? `
              <tr>
                <td colspan="2">
                  <div class="nl-box" style="border:none; margin:0; padding:10pt;">
                    <b>Tích hợp Năng lực số:</b> ${act.digitalCompetency}
                  </div>
                </td>
              </tr>
            ` : ''}
          `).join('')}
        </table>

        <br/><br/>
        <table style="border: none; width: 100%;">
          <tr style="border: none;">
            <td style="border: none; text-align: center;"><b>TỔ TRƯỞNG CHUYÊN MÔN</b><br/><i>(Ký và ghi rõ họ tên)</i></td>
            <td style="border: none; text-align: center;"><b>GIÁO VIÊN SOẠN BÀI</b><br/><i>(Ký và ghi rõ họ tên)</i></td>
          </tr>
        </table>
      </body>
      </html>
    `;

    const blob = new Blob(['\ufeff', htmlContent], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `GiaoAn_Toan6_5512_${generatedPlan.topic.replace(/\s+/g, '_')}.doc`;
    link.click();
    setIsProcessing(false);
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    setError(null);

    try {
      let extractedText = "";
      if (file.name.endsWith('.docx')) {
        const arrayBuffer = await file.arrayBuffer();
        const result = await mammoth.extractRawText({ arrayBuffer });
        extractedText = result.value;
      }

      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64Data = (reader.result as string).split(',')[1];
        try {
          const plan = await generateLessonPlan(GenerationMode.TRANSFORM, file.name, { data: base64Data, mimeType: file.type }, extractedText);
          setGeneratedPlan(plan);
        } catch (e) {
          setError("AI gặp lỗi khi xử lý tệp tin. Thầy vui lòng thử lại hoặc soạn bài mới.");
        } finally {
          setIsProcessing(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err) {
      setError("Không thể đọc tệp. Thầy hãy kiểm tra lại định dạng tệp.");
      setIsProcessing(false);
    }
  };

