            <button onClick={() => setActiveTab('competence')}
              className={`w-full flex items-center gap-4 px-6 py-4 rounded-2xl transition-all duration-300 ${activeTab === 'competence' ? 'bg-blue-600 text-white shadow-xl shadow-blue-600/30' : 'hover:bg-white/5 hover:text-white'}`}>
              <List size={20}/>
              <span className="font-bold text-sm">Khung năng lực số</span>
            </button>
          </div>
        </nav>

        <div className="p-8 bg-slate-950/40 border-t border-white/5">
          <div className="p-5 bg-slate-800/40 rounded-3xl border border-white/5 flex items-start gap-4">
            <div className="p-2 bg-blue-500/10 rounded-xl"><Info size={16} className="text-blue-400 shrink-0"/></div>
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1.5 leading-none">Mẹo nhỏ</p>
              <p className="text-[11px] font-medium text-slate-300 leading-relaxed">Sử dụng <b>Toggle TeX</b> trong MathType để biến đổi công thức sau khi mở file Word.</p>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-full overflow-hidden bg-[#fdfdfe] relative">
        <header className="h-20 bg-white/95 backdrop-blur-md border-b flex items-center justify-between px-12 z-20 no-print sticky top-0 shadow-sm">
          <div className="flex items-center gap-5">
            <div className="w-2 h-8 bg-blue-600 rounded-full animate-pulse shadow-lg shadow-blue-600/20"></div>
            <h2 className="font-black text-slate-800 text-[11px] uppercase tracking-[0.25em] flex items-center gap-3">
              Hệ thống soạn giáo án AI 5.0 <Sparkles size={18} className="text-blue-600 animate-bounce" />
            </h2>
          </div>
          {generatedPlan && (
            <div className="flex items-center gap-4">
               <button onClick={handleDownloadWord} disabled={isProcessing} className="bg-slate-900 text-white px-10 py-4 rounded-2xl font-black text-xs flex items-center gap-3 hover:bg-black transition-all shadow-xl shadow-slate-900/10 active:scale-95">
                {isProcessing ? <RefreshCw className="animate-spin" size={18}/> : <Download size={18}/>}
                XUẤT WORD (Chuẩn 5512)
              </button>
            </div>
          )}
        </header>

        {/* Layout Settings Floating Panel */}
        {showLayoutSettings && (
          <div className="absolute top-24 right-12 w-80 bg-white shadow-2xl rounded-3xl p-8 z-40 border border-slate-100 animate-in slide-in-from-right-4">
            <h4 className="font-black text-slate-900 uppercase text-xs tracking-widest mb-6 flex items-center gap-3">
              <Settings2 size={16} className="text-blue-600"/>
              Cài đặt bố cục
            </h4>

            <div className="space-y-8">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-4">Tỷ lệ cột 1: {layoutConfig.col1Width}%</label>
                <input 
                  type="range" min="30" max="70" step="5"
                  value={layoutConfig.col1Width}
                  onChange={(e) => setLayoutConfig({...layoutConfig, col1Width: parseInt(e.target.value)})}
                  className="w-full h-1.5 bg-slate-100 rounded-full appearance-none cursor-pointer accent-blue-600"
                />
                <div className="flex justify-between mt-2 text-[9px] font-bold text-slate-400 uppercase tracking-widest">
                  <span>30%</span>
                  <span>70%</span>
                </div>
              </div>

              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-4 italic">Vị trí Năng lực số</label>
                <div className="grid grid-cols-1 gap-2">
                  <button 
                    onClick={() => setLayoutConfig({...layoutConfig, competencyPlacement: 'col1-bottom'})}
                    className={`flex items-center gap-3 px-4 py-3 rounded-xl border-2 transition-all text-xs font-bold ${layoutConfig.competencyPlacement === 'col1-bottom' ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-50 hover:border-slate-200 text-slate-500'}`}>
                    <AlignLeft size={16}/>
                    Cuối cột 1
                  </button>
                  <button 
                    onClick={() => setLayoutConfig({...layoutConfig, competencyPlacement: 'col2-bottom'})}
                    className={`flex items-center gap-3 px-4 py-3 rounded-xl border-2 transition-all text-xs font-bold ${layoutConfig.competencyPlacement === 'col2-bottom' ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-50 hover:border-slate-200 text-slate-500'}`}>
                    <AlignCenter size={16}/>
                    Cuối cột 2
                  </button>
                  <button 
                    onClick={() => setLayoutConfig({...layoutConfig, competencyPlacement: 'separate-row'})}
                    className={`flex items-center gap-3 px-4 py-3 rounded-xl border-2 transition-all text-xs font-bold ${layoutConfig.competencyPlacement === 'separate-row' ? 'border-blue-600 bg-blue-50 text-blue-700' : 'border-slate-50 hover:border-slate-200 text-slate-500'}`}>
                    <AlignJustify size={16}/>
                    Hàng riêng biệt
                  </button>
                </div>
              </div>

              <button 
                onClick={() => setShowLayoutSettings(false)}
                className="w-full py-3 bg-slate-900 text-white rounded-xl font-black text-[10px] uppercase tracking-[0.2em] shadow-lg shadow-slate-900/10">
                Đóng cài đặt
              </button>
            </div>
          </div>
        )}

        <div className="flex-1 overflow-auto p-12 bg-[radial-gradient(#e5e7eb_1px,transparent_1px)] [background-size:40px_40px]">
          {error && <div className="max-w-4xl mx-auto bg-red-50 text-red-600 p-8 rounded-[2.5rem] mb-12 border border-red-100 font-bold text-sm flex gap-6 animate-in slide-in-from-top-4 shadow-xl shadow-red-100/30"><FileWarning size={24}/> {error}</div>}

          {/* Upload Area */}
          {activeTab === 'upload' && !generatedPlan && (
            <div className="max-w-4xl mx-auto mt-20 text-center">
              <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept=".pdf,.docx,image/*" />
              {!isProcessing ? (
                <div onClick={() => fileInputRef.current?.click()} className="bg-white border-4 border-dashed border-slate-200 p-36 rounded-[5rem] cursor-pointer hover:border-blue-500 hover:bg-blue-50/50 transition-all group shadow-2xl shadow-slate-200/20 relative overflow-hidden">
                  <div className="absolute -top-10 -right-10 w-64 h-64 bg-blue-600/5 rounded-full blur-3xl group-hover:bg-blue-600/10 transition-colors"></div>
                  <Upload size={96} className="mx-auto text-slate-200 group-hover:text-blue-600 mb-10 transition-all group-hover:-translate-y-4" />
                  <h3 className="text-5xl font-black text-slate-900 mb-6 tracking-tighter uppercase italic">Phân tích giáo án cũ</h3>
                  <p className="text-slate-500 font-bold max-w-lg mx-auto leading-relaxed text-sm uppercase tracking-[0.2em] opacity-50 italic">Kéo thả tệp Word/PDF để AI cấu trúc lại chuẩn 5512 và lồng ghép Năng lực số.</p>
                </div>
              ) : (
                <div className="p-36 bg-white rounded-[5rem] shadow-2xl text-center max-w-2xl mx-auto border-2 border-blue-50 relative overflow-hidden">
                  <RefreshCw className="animate-spin mx-auto text-blue-600/20 mb-12" size={120} />
                  <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <h3 className="text-4xl font-black mb-4 tracking-tighter text-slate-900 uppercase">AI Đang Làm Việc...</h3>
                    <div className="h-2 w-56 bg-slate-100 rounded-full mx-auto mb-10 overflow-hidden shadow-inner">
                      <div className="h-full bg-blue-600 animate-[loading_2s_infinite]"></div>
                    </div>
                    <p className="text-blue-600 font-black uppercase tracking-[0.3em] text-[12px] animate-pulse px-10">
                      {LOADING_MESSAGES[loadingMsgIdx]}
                    </p>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* Create New Area */}
          {activeTab === 'create' && !generatedPlan && (
            <div className="max-w-4xl mx-auto mt-20 bg-white/95 backdrop-blur-xl p-24 rounded-[5rem] shadow-2xl border border-white relative overflow-hidden">
              <div className="absolute -bottom-10 -left-10 w-80 h-80 bg-blue-600/5 rounded-full blur-3xl"></div>
              <h3 className="text-4xl font-black text-slate-900 mb-16 flex items-center gap-6 tracking-tighter uppercase italic">
                <div className="w-2.5 h-12 bg-blue-600 rounded-full shadow-lg shadow-blue-600/50"></div>
                Soạn bài dạy mới SGK
              </h3>
              <div className="space-y-12">
                <div className="relative">
                  <label className="block text-[11px] font-black text-slate-400 uppercase tracking-widest mb-4 ml-8 italic">Chọn bài học từ sách Kết nối tri thức</label>
                  <select onChange={(e) => setSelectedLessonId(e.target.value)} className="w-full p-10 bg-slate-50/80 rounded-[3rem] border-2 border-slate-100 font-bold text-slate-800 outline-none focus:border-blue-500 focus:bg-white transition-all appearance-none cursor-pointer shadow-sm text-lg">
                    <option value="">-- Click để chọn bài học --</option>
                    {DATABASE.map(c => (<optgroup key={c.chapter} label={c.chapter}>{c.lessons.map(l => <option key={l.id} value={l.id}>{l.name}</option>)}</optgroup>))}
                  </select>
                  <div className="absolute right-10 top-[4.5rem] pointer-events-none text-slate-300">
                    <ChevronRight size={24} className="rotate-90"/>
                  </div>
                </div>
                <button disabled={!selectedLessonId || isProcessing} onClick={async () => {
                  const lesson = DATABASE.flatMap(d => d.lessons).find(l => l.id === selectedLessonId);
                  if (!lesson) return; setIsProcessing(true);
                  try { const plan = await generateLessonPlan(GenerationMode.NEW, lesson.name); setGeneratedPlan(plan); } catch (e) { setError("AI gặp lỗi khi soạn thảo. Thầy hãy thử lại."); } finally { setIsProcessing(false); }
                }} className="w-full py-10 bg-gradient-to-r from-blue-600 to-indigo-700 text-white rounded-[3rem] font-black text-2xl hover:shadow-[0_20px_50px_rgba(37,99,235,0.4)] hover:-translate-y-1.5 transition-all active:scale-95 flex items-center justify-center gap-5">
                  {isProcessing ? <RefreshCw className="animate-spin" /> : <Layers size={28}/>}
                  {isProcessing ? 'AI ĐANG THIẾT KẾ...' : 'BẮT ĐẦU SOẠN GIÁO ÁN'}
                </button>
              </div>
            </div>
          )}

          {/* View Generated Plan */}
          {generatedPlan && (
            <div className="max-w-7xl mx-auto bg-white rounded-[4.5rem] shadow-2xl border border-white overflow-hidden mb-40 animate-in zoom-in-95 duration-700 no-print">
              <div className="bg-slate-900 p-20 text-white relative">
                <div className="absolute top-0 right-0 p-20 opacity-[0.03] scale-[2.5] pointer-events-none rotate-12"><Calculator size={200} /></div>
                <div className="flex flex-wrap gap-4 mb-8">
                   <span className="bg-blue-600/20 text-blue-400 border border-blue-500/30 px-6 py-2 rounded-full text-[10px] font-black tracking-[0.2em] uppercase italic">Toán 6 - Kết nối tri thức</span>
                   <span className="bg-white/5 text-slate-400 border border-white/10 px-6 py-2 rounded-full text-[10px] font-black tracking-[0.2em] uppercase italic">Chuẩn Công văn 5512</span>
                   <span className="bg-emerald-500/20 text-emerald-400 border border-emerald-500/30 px-6 py-2 rounded-full text-[10px] font-black tracking-[0.2em] uppercase flex items-center gap-2">
                     <FileCheck size={14}/> Sẵn sàng cho MathType
                   </span>
                </div>
                <h1 className="text-6xl font-black tracking-tighter uppercase leading-[1.1] max-w-5xl italic">{generatedPlan.topic}</h1>
              </div>

              <div className="p-20 space-y-28">
                {/* Section I: Objectives */}
                <section>
                  <div className="flex justify-between items-center mb-10">
                    <h3 className="font-black text-3xl text-slate-900 uppercase tracking-tighter flex items-center gap-6 italic">
                      <div className="w-12 h-12 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 font-black text-xl italic shadow-sm">I</div>
                      Mục tiêu bài giảng
                    </h3>
                  </div>
                  <div className="bg-slate-50/50 p-16 rounded-[4rem] text-sm whitespace-pre-wrap leading-loose shadow-inner border border-slate-100/50 text-slate-600 italic">
                    {generatedPlan.objectives}
                  </div>
                </section>

                {/* Section II: Activities (2 Columns) */}
                <section>
                  <h3 className="font-black text-3xl text-slate-900 uppercase tracking-tighter mb-12 flex items-center gap-6 italic">
                    <div className="w-12 h-12 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 font-black text-xl italic shadow-sm">II</div>
                    Tiến trình dạy học & Năng lực số
                  </h3>
                  <div className="space-y-24">
                    {generatedPlan.activities.map((act, i) => (
                      <div key={i} className="group border-2 border-slate-50 rounded-[4.5rem] overflow-hidden hover:border-blue-200 transition-all duration-500 hover:shadow-[0_40px_80px_-20px_rgba(0,0,0,0.06)]">
                        <div className="bg-slate-950 px-16 py-8 text-white font-black text-[12px] uppercase tracking-[0.3em] flex justify-between items-center group-hover:bg-blue-900 transition-colors">
                          <span className="flex items-center gap-6 italic"><ChevronRight size={20} className="text-blue-500 group-hover:translate-x-1 transition-transform"/> {act.title}</span>
                          <span className="text-[10px] opacity-40 font-bold uppercase tracking-widest italic">Hoạt động {i+1}</span>
                        </div>

                        <div className="flex flex-col bg-white">
                          <div className="flex flex-col lg:flex-row divide-y lg:divide-y-0 lg:divide-x divide-slate-100">
                            {/* Column 1: Content/Product */}
                            <div className="p-16" style={{ width: `${layoutConfig.col1Width}%` }}>
                              <div className="flex items-center gap-4 mb-12">
                                <BookOpen size={22} className="text-blue-600"/>
                                <h4 className="font-black text-[12px] text-slate-400 uppercase tracking-[0.25em] italic">Nhiệm vụ & Sản phẩm</h4>
                              </div>
                              <div className="space-y-12">
                                <div className="p-10 bg-slate-50 rounded-[3rem] border border-slate-100 relative group/box">
                                  <p className="absolute -top-4 left-10 bg-blue-600 text-white px-6 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest shadow-xl shadow-blue-600/20 group-hover/box:-translate-y-1 transition-all italic">Nhiệm vụ học tập</p>
                                  <MathRenderer content={act.content}/>
                                </div>
                                <div className="p-10 bg-emerald-50/20 rounded-[3rem] border border-emerald-100/50 relative group/box">
                                  <p className="absolute -top-4 left-10 bg-emerald-600 text-white px-6 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest shadow-xl shadow-emerald-600/20 group-hover/box:-translate-y-1 transition-all italic">Sản phẩm yêu cầu</p>
                                  <MathRenderer content={act.product}/>
                                </div>
                                {act.svgDiagram && (
                                  <div className="mt-14 p-12 bg-white border border-slate-100 rounded-[4rem] shadow-sm flex flex-col items-center hover:shadow-2xl transition-all">
                                    <div dangerouslySetInnerHTML={{__html: act.svgDiagram}} className="max-w-full" />
                                    <p className="text-[10px] text-slate-400 mt-10 font-black italic tracking-[0.4em] uppercase">Hình vẽ minh họa điện tử</p>
                                  </div>
                                )}

                                {layoutConfig.competencyPlacement === 'col1-bottom' && (
                                  <div className="mt-16 p-8 bg-white rounded-[2.5rem] border-2 border-blue-50 flex gap-6 items-center shadow-lg shadow-blue-500/5 transition-transform group-hover:scale-[1.02]">
                                    <div className="w-16 h-16 bg-gradient-to-br from-blue-600 to-indigo-800 rounded-2xl flex-shrink-0 flex items-center justify-center text-white shadow-xl shadow-blue-500/30 transition-all"><Cpu size={28}/></div>
                                    <div className="space-y-1">
                                      <p className="font-black uppercase tracking-[0.4em] text-[8px] text-slate-400 italic">NL số tích hợp</p>
                                      <p className="font-bold text-slate-900 text-sm leading-snug">{act.digitalCompetency}</p>
                                    </div>
                                  </div>
                                )}
                              </div>
                            </div>

                            {/* Column 2: Execution */}
                            <div className="p-16 bg-slate-50/30" style={{ width: `${100 - layoutConfig.col1Width}%` }}>
                              <div className="flex items-center gap-4 mb-12">
                                <RefreshCw size={22} className="text-blue-600"/>
                                <h4 className="font-black text-[12px] text-slate-400 uppercase tracking-[0.25em] italic">Tổ chức thực hiện</h4>
                              </div>
                              <div className="space-y-10 text-[15px] leading-relaxed text-slate-700">
                                <div className="pl-8 border-l-4 border-blue-600/30 py-1 transition-all group-hover:border-blue-600 group-hover:pl-10">
                                  <p><b className="text-blue-800 font-black uppercase text-[11px] tracking-widest block mb-2 italic">Bước 1: Chuyển giao</b> {act.execution.assignTask}</p>
                                </div>
                                <div className="pl-8 border-l-4 border-indigo-600/30 py-1 transition-all group-hover:border-indigo-600 group-hover:pl-10">
                                  <p><b className="text-indigo-800 font-black uppercase text-[11px] tracking-widest block mb-2 italic">Bước 2: Thực hiện</b> {act.execution.executeTask}</p>
                                </div>
                                <div className="pl-8 border-l-4 border-violet-600/30 py-1 transition-all group-hover:border-violet-600 group-hover:pl-10">
                                  <p><b className="text-violet-800 font-black uppercase text-[11px] tracking-widest block mb-2 italic">Bước 3: Báo cáo</b> {act.execution.reportDiscuss}</p>
                                </div>
                                <div className="pl-8 border-l-4 border-emerald-600/30 py-1 transition-all group-hover:border-emerald-600 group-hover:pl-10">
                                  <p><b className="text-emerald-800 font-black uppercase text-[11px] tracking-widest block mb-2 italic">Bước 4: Kết luận</b> {act.execution.concludeAssess}</p>
                                </div>

                                {layoutConfig.competencyPlacement === 'col2-bottom' && (
                                  <div className="mt-16 p-10 bg-white rounded-[3.5rem] border-2 border-blue-50 flex gap-10 items-center shadow-xl shadow-blue-500/5 group/nl hover:-translate-y-2 transition-transform">
                                    <div className="w-24 h-24 bg-gradient-to-br from-blue-600 to-indigo-800 rounded-[2rem] flex-shrink-0 flex items-center justify-center text-white shadow-2xl shadow-blue-500/30 group-hover/nl:rotate-6 transition-all"><Cpu size={44}/></div>
                                    <div className="space-y-2">
                                      <p className="font-black uppercase tracking-[0.4em] text-[10px] text-slate-400 italic">Năng lực số lồng ghép</p>
                                      <p className="font-bold text-slate-900 text-xl leading-snug">{act.digitalCompetency}</p>
                                    </div>
                                  </div>
                                )}
                              </div>
                            </div>
                          </div>

                          {/* Optional Separate Row for Digital Competency */}
                          {layoutConfig.competencyPlacement === 'separate-row' && (
                            <div className="px-16 pb-16 bg-slate-50/50">
                              <div className="p-10 bg-white rounded-[3.5rem] border-2 border-indigo-50 flex gap-10 items-center shadow-xl shadow-indigo-500/5 transition-transform hover:scale-[1.01]">
                                <div className="w-20 h-20 bg-gradient-to-br from-indigo-600 to-blue-800 rounded-[2.25rem] flex-shrink-0 flex items-center justify-center text-white shadow-2xl shadow-indigo-500/30"><Cpu size={36}/></div>
                                <div className="space-y-2">
                                  <p className="font-black uppercase tracking-[0.4em] text-[10px] text-slate-400 italic">Năng lực số (Hàng riêng biệt)</p>
                                  <p className="font-bold text-slate-900 text-xl leading-snug">{act.digitalCompetency}</p>
                                </div>
                              </div>
                            </div>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                </section>
              </div>
            </div>
          )}

          {/* Competence Map Area */}
          {activeTab === 'competence' && (
            <div className="max-w-6xl mx-auto space-y-12 pb-40 no-print animate-in fade-in slide-in-from-bottom-10">
              <div className="text-center mb-24">
                <h3 className="text-7xl font-black mb-8 tracking-tighter text-slate-900 uppercase italic">Năng lực số 5512</h3>
                <div className="w-32 h-1.5 bg-blue-600 mx-auto rounded-full mb-8"></div>
                <p className="text-slate-500 font-bold uppercase text-[13px] tracking-[0.6em] opacity-50 italic">Hệ thống hỗ trợ tích hợp bài dạy số hóa</p>
              </div>
              {DIGITAL_COMPETENCIES.map((c, idx) => (
                <div key={c.code} className="bg-white p-14 rounded-[4.5rem] border-2 border-white shadow-2xl flex gap-14 items-start hover:border-blue-500 transition-all hover:translate-x-5 group animate-in slide-in-from-left-8" style={{animationDelay: `${idx * 150}ms`}}>
                  <div className="bg-slate-950 text-white w-28 h-28 flex-shrink-0 flex items-center justify-center rounded-[3rem] font-black text-4xl shadow-2xl group-hover:bg-blue-600 transition-all group-hover:rotate-12 italic">{c.code}</div>
                  <div>
                    <h4 className="font-black text-4xl text-slate-900 mb-6 group-hover:text-blue-600 transition-colors leading-none tracking-tight italic uppercase">{c.name}</h4>
                    <p className="text-slate-500 text-2xl font-medium leading-relaxed opacity-70 italic">{c.description}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>
      <style>{`
        @keyframes loading {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(600%); }
        }
      `}</style>
    </div>
  );
}

export interface DigitalCompetency {
  code: string;
  name: string;
  description: string;
}

export interface ActivityExecution {
  assignTask: string; // Bước 1: Chuyển giao nhiệm vụ
  executeTask: string; // Bước 2: Thực hiện nhiệm vụ
  reportDiscuss: string; // Bước 3: Báo cáo, thảo luận
  concludeAssess: string; // Bước 4: Kết luận, nhận định
}

export interface Activity {
  id: string;
  title: string;
  objectives: string; 
  content: string; // Nội dung/Nhiệm vụ học tập (Cột 1)
  product: string; // Sản phẩm học tập (Cột 1)
  execution: ActivityExecution; // Tổ chức thực hiện (Cột 2)
  digitalCompetency: string; // Năng lực số tích hợp (Cột 2)
  svgDiagram?: string; // Hình vẽ SVG
}

export interface LessonPlan {
  topic: string;
  grade: string;
  bookSeries: string;
  objectives: string; 
  preparations: string; 
  activities: Activity[];
}

export enum GenerationMode {
  NEW = 'NEW',
  TRANSFORM = 'TRANSFORM',
  TEXTBOOK = 'TEXTBOOK'
}

import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
