export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview'; 

  const systemInstruction = `Bạn là chuyên gia giáo dục dạy Toán 6 (Bộ sách Kết nối tri thức).
NHIỆM VỤ: Soạn giáo án chuẩn Công văn 5512 với cấu trúc 2 cột nghiêm ngặt.

QUY TẮC NỘI DUNG:
1. NẾU LÀ TRANSFORM (Chuyển đổi): Giữ nguyên 100% nội dung kiến thức, ví dụ, số liệu, tên nhân vật từ tài liệu gốc. Chỉ tổ chức lại vào bảng 2 cột và thêm năng lực số.
2. NẾU LÀ SOẠN MỚI: Sát nội dung SGK Kết nối tri thức, chi tiết từng câu lệnh của giáo viên.
3. TOÁN HỌC: Bắt buộc dùng LaTeX trong dấu $...$. Không dùng ký tự unicode (², √, ∈, độ °). Phải dùng $x^2$, $\\sqrt{x}$, $\\in$, $^\\circ$.
4. HÌNH HỌC: Tạo mã SVG cho các hình phẳng (Tam giác, vuông, thoi...) hoặc đồ thị.

QUY TẮC NĂNG LỰC SỐ (NL) CHI TIẾT:
- NL1 (Khai thác thiết bị/phần mềm): "Sử dụng [Tên thiết bị] để [Hành động]. VD: Sử dụng tivi và PowerPoint trình chiếu video mô phỏng tập hợp."
- NL2 (Giao tiếp/Hợp tác số): "Thảo luận nhóm qua [Nền tảng]. VD: Học sinh gửi kết quả thảo luận lên Padlet để cả lớp cùng quan sát và phản biện."
- NL3 (Giải quyết vấn đề): "Sử dụng [Công cụ vẽ/tính]. VD: Sử dụng Geogebra để dựng hình thoi, kiểm tra tính chất đường chéo bằng thước đo ảo."
- NL4 (Ứng xử số): "VD: Nhắc nhở HS về bản quyền khi khai thác hình ảnh từ Internet cho bài báo cáo."
- NL5 (Tự học số): "VD: HS tự quét mã QR trong SGK để xem video hướng dẫn thực hành vẽ hình."

BỐ CỤC 2 CỘT (CÔNG VĂN 5512):
- Cột 1: Nội dung và Nhiệm vụ học tập (Content + Product).
- Cột 2: Tổ chức thực hiện & Năng lực số (4 bước + NL số).`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `GIỮ NGUYÊN NỘI DUNG GỐC. Chuyển đổi tài liệu sau sang giáo án 5512 hai cột, tích hợp năng lực số chi tiết và chuẩn hóa LaTeX: \n\n${extractedText || 'Dữ liệu từ tệp đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án chi tiết bài: "${input}" (Toán 6 Kết nối tri thức). Tuân thủ 5512, 2 cột, lồng ghép NL số sâu sắc, SVG sắc nét.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.1, // Giữ độ chính xác cao
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

