import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING, description: 'Mục tiêu: 1. Kiến thức; 2. Năng lực (Toán học & Chung); 3. Phẩm chất.' },
    preparations: { type: Type.STRING, description: 'Thiết bị dạy học và học liệu (GV và HS).' },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING, description: 'Tên hoạt động (vd: Hoạt động 2: Hình thành kiến thức về Phân số)' },
          objectives: { type: Type.STRING, description: 'Mục tiêu cụ thể của hoạt động.' },
          content: { type: Type.STRING, description: 'CỘT 1: Nhiệm vụ học tập. BẮT BUỘC dùng LaTeX trong $...$.' },
          product: { type: Type.STRING, description: 'CỘT 1: Sản phẩm học tập. BẮT BUỘC dùng LaTeX trong $...$.' },
          execution: {
            type: Type.OBJECT,
            properties: {
              assignTask: { type: Type.STRING, description: 'Bước 1: Chuyển giao nhiệm vụ.' },
              executeTask: { type: Type.STRING, description: 'Bước 2: Thực hiện nhiệm vụ.' },
              reportDiscuss: { type: Type.STRING, description: 'Bước 3: Báo cáo, thảo luận.' },
              concludeAssess: { type: Type.STRING, description: 'Bước 4: Kết luận, nhận định.' }
            },
            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { type: Type.STRING, description: 'CỘT 2: Gợi ý Năng lực số CHI TIẾT. Nêu rõ: Tên thiết bị/phần mềm + Hành động cụ thể của GV/HS + Mục đích giáo dục.' },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG vẽ hình hình học hoặc đồ thị minh họa bài học.' }
        },
        required: ['id', 'title', 'objectives', 'content', 'product', 'execution', 'digitalCompetency']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview'; 

  const systemInstruction = `Bạn là chuyên gia soạn giáo án Toán 6 (Bộ sách Kết nối tri thức).
NHIỆM VỤ: Soạn giáo án chuẩn Công văn 5512 với cấu trúc 2 cột cố định.

YÊU CẦU NỘI DUNG (BẮT BUỘC):
1. GIỮ NGUYÊN NỘI DUNG GỐC: Nếu người dùng tải file lên, bạn phải giữ đúng 100% các bài tập, số liệu, tên gọi, ví dụ trong file đó. Chỉ tổ chức lại vào bảng 2 cột và làm đẹp bằng LaTeX/SVG.
2. SÁT SGK: Nếu soạn mới, nội dung phải bám sát chương trình Kết nối tri thức.
3. CÔNG THỨC TOÁN: Mọi biểu thức, con số toán học (kể cả số đơn lẻ như $2$, $x$) phải bọc trong dấu $...$ để dùng với MathType. KHÔNG DÙNG KÝ TỰ UNICODE (² , √, ∈...).
4. HÌNH HỌC/ĐỒ THỊ: Vẽ bằng mã SVG (stroke="black", fill="none", stroke-width="2").

HƯỚNG DẪN CHI TIẾT NĂNG LỰC SỐ (CỘT 2):
Phần gợi ý Năng lực số phải cực kỳ chi tiết, không ghi chung chung:
- NL1 (Thiết bị): Nêu rõ việc sử dụng máy chiếu vật thể để soi bài làm HS, hoặc dùng TV tương tác để trình chiếu video học liệu số.
- NL2 (Giao tiếp số): Sử dụng Padlet/Zalo để HS nộp bài nhanh, GV nhận xét trực tiếp trên màn hình lớp.
- NL3 (Công cụ số): Sử dụng phần mềm Geogebra để đo góc, vẽ hình thoi chính xác; sử dụng máy tính Casio fx-580VNX để kiểm tra kết quả lũy thừa.
- NL4 (Ứng xử số): Giáo dục HS về việc trích dẫn nguồn khi lấy ảnh minh họa trên Internet.
- NL5 (Tự học số): Hướng dẫn HS quét mã QR trong sách để xem clip bài giảng bổ trợ.

BỐ CỤC 2 CỘT 5512:
- Cột 1: Hoạt động học (Nhiệm vụ & Sản phẩm).
- Cột 2: Tổ chức thực hiện & Năng lực số (4 bước thực hiện + Gợi ý tích hợp số).`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `GIỮ NGUYÊN TOÀN BỘ NỘI DUNG VÀ VÍ DỤ TRONG FILE SAU. Chuyển đổi nó thành giáo án 5512 hai cột chuyên nghiệp, dùng LaTeX và SVG cho hình vẽ: \n\n${extractedText || 'Dữ liệu tệp đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án chi tiết bài: "${input}" (Toán 6 Kết nối tri thức). Chi tiết từng bước, tích hợp năng lực số sâu sắc, công thức $LaTeX$ và hình vẽ SVG.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.1,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

