import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING, description: 'Mục tiêu: 1. Kiến thức; 2. Năng lực (Toán học & Chung); 3. Phẩm chất.' },
    preparations: { type: Type.STRING, description: 'Thiết bị dạy học và học liệu (GV và HS).' },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING, description: 'Tên hoạt động (vd: Hoạt động 2: Hình thành kiến thức)' },
          objectives: { type: Type.STRING, description: 'Mục tiêu cụ thể của hoạt động.' },
          teacherActivities: { type: Type.STRING, description: 'CỘT 1: Hoạt động dạy học của Giáo viên (Theo tiến trình SGK).' },
          studentResults: { type: Type.STRING, description: 'CỘT 2: Kết quả hoạt động của Học sinh (Sản phẩm học tập).' },
          executionSteps: {
            type: Type.OBJECT,
            properties: {
              assignTask: { type: Type.STRING, description: 'Bước 1: Chuyển giao nhiệm vụ.' },
              executeTask: { type: Type.STRING, description: 'Bước 2: Thực hiện nhiệm vụ.' },
              reportDiscuss: { type: Type.STRING, description: 'Bước 3: Báo cáo, thảo luận.' },
              concludeAssess: { type: Type.STRING, description: 'Bước 4: Kết luận, nhận định.' }
            },
            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { type: Type.STRING, description: 'CỘT 2 (TÍCH HỢP): Mô tả cụ thể hành vi tích hợp năng lực số của GV/HS (Sử dụng thiết bị, phần mềm gì, nhằm mục đích gì).' },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG vẽ hình minh họa nếu cần.' }
        },
        required: ['id', 'title', 'objectives', 'teacherActivities', 'studentResults', 'executionSteps', 'digitalCompetency']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview'; 

  const systemInstruction = `Bạn là chuyên gia soạn giáo án Toán 6 (Bộ sách Kết nối tri thức).
NHIỆM VỤ: Soạn giáo án chuẩn Công văn 5512 với cấu trúc 2 cột.

YÊU CẦU QUAN TRỌNG:
1. GIỮ NGUYÊN NỘI DUNG GỐC: Khi được tải file lên, bạn phải giữ lại 100% nội dung chữ, số liệu, bài tập và ví dụ từ file đó. Nếu có hình ảnh trong nội dung gốc, hãy mô tả vị trí đặt hình bằng dòng chữ "[HÌNH ẢNH GỐC TỪ FILE]".
2. BỐ CỤC 2 CỘT (CÔNG VĂN 5512):
   - Cột 1: Hoạt động dạy học (Tiến trình của Giáo viên).
   - Cột 2: Kết quả hoạt động của học sinh (Sản phẩm) TÍCH HỢP Năng lực số chi tiết.
3. CÔNG THỨC TOÁN: Phải sử dụng LaTeX bọc trong dấu $...$.
4. NĂNG LỰC SỐ: Phải mô tả cực kỳ chi tiết (vd: "HS sử dụng tivi và phần mềm Geogebra để quan sát trực quan sự thay đổi của hình...").
5. HÌNH HỌC: Vẽ bằng SVG sắc nét nếu bài học yêu cầu.`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `CHUYỂN ĐỔI GIÁO ÁN SAU SANG CHUẨN 2 CỘT 5512. 
    Lưu ý: Giữ nguyên mọi ví dụ và bài tập. Mô tả vị trí hình ảnh gốc nếu có. 
    Cột 1: Hoạt động dạy học. Cột 2: Kết quả của HS & Năng lực số chi tiết.
    Nội dung: \n\n${extractedText || 'Dữ liệu tệp đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án chi tiết bài: "${input}" (Toán 6 Kết nối tri thức). 
    Bố cục 2 cột. Cột 1: Hoạt động GV. Cột 2: Kết quả HS & Năng lực số. 
    Công thức LaTeX $, hình SVG.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.1,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

