import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING, description: 'Mục tiêu: 1. Kiến thức; 2. Năng lực; 3. Phẩm chất.' },
    preparations: { type: Type.STRING, description: 'Thiết bị dạy học và học liệu.' },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING, description: 'Tên hoạt động (vd: Hoạt động 1: Mở đầu)' },
          objectives: { type: Type.STRING },
          teacherActivities: { type: Type.STRING, description: 'CỘT 1: Nội dung các bước dạy học của Giáo viên theo tiến trình SGK.' },
          studentResults: { type: Type.STRING, description: 'CỘT 2: Kết quả/Sản phẩm học tập của học sinh tương ứng.' },
          executionSteps: {
            type: Type.OBJECT,
            properties: {
              assignTask: { type: Type.STRING },
              executeTask: { type: Type.STRING },
              reportDiscuss: { type: Type.STRING },
              concludeAssess: { type: Type.STRING }
            },
            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { type: Type.STRING, description: 'CỘT 2: Mô tả chi tiết việc tích hợp năng lực số (Sử dụng thiết bị, phần mềm, khai thác học liệu số...).' },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG nếu cần vẽ hình toán học.' }
        },
        required: ['id', 'title', 'objectives', 'teacherActivities', 'studentResults', 'executionSteps', 'digitalCompetency']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedText?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview'; 

  const systemInstruction = `Bạn là chuyên gia soạn giáo án Toán 6 (Bộ sách Kết nối tri thức).
NHIỆM VỤ: Soạn giáo án chuẩn Công văn 5512 với cấu trúc 2 cột nghiêm ngặt.

QUY TẮC CỘT:
- Cột 1 (Hoạt động dạy học): Tiến trình dẫn dắt của Giáo viên.
- Cột 2 (Kết quả HS & NL Số): Sản phẩm của HS, các bước thực hiện và NĂNG LỰC SỐ.

YÊU CẦU ĐẶC BIỆT:
1. GIỮ NGUYÊN HÌNH ẢNH GỐC: Nếu tài liệu gốc có hình ảnh, bạn phải ghi chú rõ ràng vị trí bằng dòng "[HÌNH ẢNH GỐC TẠI ĐÂY]" để GV chèn lại sau khi xuất Word. KHÔNG thay đổi vị trí nội dung xung quanh hình ảnh.
2. NĂNG LỰC SỐ: Phải cực kỳ chi tiết (vd: GV sử dụng phần mềm Geogebra để minh họa trực quan... HS nộp bài qua Padlet...).
3. TOÁN HỌC: Dùng LaTeX trong $...$.
4. TRƯỜNG HỢP SOẠN MỚI: Nội dung phải bám sát SGK Kết nối tri thức.`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `CHUYỂN ĐỔI GIÁO ÁN SAU SANG CHUẨN 2 CỘT 5512. 
    - Giữ nguyên 100% nội dung chữ, số liệu, bài tập.
    - Đánh dấu vị trí hình ảnh gốc bằng [HÌNH ẢNH GỐC TẠI ĐÂY].
    - Cột 1: GV dạy. Cột 2: Kết quả HS và NL Số chi tiết.
    Dữ liệu: \n\n${extractedText || 'Dữ liệu file đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án bài "${input}" (Toán 6 Kết nối tri thức). 2 cột, NL số chi tiết, LaTeX $...$.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.1,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

