                <div class="digital-comp-box">TÍCH HỢP NĂNG LỰC SỐ CHI TIẾT: ${act.digitalCompetency}</div>
              </td>
            </tr>
          `).join('')}
        </table>
        <br/><br/>
        <table style="border: none; width: 100%;">
          <tr style="border: none;">
            <td style="border: none; text-align: center;"><b>TỔ TRƯỞNG CHUYÊN MÔN</b></td>
            <td style="border: none; text-align: center;"><b>GIÁO VIÊN SOẠN BÀI</b></td>
          </tr>
        </table>
      </body>
      </html>
    `;

    const blob = new Blob(['\ufeff', htmlContent], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `GiaoAn_Toan6_5512_${generatedPlan.topic.replace(/\s+/g, '_')}.doc`;
    link.click();
    setIsProcessing(false);
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    setError(null);
    try {
      let extractedText = "";
      const arrayBuffer = await file.arrayBuffer();

      if (file.name.toLowerCase().endsWith('.docx')) {
        const result = await mammoth.extractRawText({ arrayBuffer });
        extractedText = result.value;
      } else if (file.name.toLowerCase().endsWith('.pdf')) {
        extractedText = await extractTextFromPdf(arrayBuffer);
      } else {
        throw new Error("Định dạng file không hỗ trợ. Vui lòng tải lên .docx hoặc .pdf");
      }

      if (!extractedText.trim()) {
        throw new Error("Không thể trích xuất nội dung từ file này. File có thể bị hỏng hoặc là file ảnh quét.");
      }

      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64Data = (reader.result as string).split(',')[1];
        try {
          const plan = await generateLessonPlan(GenerationMode.TRANSFORM, file.name, { data: base64Data, mimeType: file.type }, extractedText);
          setGeneratedPlan(plan);
        } catch (e) {
          setError("Lỗi xử lý AI. Vui lòng thử lại với file khác hoặc soạn thảo mới.");
        } finally {
          setIsProcessing(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err: any) {
      setError(err.message || "Không thể đọc tệp tin.");
      setIsProcessing(false);
    }
  };

  const handleCreateNew = async () => {
