import React, { useEffect, useRef } from 'react';

interface MathRendererProps {
  content: string;
}

const MathRenderer: React.FC<MathRendererProps> = ({ content }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (containerRef.current && (window as any).MathJax) {
      // Chuẩn hóa nội dung trước khi render: chuyển \n thành <br/> nhưng không phá vỡ khối TeX
      const formattedContent = content.replace(/\n/g, '<br/>');
      containerRef.current.innerHTML = formattedContent;

      try {
        // Sử dụng Promise để đảm bảo render xong mới xử lý các thành phần khác nếu cần
        (window as any).MathJax.typesetPromise([containerRef.current]).catch((err: any) => {
          console.error("MathJax typeset failed:", err);
        });
      } catch (e) {
        console.error("MathJax execution error:", e);
      }
    }
  }, [content]);

  return (
    <div 
      ref={containerRef} 
      className="math-rendered text-slate-700 text-sm italic"
      style={{ minHeight: '1.2em', width: '100%', overflowX: 'auto' }}
    />
  );
};

export default MathRenderer;

