            <PenTool size={18}/>
            <span className="font-bold text-sm italic">Soạn bài mới SGK</span>
          </button>
          <div className="pt-4 border-t border-white/5">
            <button onClick={() => setActiveTab('competence')}
              className={`w-full flex items-center gap-3 px-5 py-4 rounded-xl transition-all ${activeTab === 'competence' ? 'bg-blue-600 text-white shadow-xl' : 'hover:bg-white/5'}`}>
              <List size={18}/>
              <span className="font-bold text-sm italic">Khung năng lực số</span>
            </button>
          </div>
        </nav>

        <div className="p-6 bg-slate-950/40 border-t border-white/5">
          <div className="p-4 bg-slate-800/40 rounded-xl border border-white/5 flex gap-3">
            <Info size={14} className="text-blue-400 shrink-0 mt-0.5"/>
            <p className="text-[10px] text-slate-300 italic leading-snug">Hình ảnh từ file cũ sẽ được tự động giữ lại trong giáo án mới.</p>
          </div>
