import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING, description: 'Mục tiêu: 1. Kiến thức; 2. Năng lực; 3. Phẩm chất.' },
    preparations: { type: Type.STRING, description: 'Thiết bị dạy học và học liệu.' },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING, description: 'Tên hoạt động (vd: Hoạt động 1: Mở đầu)' },
          objectives: { type: Type.STRING },
          teacherActivities: { type: Type.STRING, description: 'CỘT 1: Nội dung dạy học của GV. PHẢI GIỮ NGUYÊN 100% CÁC THẺ <img> VÀ CHUỖI DATA BASE64 BÊN TRONG.' },
          studentResults: { type: Type.STRING, description: 'CỘT 2: Kết quả/Sản phẩm học tập của học sinh.' },
          executionSteps: {
            type: Type.OBJECT,
            properties: {
              assignTask: { type: Type.STRING },
              executeTask: { type: Type.STRING },
              reportDiscuss: { type: Type.STRING },
              concludeAssess: { type: Type.STRING }
            },
            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { type: Type.STRING, description: 'CỘT 2: Mô tả tích hợp năng lực số chi tiết.' },
          svgDiagram: { type: Type.STRING, description: 'Mã HTML SVG đầy đủ (<svg>...</svg>) để minh họa trực quan cho bài toán hình học hoặc sơ đồ tư duy. BẮT BUỘC NẾU CÓ HÌNH HỌC.' }
        },
        required: ['id', 'title', 'objectives', 'teacherActivities', 'studentResults', 'executionSteps', 'digitalCompetency', 'svgDiagram']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedContent?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview'; 

  const systemInstruction = `Bạn là chuyên gia soạn giáo án Toán 6 (Bộ sách Kết nối tri thức).
NHIỆM VỤ: Soạn giáo án chuẩn Công văn 5512 cấu trúc 2 cột.

QUY TẮC MINH HỌA HÌNH HỌC (CỰC KỲ QUAN TRỌNG):
- Nếu bài học có liên quan đến Hình học (Điểm, đường thẳng, góc, tam giác, hình vuông, hình thoi, hình bình hành, đối xứng...), bạn BẮT BUỘC phải tạo mã SVG trong trường "svgDiagram".
- Mã SVG phải sạch: nền trắng, nét vẽ đen (stroke="black"), chữ nhãn rõ ràng (text).
- Kích thước SVG nên là viewBox="0 0 400 300".
- Nếu là Đại số, hãy tạo SVG sơ đồ tư duy hoặc bảng số liệu minh họa.

QUY TẮC BẢO TOÀN HÌNH ẢNH CŨ:
- Giữ nguyên các thẻ <img> chứa dữ liệu base64 từ "extractedContent" và đặt vào "teacherActivities".

QUY TẮC NỘI DUNG 5512:
- Cột 1: GV dạy.
- Cột 2: Kết quả HS + Năng lực số (BẮT BUỘC mô tả hoạt động số thực tế như dùng Geogebra, quét QR, Padlet... KHÔNG ĐƯỢC để "Không có hoạt động đặc thù").
- LaTeX: Dùng $...$ cho công thức.`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `CHUYỂN ĐỔI GIÁO ÁN SAU SANG CHUẨN 5512 VÀ VẼ HÌNH MINH HỌA SVG CHO CÁC BÀI TẬP HÌNH HỌC TRONG ĐÓ. 
    Nội dung gốc: \n\n${extractedContent || 'Xem file đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án bài "${input}" (Toán 6 Kết nối tri thức). Tích hợp năng lực số mạnh mẽ, vẽ hình minh họa hình học bằng SVG chi tiết cho từng hoạt động.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.2,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

