          svgDiagram: { type: Type.STRING, description: 'Mã HTML SVG đầy đủ (<svg>...</svg>) để minh họa trực quan. BẮT BUỘC NẾU CÓ HÌNH HỌC.' }
        },
        required: ['id', 'title', 'objectives', 'teacherActivities', 'studentResults', 'executionSteps', 'digitalCompetency', 'svgDiagram']
      }
