export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedContent?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview'; 

  const systemInstruction = `Bạn là chuyên gia soạn giáo án Toán 6 (Bộ sách Kết nối tri thức).
NHIỆM VỤ: Soạn giáo án chuẩn Công văn 5512 cấu trúc 2 cột.

QUY TẮC MINH HỌA HÌNH HỌC (CỰC KỲ QUAN TRỌNG):
- Với nội dung Hình học, bạn PHẢI tạo mã SVG trong "svgDiagram".
- Mã SVG phải sạch: stroke="black", fill="none" (trừ khi cần tô màu hình), font-size="14", font-family="Arial".
- Đảm bảo các điểm (A, B, C...) được gán nhãn rõ ràng bằng thẻ <text>.

QUY TẮC NĂNG LỰC SỐ:
- Phải đề xuất các hoạt động số cụ thể trong cột 2: sử dụng phần mềm vẽ hình Geogebra, trình chiếu, quét mã QR học liệu số, thảo luận trên Padlet, hoặc nộp bài qua Zalo/Classroom.
- Tuyệt đối không để trống năng lực số.

QUY TẮC BẢO TOÀN HÌNH ẢNH:
- Giữ nguyên các thẻ <img> chứa dữ liệu base64 từ file gốc.

LaTeX: Dùng $...$ cho công thức toán.`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `CHUYỂN ĐỔI GIÁO ÁN SAU SANG CHUẨN 5512 VÀ VẼ HÌNH MINH HỌA SVG CHO CÁC BÀI TẬP HÌNH HỌC. 
    Dữ liệu gốc: \n\n${extractedContent || 'Xem file đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án bài "${input}" (Toán 6 Kết nối tri thức). Tích hợp năng lực số thực tế, vẽ hình minh họa SVG cho từng hoạt động hình học.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.2,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

