NHIỆM VỤ: Soạn giáo án chuẩn Công văn 5512 cấu trúc 2 cột.

QUY TẮC VẼ HÌNH HỌC (QUAN TRỌNG NHẤT):
- Đối với mọi bài tập hoặc ví dụ về Hình học (Tam giác, hình vuông, hình thoi, điểm, đường thẳng...), bạn PHẢI vẽ hình bằng mã SVG trong trường "svgDiagram".
- Hình vẽ phải trực quan: nét vẽ stroke="black", fill="none", có thẻ <text> để ghi tên các đỉnh (A, B, C...).
- Kích thước chuẩn viewBox="0 0 400 300".

QUY TẮC BẢO TOÀN HÌNH ẢNH CŨ:
- Nếu input có thẻ <img>, hãy giữ nguyên 100% và đặt vào "teacherActivities".

QUY TẮC NỘI DUNG 5512:
- Cột 1: GV dạy + Hình vẽ minh họa.
- Cột 2: Kết quả HS + Năng lực số (Bắt buộc ghi cụ thể hoạt động số, không để trống).
- LaTeX: Dùng $...$ cho công thức.`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `CHUYỂN ĐỔI GIÁO ÁN SAU SANG CHUẨN 5512 VÀ VẼ HÌNH HỌC SVG MINH HỌA. 
    Dữ liệu: \n\n${extractedContent || 'Xem file đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án bài "${input}" (Toán 6 Kết nối tri thức). Vẽ hình học SVG chi tiết cho từng hoạt động.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.2,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  RefreshCw, 
  Upload, 
  Calculator,
  PenTool,
  List,
  FileCheck,
  FileWarning,
  Sparkles,
  BookOpen,
  Cpu,
  ChevronRight,
  Download,
  Info,
  Layers,
  Image as ImageIcon,
  Plus,
  Send,
  FileText
} from 'lucide-react';
import mammoth from 'mammoth';
import * as pdfjsLib from 'pdfjs-dist';
import { GenerationMode, LessonPlan } from './types';
import { DIGITAL_COMPETENCIES, MATH_6_DATABASE } from './constants.tsx';
import { generateLessonPlan } from './services/geminiService';
import MathRenderer from './components/MathRenderer';

pdfjsLib.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@4.0.379/build/pdf.worker.mjs`;

const LOADING_MESSAGES = [
  "Đang khởi tạo Trình soạn thảo AI...",
  "Phân tích cấu trúc 2 cột chuẩn 5512...",
  "Đang quét hình ảnh và dữ liệu từ file...",
  "Đang vẽ hình học và sơ đồ minh họa...",
  "Chuẩn hóa công thức toán LaTeX...",
  "Tích hợp năng lực số chi tiết...",
  "Sắp hoàn tất, thầy cô đợi một lát nhé..."
];

export default function LessonPlanApp() {
  const [activeTab, setActiveTab] = useState('upload');
  const [selectedLessonId, setSelectedLessonId] = useState('');
  const [customTopic, setCustomTopic] = useState('');
  const [isCustomMode, setIsCustomMode] = useState(false);
  const [generatedPlan, setGeneratedPlan] = useState<LessonPlan | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadingMsgIdx, setLoadingMsgIdx] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    let interval: any;
    if (isProcessing) {
      interval = setInterval(() => {
        setLoadingMsgIdx(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 2500);
    }
    return () => clearInterval(interval);
  }, [isProcessing]);

  const extractTextFromPdf = async (arrayBuffer: ArrayBuffer): Promise<string> => {
    const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
    let fullText = "";
    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const textContent = await page.getTextContent();
      const pageText = textContent.items.map((item: any) => item.str).join(" ");
      fullText += pageText + "\n";
    }
    return fullText;
  };

  const svgToPngBase64 = async (svgStr: string): Promise<string> => {
    return new Promise((resolve, reject) => {
      const svgMatch = svgStr.match(/<svg[\s\S]*?<\/svg>/);
      if (!svgMatch) return resolve('');

      const cleanSvg = svgMatch[0];
      const svgBlob = new Blob([cleanSvg], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      const img = new Image();

      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 800;
        canvas.height = 600;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.fillStyle = 'white';
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          const dataUrl = canvas.toDataURL('image/png');
          URL.revokeObjectURL(url);
          resolve(dataUrl);
        } else {
          reject(new Error("Canvas failure"));
        }
      };
      img.onerror = () => reject(new Error("Image load failure"));
      img.src = url;
    });
  };

  const handleDownloadWord = async () => {
    if (!generatedPlan) return;
    setIsProcessing(true);

    try {
      const processedActivities = await Promise.all(
        generatedPlan.activities.map(async (act) => {
          let svgAsImg = '';
          if (act.svgDiagram && act.svgDiagram.includes('<svg')) {
            try {
              const pngBase64 = await svgToPngBase64(act.svgDiagram);
              if (pngBase64) {
                svgAsImg = `<div style="text-align:center;"><img src="${pngBase64}" style="width: 350pt; height: auto;" /></div>`;
              }
            } catch (e) {
              console.error("Conversion failed", e);
            }
          }
          return { ...act, svgAsImg };
        })
      );

      const htmlContent = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
          <meta charset='utf-8'>
          <style>
            @page { size: A4; margin: 1.5cm 1.5cm 1.5cm 2.5cm; }
            body { font-family: 'Times New Roman', serif; font-size: 11pt; line-height: 1.5; color: #000; }
            .center { text-align: center; }
            .bold { font-weight: bold; }
            .uppercase { text-transform: uppercase; }
            table { width: 100%; border-collapse: collapse; margin-top: 10pt; border: 0.5pt solid black; }
            th, td { border: 0.5pt solid black; padding: 10pt; vertical-align: top; text-align: justify; word-wrap: break-word; }
            .digital-comp-box { font-size: 10pt; font-weight: bold; color: #FF0000; border-top: 0.5pt dashed #FF0000; padding-top: 8pt; margin-top: 12pt; }
            img { max-width: 100%; height: auto; display: block; margin: 10pt auto; }
            .act-header { font-weight: bold; text-decoration: underline; margin-bottom: 5pt; display: block; }
          </style>
        </head>
        <body>
          <div class="center">
            <p class="bold uppercase" style="font-size: 12pt;">KẾ HOẠCH BÀI DẠY (GIÁO ÁN)</p>
            <p class="bold uppercase" style="font-size: 14pt;">BÀI: ${generatedPlan.topic}</p>
            <p>Môn: Toán 6 • Bộ sách: Kết nối tri thức • Mẫu 2 Cột (CV 5512)</p>
          </div>

          <p class="bold uppercase">I. MỤC TIÊU</p>
          <div>${generatedPlan.objectives.replace(/\n/g, '<br/>')}</div>

          <p class="bold uppercase">II. THIẾT BỊ DẠY HỌC VÀ HỌC LIỆU</p>
          <div>${generatedPlan.preparations.replace(/\n/g, '<br/>')}</div>

          <p class="bold uppercase">III. TIẾN TRÌNH DẠY HỌC</p>
          <table>
            <tr style="background-color: #f2f2f2;">
              <th style="width: 45%;">1. Hoạt động dạy học (GV dạy)</th>
              <th style="width: 55%;">2. Kết quả của HS & Năng lực số</th>
            </tr>
            ${processedActivities.map(act => `
              <tr>
                <td>
                  <span class="act-header">${act.title}</span>
                  <p><b>- Mục tiêu:</b> ${act.objectives}</p>
                  <div>${act.teacherActivities.replace(/\n/g, '<br/>')}</div>
                  ${act.svgAsImg || ''}
                </td>
                <td>
                  <p><b>- Kết quả/Sản phẩm học tập:</b><br/>${act.studentResults.replace(/\n/g, '<br/>')}</p>
                  <p><b>* Tổ chức thực hiện:</b></p>
                  <p>B1: ${act.executionSteps.assignTask}<br/>
                     B2: ${act.executionSteps.executeTask}<br/>
                     B3: ${act.executionSteps.reportDiscuss}<br/>
                     B4: ${act.executionSteps.concludeAssess}</p>
                  <div class="digital-comp-box">NĂNG LỰC SỐ: ${act.digitalCompetency}</div>
                </td>
              </tr>
            `).join('')}
          </table>
        </body>
        </html>
      `;

      const blob = new Blob(['\ufeff', htmlContent], { type: 'application/msword' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `GiaoAn_Toan6_5512_${generatedPlan.topic.replace(/\s+/g, '_')}.doc`;
      link.click();
    } catch (e) {
      setError("Lỗi khi xuất file Word.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    setError(null);
    try {
      let extractedContent = "";
      const arrayBuffer = await file.arrayBuffer();

      if (file.name.toLowerCase().endsWith('.docx')) {
        const options = {
          convertImage: mammoth.images.inline((element: any) => {
            return element.read("base64").then((imageBuffer: any) => {
              return {
                src: "data:" + element.contentType + ";base64," + imageBuffer
              };
            });
          })
        };
        const result = await mammoth.convertToHtml({ arrayBuffer }, options);
        extractedContent = result.value;
      } else if (file.name.toLowerCase().endsWith('.pdf')) {
        extractedContent = await extractTextFromPdf(arrayBuffer);
      } else {
        throw new Error("Chỉ hỗ trợ .docx và .pdf");
      }

      if (!extractedContent.trim()) {
        throw new Error("Tài liệu không có nội dung.");
      }

      const reader = new FileReader();
      reader.onloadend = async () => {
        const base64Data = (reader.result as string).split(',')[1];
        try {
          const plan = await generateLessonPlan(GenerationMode.TRANSFORM, file.name, { data: base64Data, mimeType: file.type }, extractedContent);
          setGeneratedPlan(plan);
        } catch (e) {
          setError("Lỗi AI không thể xử lý dữ liệu.");
        } finally {
          setIsProcessing(false);
        }
      };
      reader.readAsDataURL(file);
    } catch (err: any) {
      setError(err.message || "Lỗi đọc tệp.");
      setIsProcessing(false);
    }
  };

  const handleCreateNew = async () => {
    const topic = isCustomMode ? customTopic : selectedLessonId;
    if (!topic) return;
    setIsProcessing(true);
    setError(null);
    try {
      const plan = await generateLessonPlan(GenerationMode.NEW, topic);
      setGeneratedPlan(plan);
    } catch (e) {
      setError("AI không phản hồi.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="flex h-screen bg-[#f8fafc] font-['Be_Vietnam_Pro'] text-slate-900 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-80 bg-[#0f172a] text-slate-400 flex flex-col no-print border-r border-white/5 shadow-2xl z-30">
        <div className="p-8 border-b border-white/5 bg-[#020617]/50 text-center">
          <div className="inline-flex p-3 bg-blue-600 rounded-2xl mb-4 shadow-lg shadow-blue-600/20">
            <Calculator size={32} className="text-white"/>
          </div>
          <h1 className="font-black text-xl italic text-white tracking-tighter">Math AI Visual</h1>
          <p className="text-[10px] font-bold text-blue-500 uppercase italic">Số hóa & Tự vẽ hình</p>
        </div>

        <nav className="flex-1 p-6 space-y-3">
          <button onClick={() => { setActiveTab('upload'); setGeneratedPlan(null); setError(null); }}
            className={`w-full flex items-center gap-3 px-5 py-4 rounded-xl transition-all ${activeTab === 'upload' ? 'bg-blue-600 text-white shadow-xl scale-105' : 'hover:bg-white/5'}`}>
            <Upload size={18}/>
            <span className="font-bold text-sm italic">Nâng cấp bài cũ & Vẽ hình</span>
          </button>
          <button onClick={() => { setActiveTab('create'); setGeneratedPlan(null); setError(null); }}
            className={`w-full flex items-center gap-3 px-5 py-4 rounded-xl transition-all ${activeTab === 'create' ? 'bg-blue-600 text-white shadow-xl scale-105' : 'hover:bg-white/5'}`}>
            <PenTool size={18}/>
            <span className="font-bold text-sm italic">Soạn bài mới + Vẽ hình</span>
          </button>
        </nav>

        <div className="p-6 bg-slate-950/40 border-t border-white/5 italic">
          <div className="p-4 bg-slate-800/40 rounded-xl border border-white/5 flex gap-3">
            <Sparkles size={14} className="text-yellow-400 shrink-0 mt-0.5"/>
            <p className="text-[10px] text-slate-300 leading-snug">Toàn bộ hình vẽ học học sẽ được chuyển thành ảnh thật khi tải file Word.</p>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-full bg-[#fdfdfe] relative">
        <header className="h-20 bg-white border-b flex items-center justify-between px-10 z-20 no-print shadow-sm">
          <div className="flex items-center gap-4">
            <div className="w-1.5 h-8 bg-blue-600 rounded-full"></div>
            <h2 className="font-black text-slate-800 text-base uppercase tracking-widest italic tracking-tighter">Hỗ trợ vẽ hình minh họa trực quan</h2>
          </div>
          {generatedPlan && (
            <button onClick={handleDownloadWord} disabled={isProcessing} className="bg-slate-900 text-white px-8 py-3 rounded-xl font-black text-xs flex items-center gap-2 hover:bg-black transition-all shadow-xl active:scale-95 disabled:opacity-50">
              {isProcessing ? <RefreshCw className="animate-spin" size={16}/> : <Download size={16}/>} TẢI WORD (GỒM HÌNH VẼ)
            </button>
          )}
        </header>

        <div className="flex-1 overflow-auto p-10">
          {error && <div className="max-w-4xl mx-auto bg-red-50 text-red-600 p-6 rounded-2xl mb-8 border-2 border-red-100 flex gap-4 items-center shadow-sm font-bold"><FileWarning size={24}/> {error}</div>}

          {/* Upload Area */}
          {activeTab === 'upload' && !generatedPlan && (
            <div className="max-w-4xl mx-auto mt-12 text-center">
              <input type="file" ref={fileInputRef} onChange={handleFileChange} className="hidden" accept=".docx,.pdf" />
              {!isProcessing ? (
                <div onClick={() => fileInputRef.current?.click()} className="bg-white border-2 border-dashed border-slate-200 p-24 rounded-[4rem] cursor-pointer hover:border-blue-500 hover:bg-blue-50 transition-all group shadow-2xl relative overflow-hidden">
                  <div className="flex justify-center gap-6 mb-8 transition-transform group-hover:-translate-y-3 duration-500">
                    <FileText size={72} className="text-slate-300 group-hover:text-blue-500" />
                    <ImageIcon size={72} className="text-slate-200 group-hover:text-blue-600" />
                  </div>
                  <h3 className="text-4xl font-black text-slate-900 mb-4 italic uppercase tracking-tighter">Nâng cấp giáo án có hình vẽ</h3>
                  <p className="text-slate-500 font-medium italic text-base max-w-md mx-auto leading-relaxed">Hệ thống sẽ giữ lại ảnh cũ và tự động vẽ lại các sơ đồ hình học bằng SVG trực quan.</p>
                </div>
              ) : (
                <div className="p-24 bg-white rounded-[4rem] shadow-2xl text-center max-w-xl mx-auto border-2 border-blue-50">
                  <RefreshCw className="animate-spin mx-auto text-blue-600 mb-10" size={80} />
                  <h3 className="text-3xl font-black mb-4 italic uppercase tracking-tight tracking-widest">Đang vẽ hình học...</h3>
                  <p className="text-blue-600 font-bold uppercase tracking-widest text-xs animate-pulse">
                    {LOADING_MESSAGES[loadingMsgIdx]}
                  </p>
                </div>
              )}
            </div>
          )}

          {/* Create New Area */}
          {activeTab === 'create' && !generatedPlan && (
            <div className="max-w-3xl mx-auto mt-12 bg-white p-16 rounded-[4rem] shadow-2xl border border-slate-100">
               <h3 className="text-4xl font-black text-slate-900 mb-12 flex items-center gap-4 italic uppercase tracking-tighter">
                <Layers className="text-blue-600" size={32}/> Soạn bài mới + Vẽ hình SVG
              </h3>
              <div className="space-y-8">
                {!isCustomMode ? (
                  <div>
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-4 ml-4 italic">Chọn bài dạy SGK</label>
                    <select 
                      value={selectedLessonId} 
                      onChange={(e) => {
                        if (e.target.value === 'custom') setIsCustomMode(true);
                        else setSelectedLessonId(e.target.value);
                      }} 
                      className="w-full p-6 bg-slate-50 rounded-2xl border-2 border-slate-100 font-black text-slate-800 outline-none focus:border-blue-500 focus:bg-white transition-all text-base shadow-sm"
                    >
                      <option value="">-- Click chọn bài --</option>
                      {MATH_6_DATABASE.map(chapter => (
                        <optgroup key={chapter.chapter} label={chapter.chapter}>
                          {chapter.lessons.map(lesson => (
                            <option key={lesson.id} value={lesson.name}>{lesson.name}</option>
                          ))}
                        </optgroup>
                      ))}
                      <option value="custom" className="font-black text-blue-600">+ Bài khác</option>
                    </select>
                  </div>
                ) : (
                  <div className="animate-in fade-in slide-in-from-top-6 duration-500">
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-4 ml-4 italic">Tên bài học</label>
                    <div className="relative">
                      <Plus className="absolute left-6 top-1/2 -translate-y-1/2 text-blue-600" size={24}/>
                      <input 
                        type="text" 
                        autoFocus
                        placeholder="Nhập tên bài..."
                        className="w-full p-6 pl-16 bg-white rounded-2xl border-2 border-blue-500 font-black text-slate-800 outline-none"
                        value={customTopic}
                        onChange={(e) => setCustomTopic(e.target.value)}
                      />
                    </div>
                  </div>
                )}

                <button 
                  disabled={(!selectedLessonId && !customTopic) || isProcessing} 
                  onClick={handleCreateNew} 
                  className="w-full py-6 bg-blue-600 text-white rounded-2xl font-black text-xl hover:bg-blue-700 transition-all flex items-center justify-center gap-4 shadow-2xl"
                >
                  {isProcessing ? <RefreshCw className="animate-spin" size={24}/> : <Sparkles size={28}/>}
                  BẮT ĐẦU SOẠN & VẼ HÌNH
                </button>
              </div>
            </div>
          )}

          {/* Result View */}
          {generatedPlan && (
            <div className="max-w-7xl mx-auto bg-white rounded-[4rem] shadow-2xl border border-slate-100 overflow-hidden mb-20 animate-in fade-in zoom-in-95 duration-700">
              <div className="bg-slate-900 p-16 text-white text-center">
                <h1 className="text-5xl font-black uppercase italic leading-tight mb-4 tracking-tighter">BÀI: {generatedPlan.topic}</h1>
                <p className="text-slate-400 text-xs italic font-bold uppercase tracking-widest">Toàn bộ hình ảnh và hình vẽ hình học được trình bày ở Cột 1</p>
              </div>

              <div className="p-16 space-y-24">
                <section>
                  <h3 className="font-black text-2xl text-slate-900 uppercase tracking-tighter mb-12 flex items-center gap-5 italic">
                    <div className="w-10 h-10 bg-blue-50 rounded-xl flex items-center justify-center text-blue-600 font-black shadow-inner">II</div>
                    Tiến trình dạy học (Chuẩn 2 Cột 5512)
                  </h3>
                  <div className="space-y-16">
                    {generatedPlan.activities.map((act, i) => (
                      <div key={i} className="rounded-[3rem] border-2 border-slate-100 overflow-hidden shadow-md">
                        <div className="bg-slate-50 px-10 py-5 border-b-2 border-slate-100 flex justify-between items-center">
                          <span className="font-black text-sm uppercase tracking-widest italic text-slate-900">{act.title}</span>
                          <span className="bg-slate-900 text-white px-4 py-1.5 rounded-full text-[9px] font-black italic uppercase">Hoạt động {i+1}</span>
                        </div>
                        <div className="flex flex-col lg:flex-row divide-y lg:divide-y-0 lg:divide-x-2 divide-slate-100 bg-white">
                          {/* Column 1 - GV (CHỨA ẢNH & SVG) */}
                          <div className="p-12 lg:w-[45%]">
                            <p className="text-[10px] font-black text-blue-600 uppercase tracking-widest mb-6 italic border-b pb-2 inline-block">1. Hoạt động dạy học (GV)</p>
                            <div className="space-y-8">
                              <div className="bg-white p-8 rounded-3xl border border-slate-50 shadow-inner italic">
                                <p className="font-black text-[11px] mb-4 text-slate-900 uppercase tracking-tight italic">Mục tiêu: {act.objectives}</p>
                                <div className="space-y-6 lesson-content-rich">
                                  <MathRenderer content={act.teacherActivities}/>
                                  {act.svgDiagram && act.svgDiagram.includes('<svg') && (
                                    <div className="mt-8 p-8 bg-white border border-slate-100 rounded-3xl flex flex-col items-center justify-center shadow-sm hover:shadow-xl transition-all duration-500">
                                      <div className="w-full flex justify-center" dangerouslySetInnerHTML={{__html: act.svgDiagram}} />
                                      <p className="text-[10px] font-black text-slate-400 mt-4 uppercase tracking-[0.2em] italic">Hình vẽ minh họa học liệu</p>
                                    </div>
                                  )}
                                </div>
                              </div>
                            </div>
                          </div>
