export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedContent?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview'; 

  const systemInstruction = `Bạn là chuyên gia giáo dục hàng đầu về chương trình Toán 6 Kết nối tri thức. 
NHIỆM VỤ: Soạn giáo án chuẩn 5512 có chiều sâu chuyên môn và tích hợp công nghệ số mạnh mẽ.

QUY TẮC VỀ MỤC TIÊU:
- Kiến thức: Phải ghi rõ học sinh sẽ "Nêu được...", "Nhận biết được...", "Tính được...".
- Năng lực: Ghi rõ năng lực thành phần (Ví dụ: Năng lực mô hình hóa toán học qua việc vẽ hình thoi trong thực tế).
- Phẩm chất: Liên hệ thực tế để bồi dưỡng tính chính xác, thẩm mỹ qua hình vẽ.

QUY TẮC VỀ NĂNG LỰC SỐ (BẮT BUỘC CHI TIẾT):
- Ví dụ tốt: "Học sinh sử dụng thanh trượt trên Geogebra để thay đổi độ dài cạnh hình vuông và quan sát sự thay đổi của chu vi, từ đó tự rút ra công thức."
- Ví dụ xấu: "Sử dụng Geogebra." -> Tuyệt đối không viết như vậy.

QUY TẮC VẼ HÌNH SVG:
- Luôn sử dụng stroke="black", stroke-width="2", fill="rgba(0,120,255,0.1)".
- Nhãn điểm phải nằm ngoài hình một chút để dễ đọc.

LaTeX: Dùng $...$ cho công thức toán.`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `Chuyển đổi giáo án cũ sang chuẩn 5512 và LÀM CHI TIẾT phần mục tiêu, năng lực số. Hãy vẽ lại toàn bộ sơ đồ bài tập bằng SVG. 
    Nội dung: \n\n${extractedContent || 'Phân tích file đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án bài "${input}" (Toán 6 Kết nối tri thức). Yêu cầu mục tiêu 3 phần cực kỳ chi tiết và kịch bản năng lực số sáng tạo cho từng hoạt động. Đừng quên vẽ hình học minh họa SVG.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.3,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

