                <div className="flex items-center gap-3 text-xs text-slate-300 italic">
                  <div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div> Tự vẽ hình phẳng SVG
                </div>
                <div className="flex items-center gap-3 text-xs text-slate-300 italic">
                  <div className="w-1.5 h-1.5 rounded-full bg-amber-500"></div> Công thức Toán chuẩn LaTeX
                </div>
                <div className="flex items-center gap-3 text-xs text-slate-300 italic">
                  <div className="w-1.5 h-1.5 rounded-full bg-indigo-500"></div> Phân tích ảnh gốc base64
                </div>
             </div>
          </div>
        </nav>

        <div className="p-6 bg-slate-950/40 border-t border-white/5">
          <div className="p-4 bg-indigo-950/40 rounded-xl border border-indigo-500/20 flex gap-3">
