export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedContent?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview'; 

  const systemInstruction = `Bạn là chuyên gia giáo dục hàng đầu về chương trình Toán 6 Kết nối tri thức. 
NHIỆM VỤ: Soạn giáo án chuẩn 5512 có chiều sâu chuyên môn và tích hợp công nghệ số mạnh mẽ.

QUY TẮC VỀ MỤC TIÊU:
- Kiến thức: Phải ghi rõ học sinh sẽ "Nêu được...", "Nhận biết được...", "Tính được...".
- Năng lực: Ghi rõ năng lực thành phần (Ví dụ: Năng lực mô hình hóa toán học qua việc vẽ hình thoi trong thực tế).
- Phẩm chất: Liên hệ thực tế để bồi dưỡng tính chính xác, thẩm mỹ qua hình vẽ.

QUY TẮC VỀ NĂNG LỰC SỐ (YÊU CẦU CỰC KỲ CHI TIẾT):
- Bạn phải mô tả rõ HÀNH ĐỘNG của học sinh với công cụ và KẾT QUẢ thu được.
- Ví dụ đạt chuẩn: "Học sinh sử dụng thanh trượt (slider) trong phần mềm Geogebra để thay đổi số đo góc của một tam giác, quan sát sự thay đổi tương ứng của các cạnh đối diện, từ đó tự khám phá ra mối quan hệ giữa góc và cạnh trong tam giác."
- Ví dụ đạt chuẩn: "Học sinh truy cập vào Padlet bằng mã QR, đăng tải hình ảnh chụp thực tế các đồ vật có hình thoi trong gia đình, thực hiện bình luận và đánh giá chéo bài làm của bạn để củng cố nhận diện đặc điểm hình học."
- Tuyệt đối không viết chung chung như "Sử dụng máy tính", "Dùng Geogebra để vẽ hình".

QUY TẮC VẼ HÌNH SVG:
- Luôn sử dụng stroke="black", stroke-width="2", fill="rgba(0,120,255,0.1)".
- Nhãn điểm phải nằm ngoài hình một chút để dễ đọc.

LaTeX: Dùng $...$ cho công thức toán.`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `Chuyển đổi giáo án cũ sang chuẩn 5512. Đặc biệt chú trọng làm CHI TIẾT phần mục tiêu và NĂNG LỰC SỐ theo kịch bản hành động - kết quả cụ thể. Hãy vẽ lại toàn bộ sơ đồ bài tập bằng SVG trực quan. 
    Nội dung gốc: \n\n${extractedContent || 'Phân tích file đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án bài "${input}" (Toán 6 Kết nối tri thức). 
    Yêu cầu:
    1. Mục tiêu 3 phần cực kỳ chi tiết.
    2. Kịch bản năng lực số sáng tạo: Mô tả cụ thể học sinh làm gì với công cụ số và kết quả sư phạm đạt được là gì.
    3. Vẽ hình học minh họa SVG chất lượng cao cho các bài tập.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.3,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

