  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedContent?: string,
  frameworkContent?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview'; 

  const systemInstruction = `Bạn là chuyên gia giáo dục hàng đầu về chương trình Toán 6 Kết nối tri thức. 
NHIỆM VỤ: Soạn giáo án chuẩn 5512 tích hợp công nghệ số.

QUY TẮC QUAN TRỌNG:
${frameworkContent ? `- ĐÃ CÓ KHUNG NĂNG LỰC MẪU: Bạn PHẢI bám sát cấu trúc, thuật ngữ và cách phân bổ năng lực/phẩm chất từ Khung năng lực mẫu được cung cấp bên dưới.` : ''}
- NĂNG LỰC SỐ: Phải mô tả HÀNH ĐỘNG cụ thể (Ví dụ: "HS kéo thanh trượt Slider...") và KẾT QUẢ quan sát được.
- VẼ HÌNH: Luôn tạo mã SVG cho các bài tập hình học trong trường svgDiagram.
- WORD COMPATIBILITY: Đảm bảo nội dung không quá dài để khi xuất Word không bị tràn lề.
- LaTeX: Dùng $...$ cho công thức toán.`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `Nâng cấp giáo án sau sang chuẩn 5512. 
    ${frameworkContent ? `SỬ DỤNG KHUNG NĂNG LỰC THAM CHIẾU NÀY: \n${frameworkContent}\n\n` : ''}
    Nội dung giáo án cũ: \n\n${extractedContent || 'Phân tích file đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án mới cho bài "${input}" (Toán 6 Kết nối tri thức).
    ${frameworkContent ? `TUÂN THỦ KHUNG NĂNG LỰC MẪU NÀY: \n${frameworkContent}\n\n` : ''}
    Yêu cầu: Mục tiêu chi tiết, kịch bản năng lực số hành động - kết quả, và vẽ hình SVG.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.3,
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  RefreshCw, 
  Upload, 
  Calculator,
  PenTool,
  FileWarning,
  Sparkles,
  Cpu,
  Download,
  Layers,
  Plus,
