            .center { text-align: center; }
            .bold { font-weight: bold; }
            .uppercase { text-transform: uppercase; }
            .section-title { font-weight: bold; text-transform: uppercase; margin-top: 12pt; margin-bottom: 4pt; border-bottom: 0.5pt solid black; }
            table { width: 100%; border-collapse: collapse; table-layout: fixed; margin-top: 8pt; border: 0.5pt solid black; mso-table-lspace: 0pt; mso-table-rspace: 0pt; }
            th, td { border: 0.5pt solid black; padding: 6pt; vertical-align: top; overflow: hidden; word-wrap: break-word; }
            .digital-box { color: #800000; font-size: 10pt; font-weight: bold; border: 0.5pt dashed #800000; padding: 4pt; margin-top: 8pt; background: #FFF9F9; }
            img { max-width: 100%; height: auto; display: block; }
          </style>
        </head>
        <body>
          <div class="center">
            <p class="bold uppercase" style="font-size: 13pt;">KẾ HOẠCH BÀI DẠY (GIÁO ÁN)</p>
            <p class="bold uppercase" style="font-size: 15pt;">BÀI: ${generatedPlan.topic}</p>
            <p>Môn: Toán 6 • Bộ sách: ${generatedPlan.bookSeries} • Mẫu 5512</p>
          </div>

          <p class="section-title">I. MỤC TIÊU</p>
