          </button>
          <button onClick={() => { setActiveTab('create'); setGeneratedPlan(null); setError(null); }}
            className={`w-full flex items-center gap-3 px-5 py-4 rounded-xl transition-all ${activeTab === 'create' ? 'bg-indigo-600 text-white shadow-xl scale-105' : 'hover:bg-white/5'}`}>
            <PenTool size={18}/>
            <span className="font-bold text-sm italic">Soạn bài 5512 mới</span>
          </button>

          <div className="pt-8 space-y-4">
             <div className="bg-slate-800/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 italic">Tính năng xuất Word</p>
                <div className="space-y-2">
                   <div className="flex items-center gap-2 text-[11px] text-slate-300">
                      <FileDown size={14} className="text-emerald-500"/> Tự động co dãn bảng biểu
                   </div>
                   <div className="flex items-center gap-2 text-[11px] text-slate-300">
                      <FileDown size={14} className="text-emerald-500"/> Hình vẽ vừa vặn trang giấy
                   </div>
                </div>
             </div>
          </div>
        </nav>

        <div className="p-6 bg-slate-950/40 border-t border-white/5 italic">
          <div className="p-4 bg-indigo-950/40 rounded-xl border border-indigo-500/20 flex gap-3">
            <Sparkles size={14} className="text-yellow-400 shrink-0 mt-0.5"/>
            <p className="text-[10px] text-slate-300 leading-snug">AI sẽ phân tích Khung năng lực mẫu để áp dụng đúng thuật ngữ của thầy cô.</p>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-full bg-[#f8fafc] relative">
