                <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
                   <div className="absolute top-10 left-10 w-60 h-60 bg-indigo-500 rounded-full blur-[100px]"></div>
                   <div className="absolute bottom-10 right-10 w-60 h-60 bg-blue-500 rounded-full blur-[100px]"></div>
