                                       <MathRenderer content={act.studentResults}/>
                                    </div>

                                    <div className="p-6 bg-indigo-50 rounded-2xl border border-indigo-100 italic text-xs">
                                       <p className="text-[11px] font-black mb-3 text-indigo-900 uppercase flex items-center gap-2">Tổ chức thực hiện:</p>
