                                          <p><b>B2:</b> {act.executionSteps.executeTask}</p>
                                          <p><b>B3:</b> {act.executionSteps.reportDiscuss}</p>
                                          <p><b>B4:</b> {act.executionSteps.concludeAssess}</p>
