                                          <p className="text-[9px] font-black text-rose-400 uppercase tracking-widest mb-1 italic">Năng lực số chi tiết</p>
                                          <p className="font-black text-rose-700 text-[13px] leading-relaxed italic">{act.digitalCompetency}</p>
