    },
    preparations: { type: Type.STRING, description: 'Thiết bị dạy học và học liệu số cần thiết.' },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          objectives: { type: Type.STRING },
          teacherActivities: { type: Type.STRING },
          studentResults: { type: Type.STRING },
          executionSteps: {
            type: Type.OBJECT,
            properties: {
              assignTask: { type: Type.STRING },
              executeTask: { type: Type.STRING },
              reportDiscuss: { type: Type.STRING },
              concludeAssess: { type: Type.STRING }
            },
            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { 
            type: Type.STRING, 
            description: 'Kịch bản hành động cụ thể của HS với công cụ số (Ví dụ: Geogebra, Padlet) và kết quả sư phạm đạt được.' 
          },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG vẽ hình học minh họa cho bài tập hoặc kiến thức.' }
        },
        required: ['id', 'title', 'objectives', 'teacherActivities', 'studentResults', 'executionSteps', 'digitalCompetency', 'svgDiagram']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedContent?: string,
  frameworkContent?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  // Sử dụng gemini-3-pro-preview để có khả năng reasoning (suy luận) tốt nhất cho giáo dục
  const modelName = 'gemini-3-pro-preview'; 

  const systemInstruction = `Bạn là chuyên gia giáo dục cao cấp, am hiểu sâu sắc chương trình Toán 6 Kết nối tri thức và Công văn 5512.

QUY TẮC CHIẾN LƯỢC:
${frameworkContent ? `- KHUNG NĂNG LỰC THAM CHIẾU: Bạn PHẢI trích xuất các tiêu chí từ nội dung này (có thể từ file Word/Excel) để viết mục tiêu bài dạy đúng chuẩn mà giáo viên yêu cầu.` : ''}
- NĂNG LỰC SỐ (HÀNH ĐỘNG - KẾT QUẢ): Mô tả rõ HS làm gì (ví dụ: kéo slider trong Geogebra) và họ học được gì qua hành động đó.
- SVG DIAGRAM: Luôn tạo hình vẽ minh họa toán học bằng SVG (stroke="black", fill="rgba(0,120,255,0.1)").
- ĐỊNH DẠNG WORD: Nội dung phải súc tích, tránh viết quá dài gây tràn bảng khi xuất ra file Word.
- LaTeX: Luôn dùng $...$ cho công thức toán học.`;

  let prompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    prompt = `Nâng cấp giáo án này sang chuẩn 5512 Advanced. 
    ${frameworkContent ? `DỰA TRÊN KHUNG NĂNG LỰC MẪU NÀY ĐỂ SOẠN: \n${frameworkContent}\n\n` : ''}
    Nội dung giáo án gốc: \n\n${extractedContent || 'Phân tích tệp đính kèm.'}`;
  } else {
    prompt = `Soạn giáo án mới cho bài "${input}" (Toán 6 Kết nối tri thức).
    ${frameworkContent ? `DỰA TRÊN KHUNG NĂNG LỰC MẪU NÀY ĐỂ SOẠN: \n${frameworkContent}\n\n` : ''}
    Yêu cầu: Mục tiêu 3 phần chi tiết, 4 bước thực hiện chuẩn 5512, tích hợp năng lực số thực tế và vẽ hình SVG.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: prompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 1, // Gemini 3 Pro hoạt động tốt nhất ở temp 1 với Thinking
      thinkingConfig: { thinkingBudget: 16384 }, // Kích hoạt khả năng suy luận để soạn giáo án chất lượng hơn
    },
  });

  const text = response.text;
  if (!text) throw new Error("AI không phản hồi.");
  return JSON.parse(text) as LessonPlan;
};

