    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          objectives: { type: Type.STRING },
          teacherActivities: { type: Type.STRING },
          studentResults: { type: Type.STRING },
          executionSteps: {
            type: Type.OBJECT,
            properties: {
              assignTask: { type: Type.STRING },
              executeTask: { type: Type.STRING },
              reportDiscuss: { type: Type.STRING },
              concludeAssess: { type: Type.STRING }
            },
            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { 
            type: Type.STRING, 
            description: 'Kịch bản hành động số. Dùng chữ màu đỏ cho phần tích hợp mới.' 
          },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG vẽ hình học minh họa bài tập.' }
        },
        required: ['id', 'title', 'objectives', 'teacherActivities', 'studentResults', 'executionSteps', 'digitalCompetency', 'svgDiagram']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedContent?: string,
  frameworkContent?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview'; 

  const systemInstruction = `Bạn là chuyên gia giáo dục soạn giáo án 5512. 

  QUY TẮC ĐẶC BIỆT CHO CHẾ ĐỘ "NÂNG CẤP GIÁO ÁN" (TRANSFORM):
  1. GIỮ NGUYÊN NỘI DUNG GỐC: Không được thay đổi văn phong hoặc lược bỏ các ý chính trong giáo án cũ mà giáo viên cung cấp.
  2. TÍCH HỢP KHUNG NĂNG LỰC: Chỉ lồng ghép/bổ sung thêm các tiêu chí, năng lực, phẩm chất từ Khung năng lực mẫu vào các vị trí phù hợp trong giáo án cũ.
  3. ĐÁNH DẤU CHỮ ĐỎ: Tất cả các nội dung được tích hợp thêm hoặc chỉnh sửa dựa trên Khung năng lực mẫu PHẢI được bao bọc trong thẻ <span style="color: #ff0000;">...</span> (màu đỏ) để giáo viên dễ phân biệt.
  4. ĐỊNH DẠNG: Sử dụng LaTeX $...$ cho công thức và mã SVG cho hình vẽ. Trình bày 2 cột súc tích.`;

  let userPrompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    userPrompt = `Nhiệm vụ: Giữ nguyên nội dung giáo án cũ dưới đây, thực hiện tích hợp thêm Khung năng lực tham chiếu vào các phần Mục tiêu và Hoạt động. Những phần tích hợp mới PHẢI viết bằng chữ màu đỏ (<span style="color: #ff0000;">...</span>).

    KHUNG NĂNG LỰC THAM CHIẾU: 
    ${frameworkContent || "Không có khung mẫu cụ thể, hãy tự tối ưu theo chuẩn 5512."}

    NỘI DUNG GIÁO ÁN CŨ CẦN GIỮ LẠI: 
    \n\n${extractedContent || 'Xem file đính kèm.'}`;
  } else {
    userPrompt = `Soạn giáo án mới hoàn toàn cho bài "${input}" (Toán 6 Kết nối tri thức).
    ${frameworkContent ? `TUÂN THỦ KHUNG NĂNG LỰC MẪU NÀY: \n${frameworkContent}\n\n` : ''}
    Yêu cầu: Đầy đủ các bước chuyển giao nhiệm vụ, tích hợp năng lực số và vẽ hình SVG.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: userPrompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 1,
      thinkingConfig: { thinkingBudget: 32768 },
    },
  });

  const responseText = response.text;
  if (!responseText) throw new Error("AI không phản hồi dữ liệu.");

  return JSON.parse(responseText.trim()) as LessonPlan;
};

