import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { 
      type: Type.STRING, 
      description: 'Mục tiêu chi tiết. Ở chế độ Nâng cấp, giữ nguyên mục tiêu cũ và chèn thêm các năng lực mới bằng chữ màu đỏ.' 
    },
    preparations: { type: Type.STRING, description: 'Thiết bị dạy học và học liệu số.' },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          objectives: { type: Type.STRING },
          teacherActivities: { type: Type.STRING },
          studentResults: { type: Type.STRING },
          executionSteps: {
            type: Type.OBJECT,
            properties: {
              assignTask: { type: Type.STRING },
              executeTask: { type: Type.STRING },
              reportDiscuss: { type: Type.STRING },
              concludeAssess: { type: Type.STRING }
            },
            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { 
            type: Type.STRING, 
            description: 'Kịch bản hành động số. Dùng chữ màu đỏ cho phần tích hợp mới.' 
          },
          svgDiagram: { type: Type.STRING, description: 'Mã SVG vẽ hình học minh họa bài tập.' }
        },
        required: ['id', 'title', 'objectives', 'teacherActivities', 'studentResults', 'executionSteps', 'digitalCompetency', 'svgDiagram']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedContent?: string,
  frameworkContent?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-pro-preview'; 

  const systemInstruction = `Bạn là chuyên gia giáo dục soạn giáo án 5512 cho môn Toán 6 Kết nối tri thức. 

  QUY TẮC ĐẶC BIỆT CHO CHẾ ĐỘ "NÂNG CẤP GIÁO ÁN" (TRANSFORM):
  1. GIỮ NGUYÊN NỘI DUNG GỐC: Tuyệt đối không xóa bỏ hoặc thay đổi văn phong nội dung cũ của giáo viên.
  2. TÍCH HỢP NĂNG LỰC: Lồng ghép thêm các tiêu chí năng lực (từ khung mẫu của GV hoặc theo quy định chuẩn 5512/Năng lực số nếu không có khung mẫu).
  3. ĐÁNH DẤU CHỮ ĐỎ: Tất cả phần nội dung mới tích hợp thêm PHẢI được bao bọc trong thẻ <span style="color: #ff0000;">...</span> để phân biệt.
  4. ĐỊNH DẠNG: Sử dụng LaTeX $...$ cho công thức và mã SVG cho hình vẽ. Trình bày 2 cột súc tích.`;

  let userPrompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    userPrompt = `Nhiệm vụ: Nâng cấp giáo án cũ bằng cách tích hợp thêm các năng lực chi tiết. 

    NGUỒN THAM CHIẾU NĂNG LỰC: 
    ${frameworkContent ? `Sử dụng Khung năng lực mẫu này: \n${frameworkContent}` : `Sử dụng quy định chuẩn 5512 hiện hành và các kịch bản năng lực số phổ biến cho môn Toán lớp 6.`}

    YÊU CẦU: Giữ nguyên văn bản giáo án cũ, chỉ bổ sung thêm các ý về năng lực vào các phần phù hợp bằng CHỮ MÀU ĐỎ (<span style="color: #ff0000;">...</span>).

    NỘI DUNG GIÁO ÁN CŨ: 
    \n\n${extractedContent || 'Xem file đính kèm.'}`;
  } else {
    userPrompt = `Soạn giáo án mới cho bài "${input}" (Toán 6 Kết nối tri thức).
    Sử dụng ${frameworkContent ? `Khung năng lực mẫu này: \n${frameworkContent}` : `quy định chuẩn 5512 và năng lực số hiện hành`}.
    Yêu cầu: Đầy đủ các bước chuyển giao nhiệm vụ, tích hợp năng lực số và vẽ hình SVG.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: userPrompt }, ...(fileData ? [{ inlineData: fileData }] : [])] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 1,
      thinkingConfig: { thinkingBudget: 32768 },
    },
  });

  const responseText = response.text;
  if (!responseText) throw new Error("AI không phản hồi dữ liệu.");

  return JSON.parse(responseText.trim()) as LessonPlan;
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  RefreshCw, 
  Upload, 
  Calculator,
  PenTool,
  FileWarning,
  Sparkles,
  Cpu,
  Download,
  Layers,
  Plus,
  FileText,
  Target,
  FileDown,
  FileSearch,
  Table as TableIcon,
  ShieldCheck,
  Zap,
  Info
} from 'lucide-react';
import mammoth from 'mammoth';
import * as pdfjsLib from 'pdfjs-dist';
import * as XLSX from 'xlsx';
import { GenerationMode, LessonPlan } from './types';
import { MATH_6_DATABASE } from './constants.tsx';
import { generateLessonPlan } from './services/geminiService';
import MathRenderer from './components/MathRenderer';

pdfjsLib.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@4.0.379/build/pdf.worker.mjs`;

const LOADING_MESSAGES = [
  "Đang kích hoạt Model Gemini 3 Pro (Phiên bản mạnh nhất)...",
  "Đang giữ nguyên nội dung giáo án gốc của thầy cô...",
  "Đang tích hợp Khung năng lực chi tiết (chữ đỏ)...",
  "Đang kiểm tra quy định chuẩn 5512 hiện hành...",
  "Xây dựng kịch bản tương tác số hành động - kết quả...",
  "Tối ưu hóa bố cục Word (Chống tràn lề tự động)...",
  "Đang tạo hình vẽ toán học SVG độ chính xác cao..."
];

export default function LessonPlanApp() {
  const [activeTab, setActiveTab] = useState('upload');
  const [selectedLessonId, setSelectedLessonId] = useState('');
  const [customTopic, setCustomTopic] = useState('');
  const [isCustomMode, setIsCustomMode] = useState(false);
  const [generatedPlan, setGeneratedPlan] = useState<LessonPlan | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadingMsgIdx, setLoadingMsgIdx] = useState(0);
  const [error, setError] = useState<string | null>(null);

  // File state
  const [lessonFileContent, setLessonFileContent] = useState<string>('');
  const [lessonFileName, setLessonFileName] = useState<string>('');
  const [lessonFileBase64, setLessonFileBase64] = useState<any>(null);

  const [frameworkContent, setFrameworkContent] = useState<string>('');
  const [frameworkFileName, setFrameworkFileName] = useState<string>('');

  const lessonInputRef = useRef<HTMLInputElement>(null);
  const frameworkInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    let interval: any;
    if (isProcessing) {
      interval = setInterval(() => {
        setLoadingMsgIdx(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 2500);
    }
    return () => clearInterval(interval);
  }, [isProcessing]);

  const extractText = async (file: File): Promise<string> => {
    const arrayBuffer = await file.arrayBuffer();
    const fileName = file.name.toLowerCase();

    try {
      if (fileName.endsWith('.docx')) {
        const result = await mammoth.extractRawText({ arrayBuffer });
        return result.value;
      } else if (fileName.endsWith('.pdf')) {
        const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
        let fullText = "";
        for (let i = 1; i <= pdf.numPages; i++) {
          const page = await pdf.getPage(i);
          const textContent = await page.getTextContent();
          fullText += textContent.items.map((item: any) => item.str).join(" ") + "\n";
        }
        return fullText;
      } else if (fileName.endsWith('.xlsx') || fileName.endsWith('.xls')) {
        const workbook = XLSX.read(arrayBuffer, { type: 'array' });
        let excelText = "";
        workbook.SheetNames.forEach(sheetName => {
          const worksheet = workbook.Sheets[sheetName];
          excelText += `[Sheet: ${sheetName}]\n`;
          excelText += XLSX.utils.sheet_to_txt(worksheet) + "\n";
        });
        return excelText;
      }
    } catch (e) {
      console.error("Extraction error:", e);
      throw new Error(`Lỗi đọc file ${fileName}`);
    }
    return "";
  };

  const svgToPngBase64 = async (svgStr: string): Promise<string> => {
    return new Promise((resolve) => {
      const svgMatch = svgStr.match(/<svg[\s\S]*?<\/svg>/);
      if (!svgMatch) return resolve('');

      const cleanSvg = svgMatch[0];
      const svgBlob = new Blob([cleanSvg], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      const img = new Image();

      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 1200;
        canvas.height = 700;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.fillStyle = 'white';
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          const dataUrl = canvas.toDataURL('image/png');
          URL.revokeObjectURL(url);
          resolve(dataUrl);
        } else resolve('');
      };
      img.onerror = () => resolve('');
      img.src = url;
    });
  };

  const handleDownloadWord = async () => {
    if (!generatedPlan) return;
    setIsProcessing(true);

    try {
      const processedActivities = await Promise.all(
        generatedPlan.activities.map(async (act) => {
          let svgAsImg = '';
          if (act.svgDiagram && act.svgDiagram.includes('<svg')) {
            const pngBase64 = await svgToPngBase64(act.svgDiagram);
            if (pngBase64) {
              svgAsImg = `<div style="text-align:center;margin:10pt 0;"><img src="${pngBase64}" style="width: 420pt; height: auto;" /></div>`;
            }
          }
          return { ...act, svgAsImg };
        })
      );

      const htmlContent = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
          <meta charset='utf-8'>
          <style>
            @page { 
              size: A4; 
              margin: 1.5cm 1.5cm 1.5cm 2.5cm; 
              mso-header-margin: 35.4pt; 
              mso-footer-margin: 35.4pt; 
            }
            body { 
              font-family: 'Times New Roman', serif; 
              font-size: 11pt; 
              line-height: 1.3; 
              text-align: justify;
            }
            .center { text-align: center; }
            .bold { font-weight: bold; }
            .uppercase { text-transform: uppercase; }
            .section-title { font-weight: bold; text-transform: uppercase; margin-top: 15pt; margin-bottom: 5pt; border-bottom: 0.5pt solid black; }
            table { 
              width: 100%; 
              border-collapse: collapse; 
              table-layout: fixed; 
              border: 0.5pt solid black; 
              word-wrap: break-word;
            }
            th, td { 
              border: 0.5pt solid black; 
              padding: 6pt; 
              vertical-align: top; 
            }
            .digital-box { 
              color: #991b1b; 
              font-size: 10pt; 
              font-weight: bold; 
              border: 0.5pt dashed #991b1b; 
              padding: 4pt; 
              margin-top: 8pt; 
              background-color: #fef2f2;
            }
            span[style*="color: #ff0000"], 
            span[style*="color: red"] {
              color: red !important;
            }
          </style>
        </head>
        <body>
          <div class="center">
            <p class="bold uppercase" style="font-size: 14pt;">KẾ HOẠCH BÀI DẠY (GIÁO ÁN)</p>
            <p class="bold uppercase" style="font-size: 16pt;">BÀI: ${generatedPlan.topic}</p>
            <p>Môn: Toán 6 • Kết nối tri thức • Nâng cấp bởi AI</p>
          </div>
          <p class="section-title">I. MỤC TIÊU</p>
          <div style="margin-left: 5pt;">${generatedPlan.objectives.replace(/\n/g, '<br/>')}</div>
          <p class="section-title">II. THIẾT BỊ DẠY HỌC VÀ HỌC LIỆU</p>
          <div style="margin-left: 5pt;">${generatedPlan.preparations.replace(/\n/g, '<br/>')}</div>
          <p class="section-title">III. TIẾN TRÌNH DẠY HỌC</p>
          <table border="1">
            <tr style="background-color: #f8fafc;">
              <th style="width: 42%;">1. Hoạt động dạy học (GV)</th>
              <th style="width: 58%;">2. Sản phẩm HS & Năng lực số</th>
            </tr>
            ${processedActivities.map(act => `
              <tr>
                <td>
                  <p><b>${act.title}</b></p>
                  <p><i>- Mục tiêu:</i> ${act.objectives}</p>
                  <div style="font-size: 10pt;">${act.teacherActivities.replace(/\n/g, '<br/>')}</div>
                  ${act.svgAsImg || ''}
                </td>
                <td>
                  <p><b>- Sản phẩm dự kiến:</b> ${act.studentResults.replace(/\n/g, '<br/>')}</p>
                  <p><b>* Các bước thực hiện:</b></p>
                  <p style="font-size: 9.5pt;">
                    <b>B1:</b> ${act.executionSteps.assignTask}<br/>
                    <b>B2:</b> ${act.executionSteps.executeTask}<br/>
                    <b>B3:</b> ${act.executionSteps.reportDiscuss}<br/>
                    <b>B4:</b> ${act.executionSteps.concludeAssess}
                  </p>
                  <div class="digital-box">NĂNG LỰC SỐ: ${act.digitalCompetency}</div>
                </td>
              </tr>
            `).join('')}
          </table>
          <p style="font-size: 9pt; color: #666; margin-top: 20pt; font-style: italic;">Ghi chú: Nội dung màu đỏ là phần được AI tích hợp thêm từ Khung năng lực tham chiếu.</p>
        </body>
        </html>
      `;

      const blob = new Blob(['\ufeff', htmlContent], { type: 'application/msword' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `GiaoAn_Toan6_NangCap_${generatedPlan.topic.replace(/\s+/g, '_')}.doc`;
      link.click();
    } catch (e) {
      setError("Lỗi xử lý tệp tin.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleLessonFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    setError(null);
    try {
      setLessonFileName(file.name);
      const text = await extractText(file);
      setLessonFileContent(text);
      const reader = new FileReader();
      reader.onloadend = () => {
        setLessonFileBase64({ data: (reader.result as string).split(',')[1], mimeType: file.type });
        setIsProcessing(false);
      };
      reader.readAsDataURL(file);
    } catch (err: any) {
      setError(err.message);
      setIsProcessing(false);
    }
  };

  const handleFrameworkFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsProcessing(true);
    setError(null);
    try {
      setFrameworkFileName(file.name);
      const text = await extractText(file);
      setFrameworkContent(text);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleProcess = async () => {
    const topic = isCustomMode ? customTopic : selectedLessonId;
    if (activeTab === 'create' && !topic) return;
    if (activeTab === 'upload' && !lessonFileContent) return;

    setIsProcessing(true);
    setError(null);
    try {
      const mode = activeTab === 'upload' ? GenerationMode.TRANSFORM : GenerationMode.NEW;
      const targetInput = activeTab === 'upload' ? lessonFileName : topic;

      const plan = await generateLessonPlan(
        mode, 
        targetInput, 
        lessonFileBase64, 
        lessonFileContent, 
        frameworkContent
      );
      setGeneratedPlan(plan);
    } catch (e) {
      setError("AI Gemini 3 gặp sự cố kỹ thuật. Vui lòng thử lại sau vài giây.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="flex h-screen bg-[#f8fafc] font-['Be_Vietnam_Pro'] text-slate-900 overflow-hidden">
      {/* Sidebar */}
      <aside className="w-80 bg-[#0f172a] text-slate-400 flex flex-col no-print border-r border-white/5 shadow-2xl z-30">
        <div className="p-8 border-b border-white/5 bg-[#020617]/50 text-center">
          <div className="inline-flex p-3 bg-indigo-600 rounded-2xl mb-4 shadow-lg shadow-indigo-600/20">
            <Calculator size={32} className="text-white"/>
          </div>
          <h1 className="font-black text-xl italic text-white tracking-tighter">MATH ADVANCED</h1>
          <p className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest italic">Gemini 3 Pro + Thinking</p>
        </div>

        <nav className="flex-1 p-6 space-y-3 overflow-y-auto">
          <button onClick={() => { setActiveTab('upload'); setGeneratedPlan(null); setError(null); }}
            className={`w-full flex items-center gap-3 px-5 py-4 rounded-xl transition-all ${activeTab === 'upload' ? 'bg-indigo-600 text-white shadow-xl scale-105' : 'hover:bg-white/5'}`}>
            <Upload size={18}/>
            <span className="font-bold text-sm italic uppercase tracking-tighter">Nâng cấp giáo án</span>
          </button>
          <button onClick={() => { setActiveTab('create'); setGeneratedPlan(null); setError(null); }}
            className={`w-full flex items-center gap-3 px-5 py-4 rounded-xl transition-all ${activeTab === 'create' ? 'bg-indigo-600 text-white shadow-xl scale-105' : 'hover:bg-white/5'}`}>
            <PenTool size={18}/>
            <span className="font-bold text-sm italic uppercase tracking-tighter">Soạn bài mới</span>
          </button>

          <div className="pt-8 space-y-4">
             <div className="bg-slate-800/50 p-4 rounded-2xl border border-white/5">
                <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-3 italic">Trạng thái hệ thống</p>
                <div className="space-y-2">
                   <div className="flex items-center gap-2 text-[11px] text-slate-300">
                      <ShieldCheck size={14} className="text-emerald-500"/> Giữ nguyên giáo án cũ
                   </div>
                   <div className="flex items-center gap-2 text-[11px] text-slate-300">
                      <Zap size={14} className="text-rose-500"/> Tích hợp chữ đỏ (AI)
                   </div>
                   <div className="flex items-center gap-2 text-[11px] text-slate-300">
                      <Info size={14} className="text-indigo-400"/> Tự động chuẩn 5512
                   </div>
                </div>
             </div>
          </div>
        </nav>

        <div className="p-6 bg-slate-950/40 border-t border-white/5">
          <div className="p-4 bg-indigo-950/40 rounded-xl border border-indigo-500/20 flex gap-3">
            <Sparkles size={14} className="text-yellow-400 shrink-0 mt-0.5"/>
            <p className="text-[10px] text-slate-300 leading-snug italic">Toàn bộ phần tích hợp mới sẽ hiển thị bằng chữ màu đỏ để thầy cô kiểm tra.</p>
          </div>
        </div>
      </aside>

      <main className="flex-1 flex flex-col h-full bg-white relative">
        <header className="h-20 bg-white border-b flex items-center justify-between px-10 z-20 no-print shadow-sm">
          <div className="flex items-center gap-4">
            <div className="w-1.5 h-8 bg-indigo-600 rounded-full"></div>
            <h2 className="font-black text-slate-800 text-base uppercase tracking-tighter italic flex items-center gap-2">
              <ShieldCheck size={18} className="text-indigo-600"/> GIÁO ÁN TOÁN 6 - KẾT NỐI TRI THỨC
            </h2>
          </div>
          {generatedPlan && (
            <button onClick={handleDownloadWord} disabled={isProcessing} className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-black text-xs flex items-center gap-2 hover:bg-indigo-700 shadow-xl active:scale-95 disabled:opacity-50">
              {isProcessing ? <RefreshCw className="animate-spin" size={16}/> : <Download size={16}/>} TẢI GIÁO ÁN CHỮ ĐỎ
            </button>
          )}
        </header>

        <div className="flex-1 overflow-auto p-10">
          {error && <div className="max-w-4xl mx-auto bg-red-50 text-red-600 p-6 rounded-2xl mb-8 border-2 border-red-100 flex gap-4 items-center shadow-sm font-bold"><FileWarning size={24}/> {error}</div>}

          {!generatedPlan && (
            <div className="max-w-4xl mx-auto space-y-10 mt-6 animate-in fade-in slide-in-from-top-4 duration-500">
               {/* Main Input Section */}
               <div className="bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100">
                  <h3 className="text-3xl font-black text-slate-900 mb-8 flex items-center gap-4 italic uppercase tracking-tighter">
                    {activeTab === 'upload' ? <FileSearch className="text-indigo-600" size={32}/> : <Plus className="text-indigo-600" size={32}/>}
                    {activeTab === 'upload' ? 'Bước 1: Tải giáo án cũ' : 'Bước 1: Chọn bài dạy'}
                  </h3>

                  <div className="space-y-6">
                    {activeTab === 'upload' ? (
                       <div className="space-y-4">
                          <p className="text-sm font-bold text-slate-600 italic px-4 flex items-center gap-2">
                            <Info size={16} className="text-indigo-500"/>
                            AI giữ nguyên nội dung gốc và chỉ bổ sung thêm các năng lực chi tiết bằng chữ đỏ.
                          </p>
                          <div 
                            onClick={() => lessonInputRef.current?.click()}
                            className={`p-10 border-2 border-dashed rounded-3xl cursor-pointer transition-all flex flex-col items-center gap-4 ${lessonFileName ? 'border-indigo-500 bg-indigo-50' : 'border-slate-200 hover:border-indigo-400'}`}
                          >
                              <input type="file" ref={lessonInputRef} onChange={handleLessonFileChange} className="hidden" accept=".docx,.pdf" />
                              <Upload size={48} className={lessonFileName ? 'text-indigo-600' : 'text-slate-300'} />
                              <p className="font-black text-slate-800 text-center">{lessonFileName || 'Nhấn để tải lên giáo án cũ (.docx, .pdf)'}</p>
                          </div>
                       </div>
                    ) : (
                      <select 
                        value={selectedLessonId} 
                        onChange={(e) => {
                          if (e.target.value === 'custom') setIsCustomMode(true);
                          else { setSelectedLessonId(e.target.value); setIsCustomMode(false); }
                        }} 
                        className="w-full p-6 bg-slate-50 rounded-2xl border-2 border-slate-100 font-black text-slate-800 outline-none focus:border-indigo-500 shadow-sm"
                      >
                        <option value="">-- Chọn bài dạy từ SGK --</option>
                        {MATH_6_DATABASE.map(chapter => (
