export default function LessonPlanApp() {
  const [activeTab, setActiveTab] = useState('upload');
  const [selectedLessonId, setSelectedLessonId] = useState('');
  const [customTopic, setCustomTopic] = useState('');
  const [isCustomMode, setIsCustomMode] = useState(false);
  const [generatedPlan, setGeneratedPlan] = useState<LessonPlan | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadingMsgIdx, setLoadingMsgIdx] = useState(0);
  const [error, setError] = useState<string | null>(null);

  const [lessonFileContent, setLessonFileContent] = useState<string>('');
  const [lessonFileName, setLessonFileName] = useState<string>('');

  const [frameworkContent, setFrameworkContent] = useState<string>('');
  const [frameworkFileName, setFrameworkFileName] = useState<string>('');

  const lessonInputRef = useRef<HTMLInputElement>(null);
  const frameworkInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    let interval: any;
    if (isProcessing) {
      interval = setInterval(() => {
        setLoadingMsgIdx(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 2000);
    }
    return () => clearInterval(interval);
  }, [isProcessing]);

  const extractText = async (file: File): Promise<string> => {
    const arrayBuffer = await file.arrayBuffer();
    const fileName = file.name.toLowerCase();

    try {
      if (fileName.endsWith('.docx')) {
        const result = await mammoth.extractRawText({ arrayBuffer });
        return result.value;
      } else if (fileName.endsWith('.pdf')) {
        const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
        let fullText = "";
        for (let i = 1; i <= pdf.numPages; i++) {
          const page = await pdf.getPage(i);
          const textContent = await page.getTextContent();
          fullText += textContent.items.map((item: any) => item.str).join(" ") + "\n";
        }
        return fullText;
      } else if (fileName.endsWith('.xlsx') || fileName.endsWith('.xls')) {
        const workbook = XLSX.read(arrayBuffer, { type: 'array' });
        let excelText = "";
        workbook.SheetNames.forEach(sheetName => {
          const worksheet = workbook.Sheets[sheetName];
          excelText += `[Sheet: ${sheetName}]\n`;
          excelText += XLSX.utils.sheet_to_txt(worksheet) + "\n";
        });
        return excelText;
      }
    } catch (e) {
      throw new Error(`Lỗi đọc file ${fileName}. Vui lòng thử định dạng khác.`);
    }
    return "";
  };

  const svgToPngBase64 = async (svgStr: string): Promise<string> => {
    return new Promise((resolve) => {
      const svgMatch = svgStr.match(/<svg[\s\S]*?<\/svg>/);
      if (!svgMatch) return resolve('');

      const cleanSvg = svgMatch[0];
      const svgBlob = new Blob([cleanSvg], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      const img = new Image();

      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 1200;
        canvas.height = 700;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.fillStyle = 'white';
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          const dataUrl = canvas.toDataURL('image/png');
          URL.revokeObjectURL(url);
          resolve(dataUrl);
        } else resolve('');
      };
      img.onerror = () => resolve('');
      img.src = url;
    });
  };

  const handleDownloadWord = async () => {
    if (!generatedPlan) return;
    setIsProcessing(true);

    try {
      const processedActivities = await Promise.all(
        generatedPlan.activities.map(async (act) => {
          let svgAsImg = '';
          if (act.svgDiagram && act.svgDiagram.includes('<svg')) {
            const pngBase64 = await svgToPngBase64(act.svgDiagram);
            if (pngBase64) {
              svgAsImg = `<div style="text-align:center;margin:10pt 0;"><img src="${pngBase64}" style="width: 420pt; height: auto;" /></div>`;
            }
          }
          return { ...act, svgAsImg };
        })
      );

      const htmlContent = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
          <meta charset='utf-8'>
          <style>
            @page { 
              size: A4; 
              margin: 1.5cm 1.5cm 1.5cm 2.5cm; 
              mso-header-margin: 35.4pt; 
              mso-footer-margin: 35.4pt; 
            }
            body { 
              font-family: 'Times New Roman', serif; 
              font-size: 11pt; 
              line-height: 1.3; 
              text-align: justify;
            }
            .center { text-align: center; }
            .bold { font-weight: bold; }
            .uppercase { text-transform: uppercase; }
            .section-title { font-weight: bold; text-transform: uppercase; margin-top: 15pt; margin-bottom: 5pt; border-bottom: 0.5pt solid black; }
            table { 
              width: 100%; 
              border-collapse: collapse; 
              table-layout: fixed; 
              border: 0.5pt solid black; 
              word-wrap: break-word;
            }
            th, td { 
              border: 0.5pt solid black; 
              padding: 6pt; 
              vertical-align: top; 
            }
            .digital-box { 
              color: #991b1b; 
              font-size: 10pt; 
              font-weight: bold; 
