              // CHIẾN THUẬT CHỐNG TRÀN: Giới hạn bề rộng ảnh chặt chẽ hơn trong cột 1 (35%)
              // Tính toán: Cả trang 16.5cm ~ 468pt. 35% là ~163pt. Để an toàn ta để max-width 150pt.
              svgAsImg = `<div style="text-align:center;margin:10pt 0;"><img src="${pngBase64}" style="width: 155pt; height: auto; display: block; margin: 0 auto;" width="206" /></div>`;
            }
          }
          return { ...act, svgAsImg };
        })
      );

      const htmlContent = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
          <meta charset='utf-8'>
          <!--[if gte mso 9]>
          <xml>
            <w:WordDocument>
              <w:View>Print</w:View>
              <w:Zoom>100</w:Zoom>
              <w:DoNotOptimizeForBrowser/>
            </w:WordDocument>
          </xml>
          <![endif]-->
          <style>
            @page { 
              size: 21.0cm 29.7cm; 
              margin: 2.0cm 1.5cm 2.0cm 3.0cm; /* Lề trái 3cm chuẩn đóng quyển */
              mso-page-orientation: portrait;
              mso-header-margin: 35.4pt;
              mso-footer-margin: 35.4pt;
            }
            body { 
              font-family: 'Times New Roman', serif; 
              font-size: 11.5pt; 
              line-height: 1.3; 
              text-align: justify;
              mso-ascii-font-family: 'Times New Roman';
              mso-hansi-font-family: 'Times New Roman';
            }
            .center { text-align: center; }
            .bold { font-weight: bold; }
            .uppercase { text-transform: uppercase; }
            .section-title { font-weight: bold; text-transform: uppercase; margin-top: 15pt; margin-bottom: 5pt; border-bottom: 0.5pt solid black; }

            table { 
              width: 100%; 
              border-collapse: collapse; 
              table-layout: fixed; /* Ép buộc kích thước cố định để không tràn lề */
              mso-table-layout-alt: fixed;
              mso-table-lspace: 0pt; 
              mso-table-rspace: 0pt;
              border: 0.5pt solid black; 
              margin: 0;
            }
            th, td { 
              border: 0.5pt solid black; 
              padding: 6pt; 
              vertical-align: top; 
              word-break: break-all;
              word-wrap: break-word; /* Chống tràn lề do chuỗi kí tự dài */
              overflow-wrap: break-word;
              mso-border-alt: 0.5pt solid black;
            }
            .digital-box { 
              color: #991b1b; 
              font-size: 10pt; 
              font-weight: bold; 
              border: 0.5pt dashed #991b1b; 
              padding: 4pt; 
