export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedContent?: string,
  frameworkContent?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-flash-preview'; 

  const systemInstruction = `Bạn là chuyên gia giáo dục soạn giáo án 5512 môn Toán 6 Kết nối tri thức. 

  QUY TẮC CẤU TRÚC CHO MỖI HOẠT ĐỘNG (BẮT BUỘC):
  Với mỗi hoạt động, nội dung trả về phải đầy đủ các mục chi tiết sau:
  a) Mục tiêu: Chỉ rõ yêu cầu cần đạt.
  b) Nội dung: Mô tả các nhiệm vụ giáo viên giao.
  c) Sản phẩm: Gồm 2 phần rõ rệt:
     - Ghi bảng: Nội dung kiến thức cốt lõi học sinh ghi vào vở.
     - Bài tập làm thêm: Các bài tập củng cố mở rộng.
  d) Tổ chức thực hiện: Gồm 4 bước chuẩn 5512.

  QUY TẮC CHỮ ĐỎ:
  - Nếu ở chế độ NÂNG CẤP, giữ nguyên nội dung cũ của giáo viên.
  - Các phần tích hợp năng lực mới PHẢI bọc trong thẻ <span style="color: #ff0000;">...</span>.

  ĐỊNH DẠNG:
  - Sử dụng LaTeX $...$ cho công thức toán.
  - Mã SVG cho hình vẽ. Trình bày JSON chuẩn.`;

  let userPrompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    userPrompt = `Nâng cấp giáo án bài: ${input}. 
    Nội dung trích xuất: ${extractedContent}
    ${frameworkContent ? `Khung năng lực yêu cầu: ${frameworkContent}` : ""}
    Hãy giữ nguyên nội dung gốc và bổ sung thêm các tiêu chí năng lực bằng chữ màu đỏ.
    Mục Sản phẩm PHẢI ghi rõ phần 'Ghi bảng' và 'Bài tập làm thêm'.`;
  } else {
    userPrompt = `Soạn giáo án bài mới: ${input}. 
    Sách: Kết nối tri thức.
    Yêu cầu: Đầy đủ các hoạt động a, b, c, d. Mục c (Sản phẩm) phải có nội dung ghi bảng và bài tập làm thêm. Vẽ hình minh họa bằng SVG.`;
  }

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: [{ parts: [{ text: userPrompt }] }],
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: lessonPlanSchema,
        temperature: 0.7,
        thinkingConfig: { thinkingBudget: 16384 },
      },
    });

    const responseText = response.text;
    if (!responseText) throw new Error("AI không phản hồi.");
    return JSON.parse(responseText.trim()) as LessonPlan;
  } catch (err: any) {
    throw new Error(err.message || "Lỗi API");
  }
};

import React, { useEffect, useRef } from 'react';

interface MathRendererProps {
  content: string;
}

const MathRenderer: React.FC<MathRendererProps> = ({ content }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (containerRef.current && (window as any).MathJax) {
      // Chuẩn hóa nội dung
      let formatted = content;
      // Tránh việc MathJax render nhầm các thẻ span màu đỏ
      formatted = formatted.replace(/\n/g, '<br/>');

      containerRef.current.innerHTML = formatted;

      try {
        (window as any).MathJax.typesetPromise([containerRef.current]).catch((err: any) => {
          console.debug("MathJax pending:", err);
        });
      } catch (e) {
        console.error("MathJax error:", e);
      }
    }
  }, [content]);

  return (
    <div 
      ref={containerRef} 
      className="math-rendered text-slate-700 text-sm lesson-content-rich"
      style={{ 
        minHeight: '1.2em', 
        width: '100%', 
        overflowX: 'auto'
      }}
    />
  );
};

