export default function LessonPlanApp() {
  const [activeTab, setActiveTab] = useState('upload');
  const [selectedLessonId, setSelectedLessonId] = useState('');
  const [customTopic, setCustomTopic] = useState('');
  const [isCustomMode, setIsCustomMode] = useState(false);
  const [generatedPlan, setGeneratedPlan] = useState<LessonPlan | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadingMsgIdx, setLoadingMsgIdx] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [lessonFileContent, setLessonFileContent] = useState<string>('');
  const [lessonFileName, setLessonFileName] = useState<string>('');
  const [frameworkContent, setFrameworkContent] = useState<string>('');
  const [frameworkFileName, setFrameworkFileName] = useState<string>('');

  const lessonInputRef = useRef<HTMLInputElement>(null);
  const frameworkInputRef = useRef<HTMLInputElement>(null);
  const hiddenRenderRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    let interval: any;
    if (isProcessing) {
      interval = setInterval(() => {
        setLoadingMsgIdx(prev => (prev + 1) % LOADING_MESSAGES.length);
      }, 2000);
    }
    return () => clearInterval(interval);
  }, [isProcessing]);

  // Hàm quan trọng: Chuyển đổi nội dung chứa Latex thành HTML có nhúng PNG cho Word
  const processContentForWord = async (htmlStr: string): Promise<string> => {
    if (!hiddenRenderRef.current) return htmlStr;

    // Tạo container tạm để render math
    const temp = document.createElement('div');
    temp.innerHTML = htmlStr.replace(/\n/g, '<br/>');
    hiddenRenderRef.current.appendChild(temp);

    // Render MathJax
    await (window as any).MathJax.typesetPromise([temp]);

    // Tìm các SVG mà MathJax tạo ra
    const svgs = temp.querySelectorAll('mjx-container svg');
    for (const svg of Array.from(svgs)) {
      const container = (svg as any).closest('mjx-container');
      if (!container) continue;

      // Chuyển SVG sang PNG Base64
      const svgData = new XMLSerializer().serializeToString(svg);
      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);

      const pngBase64 = await new Promise<string>((resolve) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          // Scale to ensure high quality in Word
          const scale = 3; 
          canvas.width = img.width * scale;
          canvas.height = img.height * scale;
          const ctx = canvas.getContext('2d');
          if (ctx) {
            ctx.fillStyle = 'white';
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
            resolve(canvas.toDataURL('image/png'));
          } else resolve('');
        };
        img.src = url;
      });

      if (pngBase64) {
        // Thay thế math container bằng img tag
        const imgTag = document.createElement('img');
        imgTag.src = pngBase64;
        // Chiều cao math trong Word thường nhỏ, để auto width
        imgTag.style.height = `${(svg as any).getBBox().height * 1.5}pt`;
        imgTag.style.verticalAlign = 'middle';
        container.parentNode.replaceChild(imgTag, container);
      }
      URL.revokeObjectURL(url);
    }

    const result = temp.innerHTML;
    hiddenRenderRef.current.removeChild(temp);
    return result;
  };

  const svgToPngBase64 = async (svgStr: string): Promise<string> => {
    return new Promise((resolve) => {
      const svgMatch = svgStr.match(/<svg[\s\S]*?<\/svg>/);
      if (!svgMatch) return resolve('');
      const cleanSvg = svgMatch[0];
      const svgBlob = new Blob([cleanSvg], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 1600;
        canvas.height = 900;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.fillStyle = 'white';
          ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          const dataUrl = canvas.toDataURL('image/png');
          URL.revokeObjectURL(url);
          resolve(dataUrl);
        } else resolve('');
      };
      img.src = url;
    });
  };

  const handleDownloadWord = async () => {
    if (!generatedPlan) return;
    setIsProcessing(true);
