          }

          return {
            ...act,
            svgAsImg,
            objectivesHtml: await processContentForWord(act.objectives),
            teacherActivitiesHtml: await processContentForWord(act.teacherActivities),
            studentResultsHtml: await processContentForWord(act.studentResults),
            digitalCompetencyHtml: await processContentForWord(act.digitalCompetency),
            stepsHtml: {
              assign: await processContentForWord(act.executionSteps.assignTask),
              execute: await processContentForWord(act.executionSteps.executeTask),
              report: await processContentForWord(act.executionSteps.reportDiscuss),
              conclude: await processContentForWord(act.executionSteps.concludeAssess)
            }
          };
        })
      );

      const htmlContent = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
