                  <td>
                    <div style="font-size: 10.5pt; color: #1f2937;">${act.studentResultsHtml}</div>
                    <div class="digital-box">TÍCH HỢP SỐ: ${act.digitalCompetencyHtml}</div>
                  </td>
                </tr>
              </table>
            </div>
          `).join('')}
        </body>
        </html>
      `;

      const blob = new Blob(['\ufeff', htmlContent], { type: 'application/msword' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `GiaoAn_Toan6_${generatedPlan.topic.replace(/\s+/g, '_')}.doc`;
      link.click();
    } catch (e) {
      console.error(e);
      setError("Lỗi xử lý hình ảnh Word.");
    } finally {
      setIsProcessing(false);
    }
  };

