import { GoogleGenAI, Type } from "@google/genai";
import { LessonPlan, GenerationMode } from "../types";

const lessonPlanSchema = {
  type: Type.OBJECT,
  properties: {
    topic: { type: Type.STRING },
    grade: { type: Type.STRING },
    bookSeries: { type: Type.STRING },
    objectives: { type: Type.STRING },
    preparations: { type: Type.STRING },
    activities: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          title: { type: Type.STRING },
          objectives: { type: Type.STRING, description: 'Mục tiêu (a)' },
          teacherActivities: { type: Type.STRING, description: 'Nội dung dạy học (b)' },
          studentResults: { 
            type: Type.STRING, 
            description: 'Sản phẩm (c). BẮT BUỘC có 2 phần: [GHI BẢNG] và [BÀI TẬP LÀM THÊM].' 
          },
          executionSteps: {
            type: Type.OBJECT,
            properties: {
              assignTask: { type: Type.STRING },
              executeTask: { type: Type.STRING },
              reportDiscuss: { type: Type.STRING },
              concludeAssess: { type: Type.STRING }
            },
            required: ['assignTask', 'executeTask', 'reportDiscuss', 'concludeAssess']
          },
          digitalCompetency: { type: Type.STRING },
          svgDiagram: { type: Type.STRING }
        },
        required: ['id', 'title', 'objectives', 'teacherActivities', 'studentResults', 'executionSteps', 'digitalCompetency', 'svgDiagram']
      }
    }
  },
  required: ['topic', 'grade', 'bookSeries', 'objectives', 'preparations', 'activities']
};

export const generateLessonPlan = async (
  mode: GenerationMode, 
  input: string, 
  fileData?: { data: string, mimeType: string },
  extractedContent?: string,
  frameworkContent?: string
): Promise<LessonPlan> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = 'gemini-3-flash-preview'; 

  const systemInstruction = `Bạn là chuyên gia soạn giáo án 5512 môn Toán 6 Kết nối tri thức.

  YÊU CẦU CẤU TRÚC:
  - Mỗi hoạt động PHẢI có đầy đủ các mục: a) Mục tiêu; b) Nội dung; c) Sản phẩm; d) Tổ chức thực hiện.
  - Mục c) Sản phẩm PHẢI bao gồm phần 'Ghi bảng' (kiến thức cốt lõi) và 'Bài tập làm thêm'.
  - Nếu ở chế độ NÂNG CẤP (TRANSFORM), phải GIỮ NGUYÊN NỘI DUNG GỐC và chỉ bổ sung năng lực mới bằng chữ màu đỏ (<span style="color: #ff0000;">...</span>).
  - Sử dụng LaTeX $...$ cho công thức toán và mã SVG cho hình vẽ.`;

  let userPrompt = "";
  if (mode === GenerationMode.TRANSFORM) {
    userPrompt = `Nâng cấp giáo án: ${input}. 
    Dữ liệu giáo án cũ: ${extractedContent}
    Yêu cầu: Giữ nguyên toàn bộ nội dung cũ, tích hợp thêm năng lực số và năng lực toán học bằng chữ đỏ. Trình bày chuẩn 5512.`;
  } else {
    userPrompt = `Soạn giáo án mới: ${input}. 
    Yêu cầu: Trình bày chuẩn công văn 5512. Mục Sản phẩm có Ghi bảng và Bài tập làm thêm. Vẽ hình minh họa bằng SVG.`;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: [{ parts: [{ text: userPrompt }] }],
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: lessonPlanSchema,
      temperature: 0.7,
      thinkingConfig: { thinkingBudget: 16384 },
    },
  });

  return JSON.parse(response.text.trim()) as LessonPlan;
};

import React, { useEffect, useRef } from 'react';

interface MathRendererProps {
  content: string;
}

const MathRenderer: React.FC<MathRendererProps> = ({ content }) => {
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (containerRef.current && (window as any).MathJax) {
      containerRef.current.innerHTML = content.replace(/\n/g, '<br/>');
      try {
        (window as any).MathJax.typesetPromise([containerRef.current]).catch(() => {});
      } catch (e) {}
    }
  }, [content]);

  return (
    <div 
      ref={containerRef} 
      className="math-rendered text-slate-700 text-sm lesson-content-rich"
      style={{ minHeight: '1.2em', width: '100%', overflowX: 'auto' }}
    />
  );
};

