pdfjsLib.GlobalWorkerOptions.workerSrc = `https://esm.sh/pdfjs-dist@4.0.379/build/pdf.worker.mjs`;

export default function LessonPlanApp() {
  const [activeTab, setActiveTab] = useState('upload');
  const [selectedLessonId, setSelectedLessonId] = useState('');
  const [customTopic, setCustomTopic] = useState('');
  const [isCustomMode, setIsCustomMode] = useState(false);
  const [generatedPlan, setGeneratedPlan] = useState<LessonPlan | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadingMsg, setLoadingMsg] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [lessonFileContent, setLessonFileContent] = useState('');
  const [lessonFileName, setLessonFileName] = useState('');
  const [frameworkContent, setFrameworkContent] = useState('');
  const [frameworkFileName, setFrameworkFileName] = useState('');

  const lessonInputRef = useRef<HTMLInputElement>(null);
  const frameworkInputRef = useRef<HTMLInputElement>(null);
  const hiddenRenderRef = useRef<HTMLDivElement>(null);

  // Chuyển đổi Latex sang PNG để nhúng Word
  const mathToPng = async (html: string): Promise<string> => {
    if (!hiddenRenderRef.current) return html;
    const temp = document.createElement('div');
    temp.innerHTML = html.replace(/\n/g, '<br/>');
    hiddenRenderRef.current.appendChild(temp);
    await (window as any).MathJax.typesetPromise([temp]);

    const svgs = temp.querySelectorAll('mjx-container svg');
    for (const svg of Array.from(svgs)) {
      const container = (svg as any).closest('mjx-container');
      const svgData = new XMLSerializer().serializeToString(svg);
      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);

      const png = await new Promise<string>((resolve) => {
        const img = new Image();
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const scale = 2.5; 
          canvas.width = img.width * scale;
          canvas.height = img.height * scale;
          const ctx = canvas.getContext('2d');
          if (ctx) {
            ctx.fillStyle = 'white';
            ctx.fillRect(0, 0, canvas.width, canvas.height);
            ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
            resolve(canvas.toDataURL('image/png'));
          } else resolve('');
        };
        img.src = url;
      });

      if (png) {
        const imgTag = `<img src="${png}" style="height: ${(svg as any).getBBox().height * 1.3}pt; vertical-align: middle;" />`;
        container.outerHTML = imgTag;
      }
      URL.revokeObjectURL(url);
    }
    const result = temp.innerHTML;
    hiddenRenderRef.current.removeChild(temp);
    return result;
  };

  const svgToPng = async (svgStr: string): Promise<string> => {
    const match = svgStr.match(/<svg[\s\S]*?<\/svg>/);
    if (!match) return '';
    const blob = new Blob([match[0]], { type: 'image/svg+xml;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    return new Promise((resolve) => {
      const img = new Image();
      img.onload = () => {
        const canvas = document.createElement('canvas');
        canvas.width = 1200; canvas.height = 700;
        const ctx = canvas.getContext('2d');
        if (ctx) {
          ctx.fillStyle = 'white'; ctx.fillRect(0, 0, canvas.width, canvas.height);
          ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
          resolve(canvas.toDataURL('image/png'));
        } else resolve('');
      };
      img.src = url;
    });
  };

  const handleDownloadWord = async () => {
    if (!generatedPlan) return;
    setIsProcessing(true);
    setLoadingMsg("Đang tối ưu hình ảnh & công thức cho Word...");

    try {
      const objHtml = await mathToPng(generatedPlan.objectives);
      const prepHtml = await mathToPng(generatedPlan.preparations);

      const acts = await Promise.all(generatedPlan.activities.map(async (act) => {
        const png = act.svgDiagram ? await svgToPng(act.svgDiagram) : '';
        return {
          ...act,
          png: png ? `<div style="text-align:center;"><img src="${png}" style="width: 280pt;" /></div>` : '',
          a: await mathToPng(act.objectives),
          b: await mathToPng(act.teacherActivities),
          c: await mathToPng(act.studentResults),
          d_b1: await mathToPng(act.executionSteps.assignTask),
          d_b2: await mathToPng(act.executionSteps.executeTask),
          d_b3: await mathToPng(act.executionSteps.reportDiscuss),
          d_b4: await mathToPng(act.executionSteps.concludeAssess),
          dc: await mathToPng(act.digitalCompetency)
        };
      }));

      const html = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head><meta charset='utf-8'><style>
          @page { size: 21.0cm 29.7cm; margin: 2.0cm 1.5cm 2.0cm 3.0cm; }
          body { font-family: 'Times New Roman', serif; font-size: 12pt; line-height: 1.3; text-align: justify; }
          .bold { font-weight: bold; } .uppercase { text-transform: uppercase; }
          .section { font-weight: bold; text-transform: uppercase; margin-top: 15pt; border-bottom: 1pt solid black; }
          table { width: 100%; border-collapse: collapse; table-layout: fixed; margin-top: 10pt; }
          th, td { border: 0.5pt solid black; padding: 6pt; vertical-align: top; word-wrap: break-word; }
          .digital { color: #991b1b; font-size: 10pt; font-weight: bold; border: 0.5pt dashed #991b1b; padding: 4pt; background-color: #fef2f2; }
        </style></head>
        <body>
          <div style="text-align: center;">
            <p class="bold uppercase" style="font-size: 14pt;">KẾ HOẠCH BÀI DẠY (GIÁO ÁN)</p>
            <p class="bold uppercase" style="font-size: 16pt;">BÀI: ${generatedPlan.topic}</p>
          </div>
          <p class="section">I. MỤC TIÊU</p><div>${objHtml}</div>
          <p class="section">II. THIẾT BỊ DẠY HỌC VÀ HỌC LIỆU</p><div>${preHtml}</div>
          <p class="section">III. TIẾN TRÌNH DẠY HỌC</p>
          ${acts.map((act, i) => `
            <div style="margin-top: 15pt;">
              <p class="bold">Hoạt động ${i+1}: ${act.title}</p>
              <p><span class="bold">a) Mục tiêu:</span> ${act.a}</p>
              <p><span class="bold">b) Nội dung:</span> ${act.b}</p>
              <p><span class="bold">c) Sản phẩm:</span> ${act.c}</p>
              <p><span class="bold">d) Tổ chức thực hiện:</span></p>
              <table border="1">
                <tr style="background-color: #eee;">
                  <th style="width: 45%;">Hoạt động của GV</th>
                  <th style="width: 55%;">Sản phẩm của HS & Năng lực số</th>
                </tr>
                <tr>
                  <td>
                    <p class="bold">Các bước thực hiện:</p>
                    <div style="font-size: 10pt;">
                      <b>B1:</b> ${act.d_b1}<br/><b>B2:</b> ${act.d_b2}<br/>
                      <b>B3:</b> ${act.d_b3}<br/><b>B4:</b> ${act.d_b4}
                    </div>
                    ${act.png}
                  </td>
                  <td>
                    <div style="font-size: 10.5pt;">${act.c}</div>
                    <div class="digital">TÍCH HỢP SỐ: ${act.dc}</div>
                  </td>
                </tr>
              </table>
            </div>
          `).join('')}
        </body></html>`;

      const blob = new Blob(['\ufeff', html], { type: 'application/msword' });
      const link = document.createElement('a');
      link.href = URL.createObjectURL(blob);
      link.download = `GiaoAn_5512_${generatedPlan.topic.replace(/\s+/g, '_')}.doc`;
      link.click();
    } catch (e) { setError("Lỗi xuất Word."); } finally { setIsProcessing(false); }
  };

  const handleProcess = async () => {
    const topic = isCustomMode ? customTopic : selectedLessonId;
    if (!topic && activeTab === 'create') return;
    setIsProcessing(true); setError(null); setLoadingMsg("AI đang nâng cấp giáo án chuẩn 5512...");
    try {
      const mode = activeTab === 'upload' ? GenerationMode.TRANSFORM : GenerationMode.NEW;
      const plan = await generateLessonPlan(mode, topic || lessonFileName, undefined, lessonFileContent, frameworkContent);
      setGeneratedPlan(plan);
    } catch (e: any) { setError(e.message); } finally { setIsProcessing(false); }
  };

  const onFileChange = async (e: any, setContent: any, setName: any) => {
    const f = e.target.files?.[0];
    if (!f) return;
    setName(f.name);
    const buf = await f.arrayBuffer();
    if (f.name.endsWith('.docx')) {
      const res = await mammoth.extractRawText({ arrayBuffer: buf });
      setContent(res.value);
    } else if (f.name.endsWith('.pdf')) {
      const pdf = await pdfjsLib.getDocument({ data: buf }).promise;
      let txt = "";
      for (let i = 1; i <= pdf.numPages; i++) {
        const page = await pdf.getPage(i);
        const c = await page.getTextContent();
        txt += c.items.map((it: any) => it.str).join(" ") + "\n";
      }
      setContent(txt);
    }
  };

  return (
    <div className="flex h-screen bg-slate-100 font-['Be_Vietnam_Pro'] overflow-hidden">
      <aside className="w-80 bg-[#0f172a] text-slate-400 flex flex-col no-print p-6 space-y-6 shadow-2xl">
        <div className="text-center pb-6 border-b border-white/5">
          <Calculator size={40} className="text-indigo-500 mx-auto mb-2"/>
          <h1 className="text-white font-black uppercase italic tracking-tighter">Digital Math 6</h1>
        </div>
