        </div>
      </main>
      <div ref={hiddenRenderRef} className="fixed opacity-0 pointer-events-none" style={{ top: -9999 }}></div>
      {isProcessing && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-center justify-center">
          <div className="bg-white p-12 rounded-[3rem] shadow-2xl text-center border-t-8 border-indigo-600 max-w-sm">
            <RefreshCw className="animate-spin text-indigo-600 mx-auto mb-6" size={48}/>
            <p className="font-bold text-slate-800">{loadingMsg}</p>
          </div>
        </div>
      )}
    </div>
  );
}
